INSERT INTO `ai_saved_menus` (`id`, `user_id`, `menu_name`, `calories`, `description`, `created_at`) VALUES
(1, 5, 'สเต็กเนื้อริบอายเสิร์ฟคู่ไข่ดาวและมันฝรั่งอบ', 850, 'เนื้อริบอายย่างความสุกตามชอบ เสิร์ฟพร้อมไข่ดาว 2 ฟอง มันฝรั่งอบ และผักย่าง เป็นมื้อที่ให้พลังงานสูงและโปรตีนเน้นๆ', '2026-02-12 15:29:35'),
(2, 5, 'ข้าวหน้าเนื้อญี่ปุ่น (Gyudon) เพิ่มไข่ออนเซ็นคู่', 720, 'เนื้อสไลด์ผัดซอสญี่ปุ่นรสหวานเค็ม ราดบนข้าวสวยร้อนๆ พร้อมไข่ออนเซ็น 2 ฟอง ช่วยเพิ่มความละมุนและพลังงาน', '2026-02-12 15:29:36'),
(3, 5, 'กะเพราเนื้อสับราดข้าวไข่ดาวกรอบ (ไซส์พิเศษ)', 680, 'ผัดกะเพราเนื้อสับรสจัดจ้าน ใช้เนื้อวัวคุณภาพดี เสิร์ฟพร้อมข้าวสวยและไข่ดาวขอบกรอบๆ 2 ฟอง', '2026-02-12 15:29:37'),
(4, 5, 'อกไก่นึ่งสมุนไพรและไข่ต้ม ทานคู่กับข้าวกล้องและผักลวก', 650, 'เมนูโปรตีนสะอาด โซเดียมต่ำ ใช้สมุนไพรสดเพิ่มกลิ่นหอมแทนการใช้ซอสปรุงรสเยอะๆ เหมาะสำหรับผู้ควบคุมความดัน', '2026-02-12 17:22:14'),
(5, 5, 'ไก่ผัดขิงใส่ไข่ขาวและเห็ดหูหนู (สูตรลดโซเดียม)', 580, 'ขิงช่วยระบบไหลเวียนโลหิต ใช้ไข่ขาวเพื่อลดคอเลสเตอรอล ปรุงรสด้วยซีอิ๊วโซเดียมต่ำและไม่ใส่น้ำตาล', '2026-02-12 17:22:16'),
(6, 5, 'สลัดอกไก่ย่างและไข่ต้มซอสโยเกิร์ตมะนาว', 520, 'ใช้การย่างอกไก่แบบไม่ติดมัน ทานกับผักใบเขียวหลากหลายสี ช่วยเรื่องใยอาหารเพื่อชะลอการดูดซึมน้ำตาล', '2026-02-12 17:22:17'),
(7, 6, 'กะเพราสันในหมูน้ำมันรำข้าว', 320, 'ใช้เนื้อส่วนสันในที่นุ่มและไขมันน้อย ผัดกับใบกะเพราสดช่วยขับลม และใช้น้ำมันรำข้าวเพียงเล็กน้อย', '2026-02-17 15:18:53'),
(8, 6, 'หมูมะนาวรสเด็ดพร้อมผักเคียง', 250, 'หมูเนื้อแดงลวกสุกกำลังดี ราดน้ำยำรสเปรี้ยวแซ่บ เสิร์ฟคู่กับก้านคะน้ากรอบและกระเทียมฝาน ช่วยเสริมภูมิคุ้มกัน', '2026-02-17 15:18:54'),
(9, 6, 'หมูผัดขิงและเห็ดหูหนู', 280, 'เมนูช่วยระบบย่อยอาหารและลดคอเลสเตอรอล ใช้เนื้อหมูไม่ติดมันผัดกับขิงอ่อนที่มีสรรพคุณอุ่นร่างกาย', '2026-02-17 15:18:54'),
(10, 6, 'สเต็กปลาแซลมอนซอสเลมอนบัตเตอร์', 450, 'โอเมก้า 3 ในแซลมอนช่วยลดความเครียดและบำรุงสมอง ทำให้จิตใจเบิกบานครับ', '2026-02-17 16:34:45'),
(11, 6, 'พาสต้ากุ้งกระเทียมและน้ำมันมะกอก', 380, 'เมนูย่อยง่าย รสชาติกลมกล่อม ช่วยให้มื้อค่ำไม่หนักเกินไปและรู้สึกผ่อนคลาย', '2026-02-17 16:34:46'),
(12, 6, 'ดาร์กช็อกโกแลตฟองดูว์กับผลไม้ตระกูลเบอร์รี', 250, 'ช็อกโกแลตมีสารที่ช่วยกระตุ้นความรู้สึกดีและลดความกังวล เป็นของหวานที่สร้างความโรแมนติกได้ดีเยี่ยมครับ', '2026-02-17 16:34:47'),
(13, 6, 'เต้าหู้ขาวผัดอกไก่สับและไข่ขาว', 380, 'เมนูเพิ่มโปรตีนแบบคูณสองจากทั้งอกไก่และเต้าหู้ขาว ปรุงรสด้วยซอสโซเดียมต่ำ เหมาะสำหรับมื้อกลางวันที่ต้องการพลังงาน', '2026-02-18 16:39:41'),
(14, 6, 'อกไก่ย่างสมุนไพรและข้าวไรซ์เบอร์รี่', 420, 'อกไก่หมักรากผักชีพริกไทยดำย่างจนสุกพอดี เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่และบล็อกโคลี่นึ่ง', '2026-02-21 02:24:36'),
(15, 6, 'ลาบไก่สับสูตรคลีน', 320, 'ใช้เนื้ออกไก่สับล้วน ปรุงรสด้วยมะนาวและพริกป่น เน้นผักสดเคียงจำนวนมากเพื่อเพิ่มใยอาหาร', '2026-02-21 02:24:43'),
(16, 6, 'ต้มจืดฟักเขียวอกไก่ใส่เห็ดหอม', 250, 'ซุปร้อนๆ ที่ให้พลังงานต่ำแต่สารอาหารสูง ช่วยให้อิ่มท้องและสบายตัว', '2026-02-21 02:24:43'),
(20, 7, 'อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)', 600, 'อกไก่หมักสมุนไพรไทยย่างจนนุ่ม ทานคู่กับควิโนอาที่มีใยอาหารสูงและดัชนีน้ำตาลต่ำ ช่วยให้อิ่มท้องและรักษาระดับน้ำตาลได้ดี', '2026-02-24 02:49:56'),
(21, 7, 'ปลานึ่งมะนาวสูตรโซเดียมต่ำ ทานคู่ข้าวกล้อง (มื้อกลางวัน)', 800, 'ปลากะพงสดนึ่งกับน้ำมะนาวพริกกระเทียมโดยลดการใช้เครื่องปรุงโซเดียมสูง เสิร์ฟพร้อมข้าวกล้องเพื่อเพิ่มกากใยและความชะลอการย่อยคาร์โบไฮเดรต', '2026-02-24 02:49:56'),
(22, 7, 'สลัดทูน่าอะโวคาโด (มื้อว่าง)', 431, 'ทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดที่ให้ไขมันดี (HDL) มีประโยชน์ต่อหัวใจและหลอดเลือด พร้อมผักสลัดสดหลากสี', '2026-02-24 02:49:56'),
(23, 7, 'แกงเลียงกุ้งสดผักรวม (มื้อเย็น)', 600, 'แกงไทยสมุนไพรเข้มข้นที่เน้นผักพื้นบ้านและกุ้งสด สูตรลดเกลือแต่ใช้ความหอมจากพริกไทยและรากผักชี ช่วยขับลมและให้สารต้านอนุมูลอิสระสูง', '2026-02-24 02:49:56'),
(24, 7, 'ข้าวผัดธัญพืชอกไก่ (มื้อเช้า)', 600, 'ข้าวกล้องผัดกับอกไก่ไม่ติดมัน ใส่ถั่วลันเตา แครอท และข้าวโพด ปรุงรสอ่อนๆ เพื่อพลังงานที่ยั่งยืนในตอนเช้า', '2026-02-24 03:01:24'),
(25, 7, 'ปลากะพงนึ่งซีอิ๊วขิงแก่และข้าวกล้อง (มื้อกลางวัน)', 700, 'ปลากะพงขาวสดนึ่งกับขิงซอยและซีอิ๊วโซเดียมต่ำ รองจานด้วยกะหล่ำปลีนึ่ง ทานคู่กับข้าวกล้อง 1 ถ้วย', '2026-02-24 03:01:24'),
(27, 7, 'แกงส้มผักรวมกุ้งสดและข้าวไรซ์เบอร์รี่ (มื้อเย็น)', 700, 'ใช้ผักกาดขาวและน้ำมะขามเปียกปรุงเป็นแกงส้มรสกลมกล่อม (ลดเค็ม) ใส่กุ้งสด ทานคู่กับข้าวไรซ์เบอร์รี่', '2026-02-24 03:01:24'),
(28, 7, 'อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)', 620, 'อกไก่หมักสมุนไพรไทยย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่ให้โปรตีนและไฟเบอร์สูง ช่วยให้อิ่มนานและดีต่อระดับน้ำตาล', '2026-02-24 03:03:20'),
(29, 7, 'ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)', 780, 'ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ชิ้นโต ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ ให้พลังงานและโปรตีนที่เหมาะสมกับช่วงกลางวัน', '2026-02-24 03:03:20'),
(30, 7, 'ไข่ตุ๋นทรงเครื่อง (มื้อว่าง)', 350, 'ไข่ตุ๋นเนื้อนุ่มใส่ไก่สับและเห็ดหอม เป็นอาหารว่างที่ให้โปรตีนสูงและย่อยง่าย', '2026-02-24 03:03:20'),
(31, 7, 'สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)', 681, 'ปลาแซลมอนย่างให้โปรตีนและไขมันดี (Omega-3) ซึ่งดีต่อหัวใจและความดัน เสิร์ฟพร้อมหน่อไม้ฝรั่งสดกรอบ', '2026-02-24 03:03:20'),
(33, 7, 'ข้าวผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)', 750, 'ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ ให้พลังงานสูงจากคาร์โบไฮเดรตเชิงซ้อนและใยอาหาร', '2026-02-24 03:40:42'),
(34, 7, 'Quinoa Power Salad (มื้อว่าง)', 400, 'สลัดควิโนอาที่อัดแน่นไปด้วยผักใบเขียวและถั่ว ช่วยเพิ่มพลังงานระหว่างวันและให้แมกนีเซียมสูงซึ่งดีต่อความดันโลหิต', '2026-02-24 03:40:42'),
(35, 7, 'สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)', 681, 'แซลมอนย่างเกลือพริกไทยเพียงเล็กน้อยเพื่อให้ได้ไขมันดีโอเมก้า-3 เสิร์ฟพร้อมหน่อไม้ฝรั่งย่าง ช่วยเสริมสร้างระบบหัวใจและหลอดเลือด', '2026-02-24 03:40:42'),
(36, 7, 'อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)', 600, 'อกไก่ส่วนไม่ติดหนังหมักสมุนไพรไทยย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่มีโปรตีนและใยอาหารสูง', '2026-02-25 03:53:55'),
(37, 7, 'ผัดกะเพราเนื้อสับไข่ดาวน้ำ (มื้อกลางวัน)', 750, 'เนื้อวัวส่วนไม่ติดมันผัดกับใบกะเพราหอมๆ ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ เสิร์ฟพร้อมข้าวกล้องและไข่ดาวที่ใช้น้ำแทนน้ำมัน', '2026-02-25 03:53:55'),
(38, 7, 'สลัดทูน่าอะโวคาโด (มื้อว่าง)', 431, 'เนื้อทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดสุก ให้ไขมันดีที่ช่วยบำรุงหัวใจและอิ่มท้องนาน', '2026-02-25 03:53:55'),
(39, 7, 'ปลากะพงนึ่งซีอิ๊วขิงแก่ (มื้อเย็น)', 650, 'ปลากะพงขาวสดนึ่งกับขิงแก่และขึ้นฉ่าย ช่วยลดความดันโลหิต ปรุงด้วยซีอิ๊วสูตรลดโซเดียม รับประทานคู่กับข้าวกล้อง', '2026-02-25 03:53:55'),
(41, 7, 'ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)', 750, 'ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ ให้พลังงานที่ยาวนานและโปรตีนที่ครบถ้วน', '2026-02-25 03:55:27'),
(42, 7, 'สลัดทูน่าอะโวคาโด (มื้อว่าง)', 431, 'เนื้อทูน่าคุณภาพดีผสมกับอะโวคาโด ให้โปรตีนและไขมันดี (HDL) ช่วยบำรุงหัวใจและหลอดเลือด', '2026-02-25 03:55:27'),
(45, 7, 'กุ้งสดผัดบล็อกโคลี่และเห็ดแชมปิญองข้าวไรซ์เบอร์รี่ (มื้อกลางวัน)', 650, 'กุ้งแชบ๊วยตัวโตผัดกับบล็อกโคลี่และเห็ดโดยใช้น้ำมันรำข้าวเล็กน้อย ปรุงรสด้วยซีอิ๊วขาวลดโซเดียม เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่', '2026-02-25 04:07:18'),
(46, 7, 'เต้าหู้ขาวนึ่งจิ้มซีอิ๊วและถั่วแระญี่ปุ่น (มื้อว่าง)', 550, 'เต้าหู้ขาวถั่วเหลืองแท้นึ่งอุ่นๆ ทานคู่กับถั่วแระญี่ปุ่นต้ม เป็นของว่างโปรตีนสูงจากพืชและมีกากใยช่วยชะลอการดูดซึมน้ำตาล', '2026-02-25 04:07:18'),
(47, 7, 'เมี่ยงปลาทูย่างและขนมจีนข้าวกล้อง (มื้อเย็น)', 651, 'ปลาทูย่าง (ไม่ทอด) ทานคู่กับขนมจีนข้าวกล้องและผักสดหลากหลายชนิด ราดน้ำจิ้มถั่วตัดสูตรหวานน้อยและลดเกลือ ให้โปรตีนและโอเมก้า 3 สูง', '2026-02-25 04:07:18'),
(48, 7, 'ข้าวต้มข้าวกล้องอกไก่สับและไข่ลวก (มื้อเช้า)', 500, 'ข้าวกล้องต้มจนนุ่ม อกไก่สับปรุงรสด้วยพริกไทย ใส่ขิงซอยและต้นหอมเพื่อช่วยระบบไหลเวียนโลหิต พร้อมไข่ลวก 1 ฟอง', '2026-02-25 05:33:37'),
(51, 7, 'ต้มจืดมะระยัดไส้ไก่สับและข้าวไรซ์เบอร์รี่ (มื้อเย็น)', 681, 'มะระที่มีสรรพคุณช่วยลดระดับน้ำตาลในเลือด ยัดไส้ด้วยอกไก่สับในน้ำซุปสมุนไพร เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่ที่มีไฟเบอร์สูง', '2026-02-25 05:33:37'),
(55, 7, 'แกงป่าอกไก่ใส่ผักรวมและข้าวกล้อง', 700, 'แกงป่ารสจัดจ้านจากสมุนไพร ไม่ใส่กะทิ (ลดไขมันอิ่มตัว) ใส่ผักเปาะ ถั่วฝักยาว และกระชาย เสิร์ฟคู่กับข้าวกล้องร้อนๆ', '2026-03-03 08:31:46'),
(65, 9, 'ลาบอกไก่ไขมันต่ำ', 650, 'ลาบอกไก่สับคลุกเคล้าสมุนไพรไทยหอมๆ รสชาติจัดจ้านแต่ปรุงแบบลดโซเดียมและไขมัน เสิร์ฟพร้อมผักสดนานาชนิด', '2026-03-04 15:59:06'),
(66, 9, 'ก๋วยเตี๋ยวลุยสวนอกไก่', 250, 'เมนูเพื่อสุขภาพที่อุดมด้วยผักสดนานาชนิดและอกไก่หั่นชิ้น ห่อด้วยแผ่นแป้งนุ่มๆ พร้อมน้ำจิ้มสูตรลดน้ำตาลและโซเดียม', '2026-03-04 15:59:06'),
(67, 9, 'แกงส้มผักรวมกุ้งสด', 650, 'แกงส้มรสชาติจัดจ้าน เปรี้ยว เผ็ด หอมเครื่องแกง เน้นผักหลากหลายชนิดและกุ้งสด โปรตีนสูง ไขมันต่ำ ไม่ใส่กะทิ เหมาะสำหรับผู้ป่วยเบาหวานและความดัน', '2026-03-04 15:59:06'),
(68, 9, 'แกงเลียงกุ้งสดผักรวม', 450, 'แกงไทยน้ำใสไม่กะทิ อุดมด้วยผักหลากหลายชนิด เช่น ฟักทอง บวบ และตำลึง ให้ใยอาหารสูงและโซเดียมต่ำจากเครื่องแกงสมุนไพร', '2026-03-04 16:03:52'),
(69, 9, 'อกไก่ผัดขิงและเห็ดหูหนู', 650, 'ใช้เนื้ออกไก่ไม่ติดหนังผัดกับขิงสดช่วยขับลมและกระตุ้นระบบเผาผลาญ พร้อมเห็ดหูหนูซึ่งมีส่วนช่วยลดระดับไขมันในเลือด', '2026-03-04 16:03:52'),
(70, 9, 'สลัดเส้นโซบะเย็นซอสงาญี่ปุ่น', 300, 'ใช้เส้นโซบะซึ่งมีดัชนีน้ำตาลต่ำกว่าแป้งขัดขาว เสิร์ฟพร้อมผักสดและโปรตีนจากเต้าหู้ย่าง เป็นมื้อว่างที่ดีต่อสุขภาพหัวใจ', '2026-03-04 16:03:52'),
(71, 9, 'สเต็กปลากะพงย่างซอสเลมอน', 815, 'ปลากะพงย่างเน้นโปรตีนคุณภาพสูงและกรดไขมันโอเมก้า 3 ทานคู่กับผักย่าง ช่วยควบคุมความดันโลหิตและดีต่อสุขภาพโดยรวม', '2026-03-04 16:03:52'),
(72, 9, 'มื้อเช้า: แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม', 450, 'ขนมปังโฮลวีตสองแผ่นประกบอกไก่ย่างปรุงรสอ่อน ไข่ต้มสไลด์ ผักกาดแก้ว และมะเขือเทศสด เสิร์ฟพร้อมมายองเนสไขมันต่ำ ให้พลังงานและใยอาหารที่ดีสำหรับการเริ่มต้นวันใหม่', '2026-03-05 18:20:15'),
(73, 9, 'มื้อกลางวัน: อกไก่นุ่มย่างสมุนไพรและควิโนอา', 650, 'อกไก่นุ่มย่างหอมกรุ่นด้วยสมุนไพรไทยนานาชนิด เสิร์ฟพร้อมควิโนอาหุงสุก ซึ่งเป็นธัญพืชที่ให้โปรตีนและใยอาหารสูง รวมถึงผักนึ่งหลากหลายชนิด เช่น บรอกโคลี แครอท และถั่วฝักยาว', '2026-03-05 18:20:15'),
(74, 9, 'มื้อว่าง: ต้มยำอกไก่น้ำใส', 200, 'ซุปต้มยำรสชาติจัดจ้านแบบน้ำใส เน้นสมุนไพรไทยสดใหม่และอกไก่ฉีก ปรุงรสแบบลดโซเดียมและงดน้ำตาล เพื่อให้ได้รสชาติกลมกล่อมแต่ดีต่อสุขภาพ', '2026-03-05 18:20:15'),
(75, 9, 'มื้อเย็น: ผัดกะเพราอกไก่สับไข่ดาวน้ำ', 650, 'อกไก่สับผัดกะเพราสูตรลดโซเดียมและใช้น้ำมันน้อย ผัดคลุกเคล้ากับพริก กระเทียม และใบกะเพราหอมๆ เสิร์ฟพร้อมข้าวกล้องหุงสุก และไข่ดาวน้ำที่เป็นโปรตีนดีเพิ่มขึ้น', '2026-03-05 18:20:15'),
(77, 9, 'มื้อกลางวัน: แซลมอนย่างซีอิ๊วและบล็อกโคลี่นึ่ง', 620, 'เนื้อปลาแซลมอนย่างสุกพอดี ราดด้วยซอสซีอิ๊วสูตรลดโซเดียม ทานคู่กับบล็อกโคลี่นึ่งที่คงคุณค่าสารอาหาร พร้อมข้าวกล้องหรือข้าวไรซ์เบอร์รี่ (หากต้องการ)', '2026-03-05 18:22:33'),
(78, 9, 'มื้อว่าง: ผัดฟักทองใส่ไข่', 280, 'ฟักทองหั่นเต๋าผัดกับไข่ไก่ ปรุงรสด้วยน้ำปลาและซีอิ๊วลดโซเดียม เน้นหวานธรรมชาติจากฟักทอง ใช้น้ำมันรำข้าวในปริมาณน้อย', '2026-03-05 18:22:33'),
(79, 9, 'มื้อเย็น: แกงส้มชะอมกุ้ง (สูตรลดโซเดียม)', 520, 'แกงส้มรสจัดจ้าน เปรี้ยว เผ็ด หวานน้อย เน้นผักรวมและชะอมไข่ที่อุดมด้วยใยอาหาร พร้อมกุ้งสดเนื้อแน่น ปรุงรสด้วยเครื่องแกงสดและลดปริมาณโซเดียม เสิร์ฟคู่กับข้าวกล้อง (หากต้องการ)', '2026-03-05 18:22:33'),
(81, 11, 'มื้อกลางวัน: ผัดเคลกุ้งสด', 0, 'เคลสดใหม่ผัดกับกุ้งสดตัวโต ใช้น้ำมันน้อย ปรุงรสด้วยซอสโซเดียมต่ำ ให้คุณค่าทางโภชนาการสูง ทั้งใยอาหาร วิตามิน และโปรตีนจากกุ้ง พร้อมข้าวกล้องหนึ่งถ้วย', '2026-03-06 04:12:01'),
(82, 11, 'มื้อว่าง: สลัดเคลกุ้งต้มซอสโยเกิร์ตมะนาว', 150, 'เคลลวกกับกุ้งต้ม ราดด้วยซอสโยเกิร์ตผสมน้ำมะนาว รสชาติเปรี้ยวอมหวานสดชื่น เป็นของว่างเบาๆ ที่อุดมด้วยโปรตีนและใยอาหาร ไขมันต่ำ และโซเดียมต่ำ', '2026-03-06 04:12:01'),
(83, 11, 'มื้อเย็น: ปลานึ่งมะนาวสูตรโซเดียมต่ำ', 450, 'ปลากะพงหรือปลานิลเนื้อนุ่มนึ่งกับน้ำซุปมะนาวรสจัดจ้าน แต่ปรับลดโซเดียมลง ให้รสชาติกลมกล่อม หอมกลิ่นมะนาวและสมุนไพร เป็นเมนูโปรตีนสูง ไขมันต่ำ เหมาะสำหรับมื้อเย็นของคุณ', '2026-03-06 04:12:01'),
(84, 9, 'มื้อเช้า: ข้าวต้มอกไก่ฉีกกับฟักทองและเห็ด', 420, 'ข้าวต้มข้าวกล้องหอมกรุ่น เนื้ออกไก่ฉีกนุ่มๆ ฟักทองหั่นเต๋า และเห็ดรวมหลากหลายชนิด ปรุงรสอ่อนๆ เพื่อสุขภาพ ช่วยให้อิ่มสบายท้องและได้รับใยอาหารสูง', '2026-03-06 07:16:48'),
(85, 9, 'มื้อกลางวัน: ไก่ผัดเม็ดมะม่วงหิมพานต์สูตรคลีน', 650, 'อกไก่หั่นชิ้นพอดีคำ ผัดกับเม็ดมะม่วงหิมพานต์ พริกหวานสามสี และหอมใหญ่ ปรุงรสแบบคลีนโดยลดโซเดียมและใช้น้ำมันมะกอกน้อย เสิร์ฟพร้อมข้าวกล้องเพื่อเพิ่มใยอาหาร', '2026-03-06 07:16:48'),
(86, 9, 'มื้อว่าง: สลัดเส้นโซบะเย็นและอกไก่ฉีก', 350, 'เส้นโซบะเหนียวนุ่มคลุกเคล้าน้ำสลัดงาญี่ปุ่นสูตรไขมันต่ำ พร้อมอกไก่ฉีก ผักกาดแก้ว และแตงกวาญี่ปุ่น หอมสดชื่น เหมาะสำหรับเป็นมื้อว่างที่เบาแต่ได้ประโยชน์', '2026-03-06 07:16:48'),
(87, 9, 'มื้อเย็น: สปาเกตตีโฮลวีตผัดพริกแห้งและอกไก่', 780, 'สปาเกตตีเส้นโฮลวีทเหนียวนุ่ม ผัดกับอกไก่หั่นชิ้น พริกแห้ง กระเทียม และใบโหระพา ปรุงรสชาติจัดจ้านแบบไทยๆ แต่ลดโซเดียมและน้ำมันลง เพื่อสุขภาพที่ดี', '2026-03-06 07:16:48'),
(88, 9, 'มื้อเช้า: ไข่ตุ๋นทรงเครื่อง', 250, 'ไข่ตุ๋นนุ่มๆ ปรุงรสอ่อนๆ ใส่หมูสับหรืออกไก่สับเล็กน้อยและผักต่างๆ เช่น แครอท เห็ดหอม (ใช้ซีอิ๊วขาวกลูเตนฟรีสำหรับปรุงรส)', '2026-03-07 08:20:55'),
(90, 9, 'มื้อว่าง: สลัดทูน่าอะโวคาโด', 300, 'ทูน่าในน้ำแร่ผสมอะโวคาโดหั่นเต๋า มะเขือเทศเชอร์รี่ แตงกวา และผักสลัดสด ราดด้วยน้ำสลัดบัลซามิก หรือน้ำสลัดโยเกิร์ตไขมันต่ำ', '2026-03-07 08:20:55'),
(91, 9, 'มื้อเย็น: ปลากะพงนึ่งซีอิ๊วขิงแก่', 550, 'ปลากะพงสดนึ่งกับขิงซอย ต้นหอม และเห็ดหอม ราดด้วยซอสซีอิ๊วกลูเตนฟรีสูตรลดโซเดียม เสิร์ฟพร้อมข้าวกล้อง (ประมาณ 1-1.5 ทัพพี) ทำให้ได้รสชาติหอมหวานและดีต่อสุขภาพ', '2026-03-07 08:20:55'),
(92, 9, 'มื้อเช้า: อกไก่นุ่มย่างสมุนไพรและควิโนอา (เพิ่มปริมาณควิโนอาและอะโวคาโด)', 980, 'อกไก่นุ่มย่างคลุกเคล้าสมุนไพรหอมกรุ่น (ปราศจากกลูเตน/โซเดียมต่ำ) เสิร์ฟพร้อมควิโนอาและอะโวคาโดหั่นเต๋า เพิ่มพลังงานและไขมันดีจากพืช', '2026-03-07 10:09:45'),
(93, 9, 'มื้อกลางวัน: แกงส้มผักรวมกุ้งสดกับข้าวกล้อง (สูตรลดโซเดียมและไม่เติมน้ำตาล)', 890, 'แกงส้มรสจัดจ้านที่อุดมด้วยผักนานาชนิดและกุ้งสด ปรุงรสแบบลดโซเดียมและไม่เติมน้ำตาล เสิร์ฟพร้อมข้าวกล้อง เพิ่มกุ้งและข้าวเพื่อให้ได้รับพลังงานที่เพียงพอ (สามารถเพิ่มปริมาณกุ้งเพื่อโปรตีนและแคลอรี่)', '2026-03-07 10:09:45'),
(96, 9, 'ก๋วยเตี๋ยวลุยสวนอกไก่', 750, 'ก๋วยเตี๋ยวลุยสวนแป้งโฮลวีท สอดไส้อกไก่ฉีก ผักสด และเห็ดต่างๆ เน้นโปรตีนและใยอาหารสูง ราดด้วยน้ำจิ้มซีฟู้ดสูตรลดโซเดียมและใช้น้ำตาลหญ้าหวาน เพื่อให้พลังงานและสารอาหารที่ครบถ้วนสำหรับมื้อเช้า', '2026-03-07 16:58:38'),
(97, 9, 'สปาเกตตีโฮลวีตผัดพริกแห้งและอกไก่', 0, 'สปาเกตตีเส้นโฮลวีตผัดกับอกไก่หั่นเต๋า พริกแห้ง กระเทียม และสมุนไพร ปรุงรสด้วยซอสสูตรลดโซเดียม ใช้น้ำมันมะกอกอย่างดี พร้อมเพิ่มผักหลากสี เพื่อให้ได้คาร์โบไฮเดรตเชิงซ้อน โปรตีนสูง และไขมันดีในปริมาณมาก เหมาะกับการเพิ่มน้ำหนัก', '2026-03-07 16:58:38'),
(98, 9, 'กรีกโยเกิร์ตผสมข้าวโอ๊ต อกไก่ฉีก และเมล็ดเจีย', 400, 'กรีกโยเกิร์ตรสธรรมชาติไขมันเต็ม ผสมข้าวโอ๊ตดิบ อกไก่ฉีกละเอียด และเมล็ดเจีย ให้โปรตีนสูง คาร์โบไฮเดรตเชิงซ้อน และไขมันดี ช่วยเพิ่มพลังงานระหว่างวันได้อย่างรวดเร็วและดีต่อสุขภาพ', '2026-03-07 16:58:38'),
(99, 9, 'ลาบไก่สับสมุนไพร', 750, 'ลาบไก่สับจากอกไก่ล้วน ปรุงรสด้วยสมุนไพรไทย ข้าวคั่ว พริกป่น และมะนาวสด สูตรลดโซเดียม ไม่ใส่น้ำตาล เสิร์ฟพร้อมข้าวกล้องหอมมะลิในปริมาณที่มาก และผักสดนานาชนิด เพื่อให้โปรตีนสูงและใยอาหารครบถ้วน', '2026-03-07 16:58:38'),
(100, 9, 'ข้าวกล้องหน้าอกไก่ฉีกผัดขิง', 650, 'ข้าวกล้องหอมนุ่มทานคู่กับอกไก่ฉีกผัดขิงหอมๆ ปรุงรสอ่อนๆ ด้วยซีอิ๊วโซเดียมต่ำและน้ำมันรำข้าว อุดมด้วยคาร์โบไฮเดรตเชิงซ้อนและโปรตีนดี ช่วยให้อิ่มนานและได้รับพลังงานอย่างเพียงพอ', '2026-03-07 17:39:20'),
(101, 9, 'ไก่ผัดเม็ดมะม่วงหิมพานต์สูตรสุขภาพ', 850, 'อกไก่หั่นเต๋าผัดกับเม็ดมะม่วงหิมพานต์ พริกหวาน และหอมใหญ่ ปรุงรสด้วยซอสโซเดียมต่ำและน้ำตาลมะพร้าวเล็กน้อย (หากจำเป็น) เม็ดมะม่วงหิมพานต์ช่วยเพิ่มไขมันดีและแคลอรี่สูง เหมาะสำหรับเป้าหมายเพิ่มน้ำหนัก ทานคู่กับข้าวกล้อง', '2026-03-07 17:39:20'),
(102, 9, 'สมูทตี้โปรตีนกล้วยหอมและเนยถั่ว', 600, 'สมูทตี้ปั่นจากกล้วยหอมสุก เนยถั่วธรรมชาติไม่เติมน้ำตาลและเกลือ ผงโปรตีน (เลือกแบบที่ไม่มีน้ำตาล) และนมอัลมอนด์ไม่หวาน เป็นแหล่งพลังงาน โปรตีน และไขมันดีชั้นเยี่ยมสำหรับมื้อว่าง ช่วยเพิ่มแคลอรี่และเสริมสร้างกล้ามเนื้อ', '2026-03-07 17:39:20'),
(103, 9, 'ปลานิลนึ่งมะนาว ทานคู่กับผัดผักรวมมิตรกุ้งสดและข้าวกล้อง', 750, 'ปลานิลนึ่งสดใหม่ราดด้วยน้ำจิ้มมะนาวรสชาติกลมกล่อมสูตรโซเดียมต่ำ เสิร์ฟพร้อมผัดผักรวมมิตรกุ้งสดที่ใช้น้ำมันมะกอกในการผัด เพื่อให้ได้รับโปรตีนจากปลาและกุ้ง วิตามินจากผัก และคาร์โบไฮเดรตจากข้าวกล้องอย่างสมดุล เป็นมื้อเย็นที่เบาแต่ได้สารอาหารครบถ้วน', '2026-03-07 17:39:20'),
(104, 9, 'แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม', 800, 'ขนมปังโฮลวีต 4 แผ่น ทาด้วยเนยถั่วธรรมชาติ (ไม่เติมน้ำตาลและเกลือ) สอดไส้อกไก่ย่างชิ้นใหญ่ ไข่ต้ม 2 ฟอง ผักกาด มะเขือเทศ และอะโวคาโดครึ่งลูก เพื่อเพิ่มพลังงานและไขมันดี', '2026-03-08 03:07:44'),
(105, 9, 'ผัดกะเพราอกไก่สับไข่ดาวน้ำกับข้าวกล้อง', 850, 'อกไก่สับ 200 กรัม ผัดกับใบกะเพรา พริก และกระเทียม ปรุงรสด้วยซีอิ๊วลดโซเดียมและพริกไทย งดการเติมน้ำตาล เสิร์ฟพร้อมข้าวกล้อง 250-300 กรัม และไข่ดาวน้ำ 1 ฟอง', '2026-03-08 03:07:44'),
(106, 9, 'ต้มยำอกไก่น้ำใสกับข้าวกล้อง', 700, 'ต้มยำอกไก่เนื้อแน่น 200 กรัม และเห็ดนานาชนิด ปรุงรสจัดจ้านด้วยสมุนไพรไทย เช่น ตะไคร้ ข่า ใบมะกรูด น้ำปลาลดโซเดียม และน้ำมะนาวสด งดการเติมน้ำตาล เสิร์ฟพร้อมข้าวกล้อง 250-300 กรัม', '2026-03-08 03:07:44'),
(107, 9, 'อกไก่ฉีกย่างคลุกเคล้ากับอะโวคาโดและถั่วแอลมอนด์', 650, 'อกไก่ย่างฉีก 150 กรัม คลุกเคล้ากับอะโวคาโด 1 ลูก และถั่วแอลมอนด์ไม่ใส่เกลือ 30 กรัม เป็นมื้อว่างที่อุดมด้วยโปรตีนและไขมันดี เพื่อพลังงานเสริม', '2026-03-08 03:07:44'),
(108, 6, 'อกไก่นึ่งเห็ดหอมและขิง', 600, 'อกไก่นุ่มนึ่งพร้อมเห็ดหอมและขิงหอมๆ ปรุงรสอ่อนๆ เพื่อสุขภาพดี เสิร์ฟพร้อมข้าวกล้อง (200 กรัม) เพื่อพลังงานและใยอาหาร', '2026-03-08 03:56:08'),
(109, 6, 'ไก่ผัดเม็ดมะม่วงหิมพานต์สูตรสุขภาพ', 800, 'ไก่ผัดเม็ดมะม่วงหิมพานต์ที่ปรุงอย่างพิถีพิถัน ลดน้ำมันและโซเดียม เน้นโปรตีนจากอกไก่ ไขมันดีจากเม็ดมะม่วง และใยอาหารจากผักหลากสี เสิร์ฟพร้อมข้าวกล้อง', '2026-03-08 03:56:08'),
(110, 6, 'สลัดโรลอกไก่ฉีกน้ำจิ้มซีฟู้ดโยเกิร์ต', 250, 'สลัดโรลที่อุดมด้วยผักสดกรอบและอกไก่ฉีกไร้มัน ทานคู่กับน้ำจิ้มซีฟู้ดโยเกิร์ตสูตรไร้น้ำมันและลดโซเดียม เหมาะสำหรับมื้อว่างเบาๆ', '2026-03-08 03:56:08'),
(111, 6, 'ผัดผักรวมมิตรน้ำมันหอยอกไก่', 850, 'อกไก่หั่นชิ้นผัดกับผักรวมมิตรหลากหลายชนิด ปรุงรสด้วยน้ำมันหอยสูตรลดโซเดียมและใช้น้ำมันรำข้าวในปริมาณที่พอเหมาะ เสิร์ฟพร้อมข้าวกล้อง เพื่อความอิ่มและสารอาหารครบถ้วน', '2026-03-08 03:56:08'),
(112, 6, 'ข้าวกล้องผัดธัญพืชรวมและอกไก่', 600, 'ข้าวกล้องหอมนุ่มผัดกับธัญพืชหลากหลายชนิด อาทิ ข้าวโพด ถั่วลันเตา และอกไก่หั่นชิ้น ปรุงรสอย่างกลมกล่อมด้วยซีอิ๊วขาวลดโซเดียมและน้ำมันหอยสูตรไขมันต่ำ เน้นโปรตีนและใยอาหารสูง เหมาะสำหรับมื้อหลักที่ต้องการพลังงาน', '2026-03-08 04:12:18'),
(113, 6, 'ก๋วยเตี๋ยวลุยสวนอกไก่', 550, 'เมนูเพื่อสุขภาพที่อัดแน่นไปด้วยผักสดนานาชนิด ห่อด้วยแผ่นแป้งบางเบาพร้อมไส้อกไก่สับปรุงรสน้อยๆ เสิร์ฟพร้อมน้ำจิ้มซีฟู้ดสูตรลดโซเดียมและน้ำตาล เพื่อรสชาติที่สดชื่นและดีต่อสุขภาพหัวใจ', '2026-03-08 04:12:18'),
(114, 6, 'ผัดกะเพราอกไก่สับไข่ดาวน้ำ', 750, 'อกไก่สับผัดกะเพราถึงเครื่อง ปรุงรสแบบลดโซเดียมและน้ำตาลเพื่อให้เหมาะกับผู้ป่วยเบาหวานและความดันสูง เสิร์ฟพร้อมข้าวกล้องหุงสุก และไข่ดาวน้ำไร้น้ำมัน โปรตีนสูง ช่วยเสริมสร้างกล้ามเนื้อได้ดี', '2026-03-08 04:12:18'),
(115, 6, 'แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม', 500, 'ขนมปังโฮลวีตเต็มแผ่นประกบด้วยอกไก่ย่างหอมๆ และไข่ต้มหั่นชิ้น พร้อมผักสดกรอบๆ เช่น ผักกาดหอมและมะเขือเทศ เป็นมื้อว่างที่อุดมไปด้วยโปรตีนและใยอาหาร ช่วยให้อิ่มนานและควบคุมระดับน้ำตาลได้ดี', '2026-03-08 04:12:18'),
(116, 6, 'อกไก่นุ่มย่างสมุนไพรและควิโนอา', 550, 'อกไก่นุ่มหมักสมุนไพรย่างจนหอมกรุ่น เสิร์ฟคู่กับควิโนอาหุงสุก ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อนที่ดีต่อผู้ป่วยเบาหวาน และผักนึ่งหลากสีสัน ปรุงรสอ่อนเพื่อสุขภาพที่ดี', '2026-03-08 04:14:17'),
(117, 6, 'ปลานึ่งมะนาวสูตรโซเดียมต่ำ', 650, 'ปลากะพงเนื้อนุ่มนึ่งกับน้ำซุปมะนาวรสจัดจ้านแต่โซเดียมต่ำ ใส่ผักชีฝรั่ง พริก และกระเทียม ทานคู่กับข้าวกล้องหอมมะลิ เพื่อให้ได้โปรตีนและคาร์โบไฮเดรตที่สมบูรณ์', '2026-03-08 04:14:17'),
(118, 6, 'แซลมอนย่างซีอิ๊วและบล็อกโคลี่นึ่ง', 680, 'เนื้อปลาแซลมอนชิ้นโตย่างซีอิ๊วสูตรลดโซเดียมหอมกรุ่น ซึ่งอุดมไปด้วยโอเมก้า 3 ที่ดีต่อหัวใจและหลอดเลือด เสิร์ฟเคียงกับบล็อกโคลี่นึ่งร้อนๆ เพื่อเพิ่มวิตามินและใยอาหาร', '2026-03-08 04:14:17'),
(119, 6, 'สลัดทูน่าอะโวคาโด', 300, 'ทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดหั่นเต๋า มะเขือเทศเชอร์รี่ และผักสลัดหลากสี อุดมด้วยโปรตีน ไขมันดี และใยอาหาร ปรุงรสด้วยน้ำสลัดใสไขมันต่ำเพื่อสุขภาพ', '2026-03-08 04:14:17'),
(120, 9, 'อกไก่นุ่มย่างสมุนไพรและควิโนอา', 700, 'เมนูเช้าที่ให้พลังงานสูงจากควิโนอา ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อน มีโปรตีนสูงจากอกไก่ และไขมันดีจากสมุนไพรและน้ำมันมะกอกที่ใช้ย่าง ช่วยให้อิ่มนานและมีพลังงานเพียงพอสำหรับการเริ่มต้นวัน', '2026-03-08 04:16:28'),
(121, 9, 'สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง', 1000, 'มื้อกลางวันที่อุดมด้วยกรดไขมันโอเมก้า 3 จากแซลมอน ซึ่งดีต่อสุขภาพหัวใจและสมอง โปรตีนสูง และแคลอรี่ที่เหมาะสมสำหรับการเพิ่มน้ำหนัก เสิร์ฟพร้อมหน่อไม้ฝรั่งและข้าวกล้องหอมมะลิหรือควิโนอา เพื่อพลังงานและใยอาหารที่ครบถ้วน', '2026-03-08 04:16:28'),
(122, 9, 'สลัดทูน่าอะโวคาโด', 500, 'มื้อว่างที่ช่วยเติมพลังงานระหว่างวันได้อย่างมีสุขภาพดี ด้วยโปรตีนจากทูน่า (เลือกทูน่าในน้ำแร่หรือน้ำมันมะกอก) และไขมันดีจากอะโวคาโด ช่วยให้รู้สึกอิ่มและได้รับสารอาหารที่สำคัญ', '2026-03-08 04:16:28'),
(123, 9, 'ข้าวผัดธัญพืชอกไก่', 900, 'มื้อเย็นที่ให้คาร์โบไฮเดรตเชิงซ้อนจากธัญพืชหลากหลายชนิด พร้อมโปรตีนจากอกไก่ ปรุงรสอ่อนโดยใช้สมุนไพรและเครื่องเทศ เพื่อลดโซเดียมและน้ำตาล แต่ยังคงความอร่อยและได้สารอาหารครบถ้วน', '2026-03-08 04:16:28'),
(124, 9, 'ไข่ตุ๋นทรงเครื่อง', 550, 'ไข่ตุ๋นเนื้อเนียนนุ่ม ปรุงรสอ่อนๆ ใส่เนื้ออกไก่สับไม่ติดมันและผักหลากสี เสิร์ฟพร้อมข้าวกล้องหอมนุ่ม เพื่อเพิ่มโปรตีนและคาร์โบไฮเดรตเชิงซ้อน เป็นมื้อเช้าที่อิ่มสบายและมีประโยชน์', '2026-03-08 04:18:59'),
(125, 9, 'พาสต้าโฮลวีทผัดพริกแห้งและทูน่า', 700, 'พาสต้าโฮลวีทเหนียวนุ่ม ผัดคลุกเคล้ากับทูน่าในน้ำแร่ พริกแห้ง และกระเทียม ปรุงรสด้วยน้ำมันมะกอกและสมุนไพร ให้พลังงานสูงจากคาร์โบไฮเดรตเชิงซ้อนและโปรตีนดี', '2026-03-08 04:18:59'),
(126, 9, 'ผัดบล็อกโคลี่กุ้งสด', 750, 'บล็อกโคลี่สดกรอบผัดกับกุ้งสดตัวโต ปรุงรสด้วยซอสสูตรลดโซเดียมและน้ำมันหอยลดเค็ม เพิ่มความหอมด้วยกระเทียม เสิร์ฟพร้อมข้าวกล้องร้อนๆ เป็นเมนูที่อุดมไปด้วยโปรตีน ใยอาหาร และแร่ธาตุ', '2026-03-08 04:18:59'),
(127, 9, 'เส้นโซบะเย็นซอสถั่วใส่เต้าหู้ย่าง', 600, 'เส้นโซบะเหนียวนุ่ม ท็อปด้วยเต้าหู้ขาวแผ่นย่างหอมๆ และผักสดนานาชนิด ราดด้วยซอสถั่วลิสงสูตรเฉพาะที่ลดโซเดียมและน้ำตาล ให้พลังงานและโปรตีนที่ดีต่อร่างกาย เป็นมื้อว่างที่อิ่มและมีประโยชน์', '2026-03-08 04:18:59'),
(128, 9, 'ข้าวต้มข้าวกล้องอกไก่ฉีกและขิงซอย - มื้อเช้า', 380, 'เมนูย่อยง่าย ให้พลังงานดีเยี่ยมสำหรับเริ่มต้นวันใหม่ของคุณKha อกไก่ให้โปรตีนสูง ขิงช่วยขับลมและบำรุงธาตุ ข้าวกล้องให้คาร์โบไฮเดรตเชิงซ้อนที่ดีต่อการควบคุมระดับน้ำตาลในเลือดและปลอดภัยสำหรับผู้ป่วยความดันสูงเพราะมีโซเดียมต่ำครับ', '2026-03-08 04:24:37'),
(129, 9, 'ข้าวกล้องอกไก่ผัดขิงเห็ดหอม - มื้อกลางวัน', 600, 'เมนูนี้จัดเต็มด้วยรสชาติหอมจากขิงและเห็ดหอมครับ อกไก่เป็นโปรตีนลีนชั้นดี ขิงช่วยกระตุ้นการเผาผลาญและลดไขมัน ส่วนการใช้ซีอิ๊วและน้ำมันหอยลดโซเดียมช่วยให้คุณKha ทานได้อย่างสบายใจเรื่องความดันครับ', '2026-03-08 04:24:37'),
(130, 9, 'ลาบอกไก่สมุนไพร - มื้อเย็น', 350, 'เมนูลาบไก่สมุนไพรเป็นตัวเลือกที่ยอดเยี่ยมสำหรับมื้อเย็นของคุณKha ครับ เพราะให้โปรตีนสูงจากอกไก่และมีสมุนไพรนานาชนิดช่วยเรื่องระบบย่อยอาหาร การใช้ข้าวคั่วช่วยเพิ่มกลิ่นหอมและใยอาหาร พร้อมกับน้ำปลาลดโซเดียม ทำให้เป็นเมนูที่สดชื่นและปลอดภัยต่อสุขภาพหัวใจและเบาหวานครับ', '2026-03-08 04:24:37'),
(131, 9, 'สลัดโรลอกไก่ฉีกน้ำจิ้มซีฟู้ดโยเกิร์ต - มื้อว่าง', 450, 'สลัดโรลอกไก่ฉีกเป็นมื้อว่างที่เหมาะสำหรับคุณKha ที่ต้องการความสดชื่นและประโยชน์ครบถ้วนครับ อกไก่ให้โปรตีนสูง ผักสดให้วิตามินและใยอาหาร น้ำจิ้มซีฟู้ดโยเกิร์ตปรุงด้วยโยเกิร์ตไขมันต่ำและลดโซเดียม ช่วยลดความเสี่ยงทั้งเบาหวานและความดันสูงได้อย่างดีเยี่ยมเลยครับ', '2026-03-08 04:24:37'),
(132, 9, 'โจ๊กข้าวกล้องหมูสับและเห็ดหอม - มื้อเช้า', 720, 'เมนูย่อยง่ายแต่ให้พลังงานสูง เหมาะสำหรับมื้อเช้าของคุณKhaครับ มีคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง โปรตีนจากหมูสับและไข่ และไขมันดีจากน้ำมันงา ช่วยควบคุมระดับน้ำตาลได้ดีและดีต่อความดัน', '2026-03-08 04:26:59'),
(133, 9, 'ผัดไทยวุ้นเส้นอกไก่สูตรลดโซเดียม - มื้อกลางวัน', 980, 'ผัดไทยสูตรนี้เน้นวุ้นเส้นและอกไก่ ให้พลังงานสูงจากคาร์โบไฮเดรต โปรตีน และไขมันดีจากถั่วลิสง ลดโซเดียมเพื่อคุณKhaครับ เหมาะสำหรับมื้อกลางวันที่ต้องการพลังงานไปทำงานต่อ', '2026-03-08 04:26:59'),
(134, 9, 'ปลากะพงนึ่งซีอิ๊วขิงแก่กับข้าวกล้อง - มื้อเย็น', 950, 'เมนูนี้ดีต่อสุขภาพของคุณKhaมากๆ ครับ มีโปรตีนสูงจากปลากะพง ไขมันต่ำ และลดโซเดียม ขิงช่วยเพิ่มรสชาติและคุณประโยชน์ หาทานคู่กับข้าวกล้องปริมาณเหมาะสมเพื่อเพิ่มพลังงานให้ถึงเป้าหมายนะครับ', '2026-03-08 04:26:59'),
(135, 9, 'สลัดทูน่าอะโวคาโด - มื้อว่าง', 650, 'สลัดทูน่าอะโวคาโดเป็นเมนูว่างที่ให้พลังงานสูงและอุดมไปด้วยไขมันดีจากอะโวคาโดและน้ำมันมะกอก ซึ่งจำเป็นสำหรับการเพิ่มน้ำหนักของคุณKhaครับ มีโปรตีนจากทูน่า และใยอาหารจากผัก ช่วยบำรุงหัวใจและควบคุมระดับน้ำตาลได้เป็นอย่างดี', '2026-03-08 04:26:59'),
(136, 9, 'ข้าวต้มอกไก่เห็ดหอม', 650, 'เมนูย่อยง่ายแต่ให้พลังงานสูง เหมาะสำหรับมื้อเช้า ช่วยควบคุมระดับน้ำตาลและโซเดียมได้ดีครับ', '2026-03-08 04:30:23'),
(137, 9, 'ไก่ผัดเม็ดมะม่วงหิมพานต์กับข้าวกล้อง', 950, 'เมนูนี้อุดมด้วยโปรตีนจากไก่ และไขมันดีจากเม็ดมะม่วงหิมพานต์ ช่วยเพิ่มน้ำหนักอย่างมีคุณภาพและให้พลังงานสูงครับ', '2026-03-08 04:30:23'),
(138, 9, 'อกไก่ผัดพริกแกงถั่วฝักยาวกับข้าวกล้อง', 950, 'เมนูรสชาติเข้มข้นที่ให้โปรตีนสูงและใยอาหารจากถั่วฝักยาว ช่วยเพิ่มพลังงานได้ดีและยังคงคุมโซเดียมและน้ำตาลครับ', '2026-03-08 04:30:23'),
(139, 9, 'ยำวุ้นเส้นอกไก่ฉีก', 665, 'เมนูนี้สดชื่นและให้โปรตีนสูง พร้อมใยอาหารจากผักและวุ้นเส้น เหมาะเป็นมื้อว่างที่ช่วยเสริมพลังงานเพื่อเพิ่มน้ำหนักครับ', '2026-03-08 04:30:23'),
(140, 12, 'แกงจืดเต้าหู้หมูสับ', 320, 'เมนูเบาๆ ย่อยง่าย ได้โปรตีนจากหมูและเต้าหู้ พร้อมใยอาหารจากผัก เหมาะสำหรับมื้อเช้าของคุณโจจิ ช่วยให้อิ่มสบายท้องและได้รับพลังงานอย่างพอเหมาะครับ', '2026-03-09 05:01:57'),
(141, 12, 'ลาบหมู', 380, 'ลาบหมูเป็นเมนูโปรตีนสูง ไขมันต่ำ (หากเลือกหมูไม่ติดมัน) รสจัดจ้านจากสมุนไพรสด ช่วยเพิ่มความสดชื่นและกระตุ้นการเผาผลาญได้ดีสำหรับคุณโจจิครับ แนะนำให้ทานคู่กับข้าวกล้องหรือผักสดเยอะๆ ครับ', '2026-03-09 05:01:57'),
(142, 12, 'ส้มตำไทย', 180, 'ส้มตำไทยเป็นเมนูเบาๆ ที่อุดมด้วยใยอาหารและวิตามินซีจากมะละกอและผักต่างๆ ช่วยเรื่องระบบขับถ่ายและให้ความสดชื่น เหมาะสำหรับเป็นของว่างยามบ่ายของคุณโจจิครับ', '2026-03-09 05:01:57'),
(143, 12, 'ปลากะพงนึ่งมะนาว', 450, 'ปลากะพงนึ่งมะนาวเป็นเมนูที่ให้โปรตีนสูง ไขมันต่ำ และได้ประโยชน์จากสมุนไพรต่างๆ ช่วยบำรุงสุขภาพและควบคุมน้ำหนักได้ดีสำหรับคุณโจจิครับ การนึ่งเป็นวิธีปรุงที่ช่วยรักษาสารอาหารได้ดีที่สุดครับ', '2026-03-09 05:01:57'),
(144, 9, 'ข้าวผัดแซลมอนเห็ดหอมแครอท', 880, 'เมนูเช้าที่อุดมไปด้วยโปรตีนจากแซลมอนและไข่ พร้อมคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง ช่วยให้คุณKhaอิ่มนานและได้รับพลังงานที่สม่ำเสมอ เห็ดหอมและแครอทเพิ่มใยอาหารและวิตามิน การใช้ซีอิ๊วลดโซเดียมช่วยควบคุมความดันได้อย่างดีเยี่ยมครับ', '2026-03-09 14:38:19'),
(145, 9, 'แกงเขียวหวานไก่', 810, 'แกงเขียวหวานไก่เป็นเมนูที่ให้พลังงานสูง เหมาะสำหรับการเพิ่มน้ำหนักของคุณKhaครับ การใช้สะโพกไก่ไม่มีหนังช่วยเพิ่มโปรตีนและไขมันดี การเลือกกะทิไขมันต่ำ/กะทิธัญพืช พริกแกงลดโซเดียม และการไม่เติมน้ำตาลจะช่วยควบคุมระดับน้ำตาลในเลือดและความดันโลหิตได้เป็นอย่างดีครับ', '2026-03-09 14:38:19'),
(146, 9, 'แซลมอนย่างซีอิ๊วลดโซเดียมกับผักรวม', 780, 'เมนูนี้ดีต่อสุขภาพหัวใจของคุณKhaอย่างมาก ด้วยกรดไขมันโอเมก้า 3 จากแซลมอน และใยอาหารสูงจากแครอทและบรอกโคลี การใช้ซีอิ๊วลดโซเดียมจะช่วยควบคุมโซเดียมได้ดีครับ เป็นอีกมื้อที่ให้โปรตีนและพลังงานสูง เหมาะกับการเพิ่มน้ำหนักอย่างมีคุณภาพ', '2026-03-09 14:38:19'),
(147, 9, 'ขนมปังโฮลวีทหน้าไข่คนเห็ดหอมแครอท', 420, 'เป็นมื้อว่างที่อุดมด้วยโปรตีนจากไข่ และคาร์โบไฮเดรตเชิงซ้อนจากขนมปังโฮลวีท ซึ่งช่วยให้คุณKhaได้รับพลังงานต่อเนื่องไปถึงมื้อถัดไปครับ เห็ดหอมและแครอทยังช่วยเพิ่มใยอาหารและสารอาหารที่จำเป็น เป็นการเพิ่มน้ำหนักที่ใส่ใจสุขภาพและคุมระดับน้ำตาลได้ดีเยี่ยมครับ', '2026-03-09 14:38:19'),
(148, 9, 'ไข่ตุ๋นทรงเครื่อง', 280, 'เมนูมื้อเช้าโปรตีนสูง ไขมันต่ำ อุดมไปด้วยใยอาหารจากผัก และดีต่อการควบคุมระดับน้ำตาลในเลือด เหมาะสำหรับคุณKha ที่ต้องการควบคุมเบาหวานและความดันครับ', '2026-03-09 15:55:41'),
(149, 9, 'แกงส้มชะอมกุ้ง', 520, 'เมนูรสจัดจ้านที่อุดมไปด้วยโปรตีนจากกุ้งและไข่ชะอม มีใยอาหารสูงจากผักนานาชนิด และไขมันต่ำ การเลือกใช้น้ำปลาลดโซเดียมและลดน้ำตาลจะช่วยควบคุมโรคเบาหวานและความดันโลหิตสูงได้ดีครับ', '2026-03-09 15:55:41'),
(150, 9, 'แกงจืดเต้าหู้หมูสับ', 400, 'เมนูมื้อเย็นเบาๆ ที่ย่อยง่าย อุดมด้วยโปรตีนจากเต้าหู้และหมูสับ มีใยอาหารจากผัก และโซเดียมต่ำ เหมาะสำหรับคุณKha เพื่อรักษาระดับน้ำตาลและความดันโลหิตให้คงที่ครับ', '2026-03-09 15:55:41'),
(151, 9, 'ผลไม้รวมหั่นเต๋า', 120, 'มื้อว่างที่สดชื่น มีวิตามินและใยอาหารสูง ช่วยให้อิ่มนานขึ้นโดยไม่เพิ่มน้ำตาลในเลือดมากเกินไป ควรเลือกผลไม้ที่มีรสไม่หวานจัด เพื่อสุขภาพที่ดีของคุณKha ครับ', '2026-03-09 15:55:41'),
(154, 9, 'เต้าฮวยฟรุตสลัด (ไม่ใส่น้ำเชื่อม)', 250, 'ของว่างเย็นๆ ชื่นใจ ให้โปรตีนจากเต้าฮวย วิตามินและใยอาหารจากผลไม้ โดยไม่ใส่น้ำเชื่อม จึงดีต่อผู้ป่วยเบาหวานและช่วยคุมน้ำหนักได้ดีครับ', '2026-03-12 01:48:14'),
(155, 9, 'กุ้งอบวุ้นเส้น', 600, 'เมนูยอดนิยมที่อุดมด้วยโปรตีนจากกุ้งและวุ้นเส้นที่ให้พลังงานกำลังดี โดยเน้นการลดโซเดียมและไขมัน และเพิ่มขิงเพื่อสุขภาพที่ดีของคุณKhaครับ', '2026-03-12 01:48:14'),
(156, 8, 'ข้าวต้มไก่', 350, 'เมนูย่อยง่าย เหมาะกับการเริ่มต้นวันใหม่ของคุณsql ครับ ให้พลังงานกำลังดีและโปรตีนจากไก่จะช่วยให้อิ่มสบายท้องไปจนถึงมื้อกลางวันครับ', '2026-03-16 15:25:02'),
(157, 8, 'ข้าวมันไก่', 580, 'ข้าวมันไก่เป็นเมนูยอดนิยมที่ให้พลังงานดีเยี่ยมสำหรับมื้อกลางวันของคุณsql ครับ มีทั้งคาร์โบไฮเดรตและโปรตีนครบถ้วน อิ่มอร่อยได้ไม่น่าเบื่อเลยครับ', '2026-03-16 15:25:02'),
(158, 8, 'แกงเขียวหวานไก่', 680, 'แกงเขียวหวานไก่เป็นเมนูไทยคลาสสิกที่อุดมไปด้วยสมุนไพรและรสชาติจัดจ้านครับคุณsql เหมาะสำหรับมื้อเย็นที่ต้องการความอร่อยและได้พลังงานกำลังดี ทานคู่กับข้าวสวยร้อนๆ อร่อยลงตัวครับ', '2026-03-16 15:25:02'),
(159, 8, 'อกไก่ย่างสมุนไพร', 280, 'เมนูอกไก่ย่างสมุนไพรเป็นมื้อว่างที่เหมาะสำหรับคุณsql มากๆ ครับ ให้โปรตีนสูง ไขมันต่ำ ช่วยให้อิ่มนานและควบคุมน้ำหนักได้ดีเยี่ยมเลยครับ หากไม่ทานน้ำจิ้มแคลอรี่ก็จะลดลงไปอีกครับ', '2026-03-16 15:25:02'),
(160, 9, 'ข้าวต้มปลาอินทรี', 380, 'ข้าวต้มปลาอินทรีเป็นอาหารเช้าที่ย่อยง่าย ให้โปรตีนสูงจากปลาอินทรีซึ่งมีไขมันดีโอเมก้า 3 และมีคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้องที่ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี เหมาะสำหรับคุณKha ที่ต้องการควบคุมเบาหวานและความดัน โดยเน้นการปรุงรสแบบลดโซเดียมและปราศจากกลูเตนครับ', '2026-03-19 04:22:44'),
(161, 9, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 520, 'ผัดกะเพราไก่สับอกราดข้าวกล้องเป็นเมนูโปรดของใครหลายคน และดีต่อสุขภาพของคุณKha ด้วยการใช้อกไก่สับซึ่งเป็นโปรตีนไร้ไขมัน ข้าวกล้องเพิ่มใยอาหารและช่วยคุมระดับน้ำตาล และการปรับลดโซเดียมกับน้ำตาลในเครื่องปรุงครับ เมนูนี้จะช่วยให้คุณKha อิ่มนานและได้รับพลังงานอย่างเหมาะสมในมื้อกลางวันครับ', '2026-03-19 04:22:44'),
(162, 9, 'ยำวุ้นเส้นหมูสับ', 320, 'ยำวุ้นเส้นหมูสับเป็นเมนูเบาๆ ที่ให้โปรตีนจากหมูสับส่วนสันในและวุ้นเส้นที่ปราศจากกลูเตน อุดมด้วยใยอาหารจากผักสดหลากหลายชนิด และมีรสชาติจัดจ้านสดชื่นจากสมุนไพรและน้ำยำที่ปรุงพิเศษสำหรับคุณKha ด้วยการลดปริมาณโซเดียมและน้ำตาล ทำให้เป็นมื้อว่างที่อร่อยและดีต่อสุขภาพครับ', '2026-03-19 04:22:44'),
(163, 9, 'แกงป่าหมู', 450, 'แกงป่าหมูเป็นแกงที่ขึ้นชื่อเรื่องรสชาติจัดจ้านและดีต่อสุขภาพของคุณKha อย่างยิ่งครับ เพราะไม่มีส่วนผสมของกะทิ ทำจากเนื้อหมูส่วนสันในติดมันน้อยและผักนานาชนิด ให้ใยอาหารสูง โปรตีนดี และสมุนไพรที่มีประโยชน์ต่อการไหลเวียนโลหิต ช่วยเสริมสุขภาพหัวใจและควบคุมความดันได้ดีเยี่ยมครับ โดยเราจะเลือกใช้พริกแกงที่ปราศจากกลูเตนและลดโซเดียมเป็นพิเศษครับ', '2026-03-19 04:22:44'),
(164, 9, 'ข้าวต้มเห็ดหอมไก่สับ', 480, 'เมนูย่อยง่าย อุดมด้วยโปรตีนคุณภาพจากอกไก่และใยอาหารจากข้าวกล้องและเห็ดหอม ช่วยควบคุมระดับน้ำตาลในเลือดและดีต่อระบบหัวใจและหลอดเลือด เหมาะสำหรับมื้อเช้าที่ต้องการพลังงานและดูแลสุขภาพอย่างรอบด้านครับคุณKha', '2026-03-19 04:24:38'),
(165, 9, 'ลาบหมูข้าวกล้อง', 620, 'เมนูโปรตีนสูง ไขมันต่ำ เต็มไปด้วยสมุนไพรสดและเครื่องเทศ ที่ช่วยเสริมสร้างภูมิคุ้มกันและลดความดันโลหิต การใช้ข้าวคั่วจากข้าวเหนียวแท้และน้ำปลาลดโซเดียมทำให้เมนูนี้ปราศจากกลูเตนและโซเดียมต่ำ เหมาะกับคุณKha มากๆ เลยครับ', '2026-03-19 04:24:38'),
(166, 9, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 600, 'เมนูนี้อุดมด้วยโปรตีนจากเนื้อปลา ไขมันต่ำ และได้ประโยชน์จากสมุนไพรนานาชนิด ช่วยกระตุ้นการเผาผลาญและบำรุงหัวใจ ปรุงรสแบบจัดจ้านแต่ลดโซเดียมและปราศจากกลูเตน ทำให้ดีต่อเบาหวานและความดันของคุณKha ครับ', '2026-03-19 04:24:38'),
(167, 9, 'เมี่ยงปลาทู', 400, 'เมี่ยงปลาทูเป็นเมนูของว่างที่ครบเครื่องเรื่องสุขภาพครับคุณKha ได้โปรตีนดีๆ จากปลาทูและโอเมก้า 3 ที่ช่วยบำรุงสมองและหัวใจ พร้อมใยอาหารจากผักสดนานาชนิด ช่วยควบคุมระดับน้ำตาลในเลือด ลดความดันโลหิต และปราศจากกลูเตน เหมาะกับการเป็นมื้อว่างที่อร่อยและดีต่อสุขภาพครับ', '2026-03-19 04:24:38'),
(168, 9, 'ข้าวต้มอกไก่ใส่เห็ดและขิง', 380, 'เมนูยามเช้าที่ย่อยง่าย ให้พลังงานดีเยี่ยม โปรตีนสูงจากอกไก่ ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี เหมาะสำหรับผู้ป่วยเบาหวานและความดันสูง และปราศจากกลูเตนครับ', '2026-03-19 04:53:28'),
(169, 9, 'แกงเขียวหวานอกไก่', 620, 'เมนูโปรดของคุณKha หลายคน โดยเราปรับให้ดีต่อสุขภาพมากขึ้น ลดปริมาณกะทิและน้ำตาล แต่ยังคงความหอมอร่อยและได้โปรตีนจากอกไก่เต็มๆ ครับ ปราศจากกลูเตนและควบคุมความเค็มเพื่อสุขภาพหัวใจที่ดี', '2026-03-19 04:53:28'),
(170, 9, 'ต้มข่าไก่ใส่มะพร้าวอ่อน', 500, 'เมนูหอมกลิ่นสมุนไพรไทย ช่วยให้เจริญอาหารได้ดีครับคุณKha เราใช้เนื้ออกไก่เพื่อโปรตีนคุณภาพดี และลดปริมาณกะทิเพื่อควบคุมไขมัน ให้รสชาติกลมกล่อมและปราศจากกลูเตนครับ', '2026-03-19 04:53:28'),
(171, 9, 'อกไก่ย่างสมุนไพรกับผักลวก', 250, 'เป็นมื้อว่างโปรตีนสูงที่ช่วยให้อิ่มท้องได้นาน ดีต่อการควบคุมน้ำหนัก และรักษาสมดุลของระดับน้ำตาลในเลือดครับคุณKha เมนูนี้ไขมันต่ำ ปราศจากกลูเตน และได้คุณประโยชน์จากสมุนไพรและผักครบถ้วน', '2026-03-19 04:53:28'),
(172, 14, 'ข้าวต้มอกไก่ใส่เห็ดและขิง', 450, 'เมนูย่อยง่าย เบาสบายท้อง เหมาะสำหรับมื้อเช้า ให้พลังงานที่คงที่จากข้าวและโปรตีนจากอกไก่ ช่วยควบคุมระดับน้ำตาลได้ดี และดีต่อหัวใจ ไต และผู้ป่วยโรคเก๊าท์ เนื่องจากใช้เนื้อไก่ส่วนอก ซึ่งมีไขมันและพิวรีนต่ำ', '2026-03-20 12:58:27'),
(174, 14, 'ฟักทองนึ่ง', 150, 'ฟักทองนึ่งเป็นของว่างที่ยอดเยี่ยมสำหรับคุณวิกรมครับ ให้ใยอาหารสูง ช่วยให้อิ่มนาน มีวิตามินและแร่ธาตุที่จำเป็น และมีรสหวานตามธรรมชาติ ไม่ต้องเติมน้ำตาลเพิ่ม เหมาะสำหรับผู้ป่วยเบาหวานและผู้ที่ต้องการควบคุมน้ำหนัก ไม่มีส่วนผสมของสารก่อภูมิแพ้ใดๆ เลยครับ', '2026-03-20 12:58:27'),
(176, 14, 'ข้าวต้มเห็ดหอมไก่สับ', 380, 'เมนูมื้อเช้าที่ย่อยง่าย ให้โปรตีนและคาร์โบไฮเดรตเชิงซ้อน ช่วยให้คุณวิกรมมีพลังงานตลอดเช้า เหมาะสำหรับการรักษาน้ำหนักและเป็นมื้อที่สบายท้องครับ', '2026-03-20 13:00:10'),
(182, 14, 'ลาบหมูข้าวกล้อง', 410, 'ลาบหมูข้าวกล้องเป็นเมนูอาหารเย็นที่อร่อย จัดจ้าน และได้สุขภาพดีจากข้าวกล้องที่มีใยอาหารสูง รวมถึงโปรตีนจากหมู ช่วยให้อิ่มนานและควบคุมน้ำหนักได้ดีสำหรับคุณวิกรมครับ', '2026-03-20 13:07:01'),
(184, 9, 'ไข่เจียวหมูสับกับผักลวก', 350, 'เมนูมื้อเช้าที่อุดมไปด้วยโปรตีนจากไข่และหมูสับ ปรุงรสอ่อน ลดโซเดียม และใช้น้ำมันน้อย ช่วยควบคุมระดับน้ำตาลและความดันได้ดีครับคุณKha', '2026-03-22 08:34:48'),
(186, 9, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 220, 'ของว่างนี้ให้โปรไบโอติกที่ดีต่อลำไส้จากโยเกิร์ต วิตามินซีสูงจากกีวี่ และใยอาหารจากธัญพืช ช่วยให้อิ่มท้องและรักษาระดับน้ำตาลในเลือดให้คงที่ครับคุณKha', '2026-03-22 08:34:48'),
(187, 9, 'แกงส้มกุ้งชะอมไข่', 450, 'เมนูมื้อเย็นรสกลมกล่อม เปรี้ยว เผ็ด หวานน้อย เน้นโปรตีนจากกุ้งและไข่ชะอม มีใยอาหารสูงจากผักนานาชนิด ช่วยให้คุณKhaอิ่มสบายท้อง และยังดีต่อการควบคุมน้ำตาลและความดันโลหิตอีกด้วยครับ', '2026-03-22 08:34:48'),
(189, 9, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 520, 'เมนูยอดนิยมที่ปรับให้ดีต่อสุขภาพคุณroot โปรตีนสูงจากอกไก่และใยอาหารจากข้าวกล้องและผัก ปรุงรสโดยลดโซเดียมและงดน้ำตาล เหมาะสำหรับคุณrootที่ควบคุมเบาหวานและความดัน และปราศจากกลูเตนแน่นอนครับ', '2026-03-22 08:40:45'),
(190, 9, 'ฟักทองนึ่ง', 120, 'ของว่างเพื่อสุขภาพที่มีใยอาหารสูง ช่วยควบคุมระดับน้ำตาลในเลือดและให้พลังงานที่ดีจากคาร์โบไฮเดรตเชิงซ้อน ไม่มีกลูเตนและโซเดียมต่ำ เป็นตัวเลือกที่ยอดเยี่ยมสำหรับคุณrootเลยครับ', '2026-03-22 08:40:45'),
(191, 9, 'ไก่ผัดขิงกับเห็ดและข้าวกล้อง', 500, 'เมนูย่อยง่าย รสชาติกลมกล่อมจากขิงช่วยกระตุ้นการไหลเวียนเลือด และดีต่อระบบย่อยอาหาร อุดมด้วยโปรตีนและใยอาหารจากอกไก่ เห็ด และข้าวกล้อง ปรุงรสแบบปราศจากกลูเตนและลดโซเดียม เป็นมื้อเย็นที่เบาสบายและเหมาะสมกับคุณrootมากๆ ครับ', '2026-03-22 08:40:45'),
(192, 9, 'แกงจืดเต้าหู้หมูสับ (กับข้าวกล้อง)', 380, 'เมนูยามเช้าที่ย่อยง่าย ให้โปรตีนดีจากหมูสับและเต้าหู้ไข่ ผักหลากหลายชนิดให้ใยอาหาร ช่วยควบคุมระดับน้ำตาลในเลือดและดูแลความดันโลหิตได้ดี เพราะปรุงรสอ่อนและปราศจากกลูเตนครับ', '2026-03-22 08:43:41'),
(193, 9, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 600, 'เมนูนี้ดีต่อใจและดีต่อสุขภาพของคุณมากครับคุณ! ปลานึ่งให้โปรตีนคุณภาพสูงและไขมันดี (โอเมก้า 3) จากปลา ผักและเครื่องปรุงรสธรรมชาติช่วยลดโซเดียม ปราศจากกลูเตน และข้าวไรซ์เบอร์รี่เป็นคาร์โบไฮเดรตเชิงซ้อนที่ดีต่อการควบคุมระดับน้ำตาลครับ', '2026-03-22 08:43:41'),
(194, 9, 'อกไก่ย่างสมุนไพรกับผักลวกและข้าวกล้อง', 550, 'เมนูนี้ให้โปรตีนสูง ไขมันต่ำ และใยอาหารมากครับคุณ เหมาะสำหรับมื้อเย็นที่ต้องการความเบาสบายแต่ยังคงอิ่มท้องและได้รับสารอาหารครบถ้วน ช่วยดูแลระดับน้ำตาลและควบคุมความดันโลหิตได้ดีเยี่ยมเลยครับ', '2026-03-22 08:43:41'),
(195, 9, 'เมี่ยงปลาทู', 400, 'เมนูของว่างที่สดชื่นและมีประโยชน์มากครับคุณ! เมี่ยงปลาทูให้ไขมันดีจากปลาทูและถั่วลิสง และใยอาหารสูงจากผักสดหลายชนิด สามารถทำเป็นเมนูไร้น้ำตาลและปราศจากกลูเตนได้ง่ายๆ เหมาะสำหรับผู้ที่ต้องการควบคุมน้ำหนักและดูแลสุขภาพเบาหวานและความดันครับ', '2026-03-22 08:43:41'),
(196, 9, 'ข้าวต้มปลาอินทรี', 420, 'เมนูมื้อเช้าที่ย่อยง่ายและดีต่อสุขภาพหัวใจครับคุณadmin ให้โปรตีนสูงจากปลาอินทรี และใยอาหารจากข้าวกล้องที่ช่วยควบคุมระดับน้ำตาลได้ดี ปรุงรสน้อยเพื่อควบคุมความดันโลหิต และปราศจากกลูเตนแน่นอนครับ', '2026-03-22 08:46:07'),
(197, 9, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 280, 'เป็นอาหารว่างที่ดีเยี่ยมสำหรับคุณadminครับ ให้โปรไบโอติกส์ที่ดีต่อลำไส้ ใยอาหารสูงจากกีวี่และธัญพืช ช่วยควบคุมระดับน้ำตาลและให้พลังงานอย่างต่อเนื่อง ปราศจากกลูเตนและน้ำตาลเพิ่ม เหมาะกับผู้ที่ต้องการดูแลสุขภาพในระยะยาวครับ', '2026-03-22 08:46:07'),
(198, 9, 'แกงส้มกุ้งชะอมไข่ กับข้าวกล้อง', 650, 'แกงส้มเป็นเมนูที่ดีเยี่ยมสำหรับคุณadminครับ ให้โปรตีนสูงจากกุ้งและไข่ มีใยอาหารและวิตามินมากมายจากผัก ปรุงรสโดยเน้นความเปรี้ยวจากมะขามเปียก ลดปริมาณโซเดียมและน้ำตาล จึงเหมาะสำหรับผู้ป่วยเบาหวานและความดันสูง และปราศจากกลูเตนแน่นอนครับ', '2026-03-22 08:46:07'),
(199, 9, 'แกงเลียงกุ้งสด กับข้าวไรซ์เบอร์รี่', 630, 'แกงเลียงเป็นเมนูอาหารไทยโบราณที่อุดมไปด้วยสมุนไพรและผักหลากหลายชนิดครับคุณadmin ให้ใยอาหารสูง วิตามินและแร่ธาตุครบถ้วน ปราศจากไขมันจากกะทิ และเมื่อปรุงรสด้วยน้ำปลาลดโซเดียม จะช่วยควบคุมความดันโลหิตและระดับน้ำตาลได้ดีเยี่ยมครับ เมนูนี้ยังปราศจากกลูเตนอีกด้วยครับ', '2026-03-22 08:46:07'),
(200, 9, 'ข้าวต้มอกไก่ใส่เห็ดและขิง', 420, 'เมนูอาหารเช้าที่ย่อยง่าย ให้โปรตีนและคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง ช่วยควบคุมระดับน้ำตาลได้ดี เหมาะสำหรับคุณadminที่แพ้กลูเตนและมีเบาหวานครับ', '2026-03-22 08:47:07'),
(201, 9, 'ไก่ผัดขิงกับเห็ดและข้าวกล้อง', 650, 'เป็นเมนูมื้อกลางวันที่ให้โปรตีนสูงจากอกไก่ และใยอาหารจากเห็ดและข้าวกล้อง ขิงยังช่วยเรื่องระบบย่อยอาหารได้ดี ปรุงรสแบบลดโซเดียมและน้ำตาล เพื่อสุขภาพหัวใจและควบคุมเบาหวานของคุณadminครับ', '2026-03-22 08:47:07'),
(202, 9, 'ยำรวมมิตรทะเล', 400, 'เมนูนี้เน้นโปรตีนจากอาหารทะเลหลากหลายชนิด และผักสด ช่วยให้คุณadminได้รับสารอาหารครบถ้วนโดยไม่ต้องกังวลเรื่องกลูเตน และยังควบคุมโซเดียมและน้ำตาลได้ดี เหมาะสำหรับมื้อเย็นที่ต้องการความเบาครับ', '2026-03-22 08:47:07'),
(204, 9, 'ไข่เจียวอกไก่สับกับผักลวก', 380, 'สำหรับมื้อเช้าของคุณadmin เมนูนี้เป็นโปรตีนสูง เหมาะสำหรับมื้อเช้าที่ต้องการพลังงานและอิ่มนาน ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี และปลอดภัยสำหรับผู้แพ้กลูเตนครับ', '2026-03-22 08:53:19'),
(205, 9, 'อกไก่ย่างสมุนไพรกับผักลวกและข้าวกล้อง', 550, 'เมนูนี้เหมาะสำหรับมื้อกลางวันของคุณadmin เป็นเมนูที่ให้โปรตีนสูงจากอกไก่ และคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง มีใยอาหารจากผัก ช่วยควบคุมระดับน้ำตาลและความดันได้ดีเยี่ยม ปรุงรสน้อย เน้นความหอมจากสมุนไพรครับ', '2026-03-22 08:53:19'),
(206, 9, 'แกงป่าไก่', 420, 'สำหรับมื้อเย็นของคุณadmin เป็นเมนูรสชาติจัดจ้านที่ไม่มีกะทิ จึงดีต่อสุขภาพหัวใจและควบคุมน้ำหนักครับ อุดมด้วยสมุนไพรและผักหลากหลาย ช่วยลดน้ำตาลและความดันได้ดี แต่คุณadmin ต้องมั่นใจว่าใช้พริกแกงที่ปราศจากกลูเตนนะครับ', '2026-03-22 08:53:19'),
(207, 9, 'ฟักทองนึ่ง', 150, 'สำหรับมื้อว่างของคุณadmin ฟักทองนึ่งเป็นของว่างที่หวานอร่อยตามธรรมชาติ มีใยอาหารสูง ช่วยให้อิ่มนานและดีต่อระบบขับถ่ายครับ เหมาะสำหรับผู้ป่วยเบาหวานและทุกคนที่ต้องการควบคุมน้ำหนัก เพราะให้พลังงานไม่สูงและมีสารอาหารครบถ้วนครับ', '2026-03-22 08:53:19'),
(208, 15, 'ข้าวต้มอกไก่ใส่เห็ดและขิง', 350, 'เมนูมื้อเช้าที่ย่อยง่าย ให้พลังงานดีจากคาร์โบไฮเดรตเชิงซ้อนและโปรตีนจากอกไก่ ขิงมีส่วนช่วยลดการอักเสบและเสริมภูมิคุ้มกัน เหมาะสำหรับคุณBANCHAที่ต้องการดูแลสุขภาพและควบคุมน้ำหนักครับ', '2026-03-22 09:52:14'),
(209, 15, 'อกไก่ย่างสมุนไพรกับผักลวกและข้าวกล้อง', 500, 'เมนูมื้อกลางวันโปรตีนสูงจากอกไก่ไร้มัน และคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง พร้อมใยอาหารและวิตามินจากผัก ช่วยให้อิ่มนานและควบคุมแคลอรี่ได้ดี เป็นมิตรต่อการดูแลสะเก็ดเงินของคุณBANCHAครับ', '2026-03-22 09:52:14'),
(210, 15, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 450, 'เมนูมื้อเย็นปลานึ่งที่อุดมไปด้วยโอเมก้า 3 ซึ่งมีส่วนช่วยลดการอักเสบ เป็นประโยชน์ต่อผู้มีภาวะสะเก็ดเงิน และยังเป็นโปรตีนที่ดีเยี่ยมสำหรับควบคุมน้ำหนัก พร้อมข้าวไรซ์เบอร์รี่ที่มีสารต้านอนุมูลอิสระสูงครับ', '2026-03-22 09:52:14'),
(211, 15, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 230, 'ของว่างเพื่อสุขภาพที่ให้โปรไบโอติกจากโยเกิร์ต ช่วยปรับสมดุลลำไส้ กีวี่อุดมด้วยวิตามินซีและสารต้านอนุมูลอิสระ ส่วนธัญพืชให้ใยอาหารและไขมันดี ช่วยให้อิ่มท้องและเสริมสร้างสุขภาพโดยรวมของคุณBANCHAครับ', '2026-03-22 09:52:14'),
(213, 15, 'แกงส้มกุ้งชะอมไข่ กับข้าวกล้อง', 500, 'แกงส้มรสจัดจ้านที่อุดมไปด้วยผักและโปรตีนจากกุ้งและไข่ ช่วยเรื่องระบบขับถ่ายได้ดีครับ การทานคู่กับข้าวกล้องจะเพิ่มใยอาหารและควบคุมน้ำตาลได้ดี เหมาะสำหรับคุณBANCHAที่ต้องการลดน้ำหนักและมีสะเก็ดเงิน เพราะเน้นผักสดและโปรตีนคุณภาพครับ', '2026-03-22 09:56:51'),
(214, 15, 'ยำวุ้นเส้นหมูสับ', 380, 'ยำวุ้นเส้นเป็นเมนูที่เบาและสดชื่น เหมาะสำหรับมื้อเย็นของคุณBANCHA ที่ต้องการลดน้ำหนักครับ เมนูนี้มีโปรตีนจากหมูสับและใยอาหารจากวุ้นเส้นและผักหลากหลายชนิด การใช้สันคอหมูที่เลาะไขมันและน้ำปลาลดโซเดียมช่วยให้ดีต่อสุขภาพและลดปริมาณโซเดียม ซึ่งดีต่อผู้มีสะเก็ดเงินด้วยครับ', '2026-03-22 09:56:51'),
(215, 15, 'มะละกอสุก', 120, 'มะละกอสุกเป็นผลไม้ที่มีใยอาหารสูง วิตามินซีและสารต้านอนุมูลอิสระมากมาย ซึ่งมีส่วนช่วยบำรุงผิวพรรณและระบบภูมิคุ้มกัน เป็นของว่างที่สดชื่นและดีต่อสุขภาพของคุณBANCHA ทั้งเรื่องการลดน้ำหนักและช่วยเสริมวิตามินสำหรับผู้มีสะเก็ดเงินครับ', '2026-03-22 09:56:51'),
(216, 16, 'โจ๊กไก่ใส่ไข่ขาวและเห็ดหอม', 280, 'เมนูมื้อเช้าที่อิ่มสบายท้อง ย่อยง่าย ให้โปรตีนสูงจากอกไก่และไข่ขาว ช่วยให้อยู่ท้องตลอดช่วงเช้าโดยมีแคลอรี่ต่ำ เหมาะกับการเริ่มต้นวันใหม่เพื่อการลดน้ำหนักครับ', '2026-03-22 10:10:41'),
(217, 16, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 380, 'เมนูมื้อกลางวันที่ให้โปรตีนสูงจากปลาซึ่งเป็นไขมันดี มีวิตามินซีจากมะนาว และใยอาหารสูงจากข้าวไรซ์เบอร์รี่ ช่วยให้อิ่มนานและควบคุมระดับน้ำตาลในเลือดได้ดีเยี่ยมครับ', '2026-03-22 10:10:41'),
(218, 16, 'แกงเลียงกุ้งสด', 280, 'เมนูนี้ดีต่อสุขภาพมากๆ เลยครับคุณคนสวยดูดีเด้งดึ๋ง เป็นซุปผักรวมรสจัดจ้านที่ให้ใยอาหารสูงมาก วิตามินและแร่ธาตุครบครัน แถมแคลอรี่ต่ำ ทำให้อิ่มท้องโดยไม่รู้สึกผิด เป็นทางเลือกที่ดีเยี่ยมแทนซุปมะเขือครับ', '2026-03-22 10:10:41'),
(219, 16, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 180, 'มื้อว่างที่ช่วยเติมโปรไบโอติกที่ดีต่อระบบขับถ่ายของคุณคนสวยดูดีเด้งดึ๋ง มีวิตามินซีสูงจากกีวี่ และใยอาหารจากธัญพืช ช่วยให้อิ่มนาน ลดความอยากอาหาร และให้ความสดชื่นครับ', '2026-03-22 10:10:41'),
(220, 16, 'ข้าวต้มปลาอินทรี', 280, 'เมนูมื้อเช้าที่ย่อยง่าย ให้โปรตีนสูงจากปลาอินทรี และใยอาหารจากข้าวกล้อง ช่วยให้อิ่มนานและมีพลังงานตลอดเช้า เหมาะสำหรับคุณคนสวยดูดีเด้งดึ๋งที่ต้องการควบคุมน้ำหนัก', '2026-03-22 10:11:48'),
(221, 16, 'อกไก่ย่างสมุนไพรกับผักลวกและข้าวกล้อง', 380, 'เมนูโปรตีนสูง ไขมันต่ำ อุดมด้วยใยอาหารและวิตามินจากผักและข้าวกล้อง ช่วยให้อิ่มนาน ลดความอยากอาหารได้ดีเยี่ยม เหมาะสำหรับการลดน้ำหนักของคุณคนสวยดูดีเด้งดึ๋ง', '2026-03-22 10:11:48'),
(222, 16, 'แกงส้มกุ้งชะอมไข่ กับข้าวกล้อง', 430, 'แกงส้มเป็นเมนูไทยรสจัดจ้านที่แคลอรี่ต่ำเมื่อไม่ใส่กะทิ ให้โปรตีนจากกุ้งและไข่ชะอม และใยอาหารจากผักหลากหลาย ช่วยกระตุ้นการเผาผลาญได้อย่างดี เหมาะสำหรับมื้อเย็นของคุณคนสวยดูดีเด้งดึ๋ง', '2026-03-22 10:11:48'),
(223, 16, 'ฟักทองนึ่ง', 80, 'ฟักทองนึ่งเป็นของว่างที่ดีต่อสุขภาพ อุดมด้วยใยอาหารและเบต้าแคโรทีน ให้ความอิ่มกำลังดี มีรสหวานธรรมชาติ เหมาะสำหรับควบคุมน้ำหนักและบำรุงผิวพรรณครับคุณคนสวยดูดีเด้งดึ๋ง', '2026-03-22 10:11:48'),
(225, 16, 'ลาบหมูข้าวกล้อง', 380, 'ลาบหมูรสจัดจ้าน ให้โปรตีนสูงจากหมูสันในและมีใยอาหารจากข้าวกล้องและผักสดต่างๆ เพื่อสุขภาพที่ดีของคุณคนสวยดูดีเด้งดึ๋ง ควรเลือกหมูที่ไม่มีมันมากและลดปริมาณน้ำมันในการรวนนะครับ', '2026-03-22 10:12:32'),
(226, 16, 'มะละกอสุก', 90, 'ผลไม้ที่อุดมไปด้วยวิตามิน แร่ธาตุ และใยอาหาร ช่วยในการขับถ่ายและให้ความสดชื่น เหมาะเป็นของว่างเพื่อสุขภาพที่ดีของคุณคนสวยดูดีเด้งดึ๋งในยามบ่ายครับ', '2026-03-22 10:12:32'),
(227, 16, 'เมี่ยงปลาทู', 320, 'เมนูเพื่อสุขภาพที่ให้โปรตีนสูงจากปลาทู และใยอาหารจากผักสดมากมาย ช่วยให้อิ่มโดยไม่รู้สึกหนักท้อง คุณคนสวยดูดีเด้งดึ๋งจะได้รับประทานอาหารเย็นที่เบาสบายตัวและดีต่อสุขภาพอย่างแน่นอนครับ', '2026-03-22 10:12:32'),
(233, 14, 'โจ๊กไก่ใส่ไข่ขาวและเห็ดหอม', 390, 'เมนูย่อยง่าย เหมาะสำหรับมื้อเช้าที่ต้องการพลังงานและโปรตีนเพื่อเริ่มต้นวันใหม่ ให้พลังงานเพียงพอและช่วยให้อิ่มนานครับคุณwikrxm', '2026-03-22 11:30:45'),
(234, 14, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 520, 'เมนูไทยยอดนิยมที่ให้โปรตีนสูงจากอกไก่ และยังได้ใยอาหารจากข้าวกล้องและผัก ช่วยให้อิ่มท้องและรักษาน้ำหนักได้ดีครับคุณwikrxm', '2026-03-22 11:30:45'),
(235, 14, 'แกงเขียวหวานอกไก่', 480, 'แกงเขียวหวานรสกลมกล่อม ที่ปรับสูตรลดไขมันโดยใช้กะทิไขมันต่ำ ให้โปรตีนจากอกไก่และใยอาหารจากผักหลากชนิด เป็นมื้อเย็นที่อิ่มอร่อยและดีต่อสุขภาพครับ', '2026-03-22 11:30:45'),
(236, 14, 'ไข่เจียวอกไก่สับกับผักลวก', 230, 'เป็นมื้อว่างที่ให้โปรตีนสูงจากไข่และอกไก่ ช่วยเสริมสร้างกล้ามเนื้อ และยังได้วิตามินจากผักลวก ช่วยให้อิ่มสบายท้อง ไม่หนักจนเกินไป เหมาะสำหรับคุณwikrxmที่กำลังรักษาน้ำหนักนะครับ', '2026-03-22 11:30:45'),
(237, 9, 'โจ๊กไก่ใส่ไข่ขาวและเห็ดหอม', 280, 'โจ๊กอกไก่เน้นโปรตีนและไขมันต่ำ ย่อยง่าย เหมาะสำหรับมื้อเช้าของคุณadmin ที่มีโรคเบาหวานและความดันสูงครับ การใช้ข้าวหอมมะลิที่ต้มจนนิ่มช่วยให้ย่อยง่าย และการเสริมด้วยเห็ดหอมช่วยเพิ่มรสชาติและใยอาหารครับ', '2026-03-22 15:46:18'),
(238, 9, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 480, 'เมนูโปรดคลาสสิกของคนไทย ผัดกะเพราไก่สับอกเน้นเนื้ออกไก่ไร้มัน และเลือกใช้ข้าวกล้องเพื่อเพิ่มใยอาหาร ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี เหมาะสำหรับคุณadmin ที่ต้องการควบคุมน้ำหนักและโรคประจำตัวครับ ควรลดปริมาณเครื่องปรุงรสเพื่อควบคุมโซเดียมนะครับ', '2026-03-22 15:46:18'),
(239, 9, 'อกไก่นึ่งสมุนไพร', 180, 'เมนูว่างโปรตีนสูง ไขมันต่ำ ปรุงน้อย และไม่ใส่กลูเตนครับ การนึ่งช่วยรักษาสารอาหารและลดการใช้น้ำมัน สมุนไพรต่างๆ ยังช่วยเพิ่มกลิ่นหอมและมีประโยชน์ต่อสุขภาพ เหมาะสำหรับคุณadmin ที่ต้องการควบคุมระดับน้ำตาลและความดัน และรักษาน้ำหนักครับ', '2026-03-22 15:46:18'),
(240, 9, 'แกงเขียวหวานอกไก่', 400, 'แกงเขียวหวานอกไก่สูตรนี้ลดกะทิและเลือกใช้เนื้ออกไก่ เพื่อลดไขมันและเพิ่มโปรตีนครับ การลดปริมาณเครื่องปรุงรสและใช้สารให้ความหวานแทนน้ำตาล จะช่วยให้เมนูนี้เหมาะสำหรับคุณadmin ที่ต้องการควบคุมเบาหวานและความดันสูง โดยยังคงรสชาติอร่อยตามแบบฉบับอาหารไทยครับ', '2026-03-22 15:46:18'),
(241, 9, 'แกงเลียงกุ้งสด', 250, 'เมนูสมุนไพรไทย ช่วยขับลม อุดมด้วยวิตามินและแร่ธาตุ ดีต่อความดันโลหิตและเบาหวานครับ', '2026-03-22 16:07:02'),
(242, 9, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 450, 'สำหรับคุณadmin เมนูนี้ให้โปรตีนคุณภาพสูงจากปลา และคาร์โบไฮเดรตเชิงซ้อนจากข้าวไรซ์เบอร์รี่ ช่วยให้ระดับน้ำตาลคงที่ครับ', '2026-03-22 16:07:02'),
(243, 9, 'แกงจืดเต้าหู้หมูสับ (กับข้าวกล้อง)', 400, 'รสชาติกลมกล่อม ย่อยง่าย เหมาะสำหรับเป็นมื้อเย็นที่เบาสบายท้องของคุณadminครับ', '2026-03-22 16:07:02'),
(244, 9, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 250, 'มื้อว่างที่อุดมไปด้วยโปรไบโอติกและไฟเบอร์สูง ช่วยปรับสมดุลลำไส้ให้คุณadminครับ', '2026-03-22 16:07:02'),
(245, 9, 'ข้าวต้มปลาอินทรี', 350, 'เมนูนี้ดีต่อหัวใจด้วยโอเมก้า 3 จากปลาอินทรี ข้าวกล้องช่วยคุมระดับน้ำตาลในเลือดให้คงที่ครับ', '2026-03-22 16:08:05'),
(246, 9, 'แกงส้มกุ้งชะอมไข่', 420, 'แกงส้มมีสมุนไพรสูงและให้ไฟเบอร์จากชะอม ดีต่อระบบขับถ่ายและไม่ทำให้น้ำตาลพุ่งครับ', '2026-03-22 16:08:05'),
(247, 9, 'แจ่วปลาทู กับมะเขือเปราะลวก', 250, 'เมนูนี้ไขมันต่ำมาก อุดมไปด้วยโปรตีนจากปลาทูและวิตามินจากผักลวก ช่วยคุมความดันได้ดีครับคุณadmin', '2026-03-22 16:08:05'),
(248, 9, 'มะละกอสุก', 80, 'ผลไม้ไทยที่มีเอนไซม์ช่วยย่อยอาหารได้ดีเยี่ยม และมีสารต้านอนุมูลอิสระ เหมาะเป็นมื้อว่างเพื่อสุขภาพครับ', '2026-03-22 16:08:05'),
(249, 9, 'แกงจืดเต้าหู้หมูสับ', 280, 'เมนูนี้ดีต่อใจคุณadminมากครับ เพราะโซเดียมต่ำและย่อยง่าย เหมาะสำหรับผู้ป่วยเบาหวานและดันสูงมากครับ', '2026-03-22 16:08:36'),
(251, 9, 'ลาบหมูข้าวกล้อง', 420, 'ข้าวกล้องมีดัชนีน้ำตาลต่ำกว่าข้าวขาว ซึ่งดีมากสำหรับคุณadminในการควบคุมระดับน้ำตาลในเลือดครับ', '2026-03-22 16:08:36'),
(253, 9, 'ต้มข่าไก่ใส่มะพร้าวอ่อน', 450, 'เมนูนี้มีไขมันดีจากกะทิและโปรตีนสูงจากอกไก่ เหมาะสำหรับคุณadminที่ต้องการควบคุมความดันและระดับน้ำตาลครับ', '2026-03-22 16:08:54'),
(254, 9, 'ไก่ผัดขิงกับเห็ดและข้าวกล้อง', 550, 'ขิงช่วยเรื่องระบบขับถ่ายและลดการอักเสบในร่างกายได้ดีมากสำหรับคุณadminครับ', '2026-03-22 16:08:54'),
(255, 9, 'อกไก่นึ่งสมุนไพร', 350, 'เมนูไร้ไขมันและย่อยง่ายมาก ปลอดภัยต่อสุขภาพหัวใจและระดับน้ำตาลของคุณadminครับ', '2026-03-22 16:08:54'),
(256, 9, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 250, 'มื้อว่างที่อุดมไปด้วยโปรไบโอติกและกากใย ช่วยเรื่องระบบขับถ่ายได้ดีครับคุณadmin', '2026-03-22 16:08:54'),
(258, 9, 'แกงเขียวหวานอกไก่', 450, 'เมนูโปรตีนสูงที่ได้รับวิตามินจากผักในแกง สำหรับคุณadminแนะนำให้ทานคู่กับข้าวไรซ์เบอร์รี่ในปริมาณที่จำกัดครับ', '2026-03-22 16:09:56'),
(259, 9, 'โจ๊กไก่ใส่ไข่ขาวและเห็ดหอม', 350, 'เมนูที่ย่อยง่ายและดีต่อระบบขับถ่าย สำหรับคุณadminช่วยให้อิ่มท้องได้นานโดยไม่กระทบระดับน้ำตาลในเลือดครับ', '2026-03-22 16:09:56'),
(262, 9, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 570, 'ผัดกะเพราจานนี้ปรับสูตรให้ดีต่อสุขภาพคุณadmin ครับ ใช้ไก่ส่วนอกและข้าวกล้อง ช่วยควบคุมระดับน้ำตาลและให้ใยอาหารสูง ลดการใช้น้ำมันและปรุงรสด้วยเครื่องปรุงลดโซเดียมปราศจากกลูเตน ทำให้ปลอดภัยสำหรับผู้ป่วยเบาหวาน ความดัน และแพ้กลูเตนครับ', '2026-03-22 16:13:47'),
(269, 9, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 450, 'เมนูนี้ให้โปรตีนสูงและไขมันต่ำ มีใยอาหารจากข้าวไรซ์เบอร์รี่ ช่วยให้ระดับน้ำตาลคงที่ครับ', '2026-03-23 15:03:14'),
(270, 9, 'แกงเลียงกุ้งสด', 320, 'เมนูสมุนไพร ช่วยบำรุงสุขภาพและกระตุ้นการไหลเวียนเลือด เหมาะกับผู้ป่วยความดันครับ', '2026-03-23 15:03:14'),
(271, 9, 'ไข่ตุ๋นกุ้งสับ', 280, 'เป็นแหล่งโปรตีนคุณภาพดี ย่อยง่าย สบายท้อง ไม่กระทบระดับน้ำตาลในเลือดครับ', '2026-03-23 15:03:14'),
(274, 9, 'เมี่ยงปลาทู', 400, 'เมนูที่มีโอเมก้า 3 สูงจากปลาทู และอุดมไปด้วยวิตามินจากผักสด ปราศจากกลูเตนและไม่อ้วนครับคุณadmin', '2026-03-23 15:03:40'),
(277, 8, 'ต้มยำกุ้งน้ำข้น', 450, 'เมนูโปรตีนสูงจากกุ้งสด รสชาติจัดจ้านช่วยกระตุ้นการเผาผลาญได้ดีครับคุณdata', '2026-03-23 18:09:02'),
(278, 8, 'แกงเลียงกุ้งสด กับข้าวไรซ์เบอร์รี่', 550, 'เป็นเมนูที่อุดมไปด้วยวิตามินและใยอาหารจากผักหลากหลายชนิด ดีต่อระบบขับถ่ายของคุณdataครับ', '2026-03-23 18:09:02'),
(279, 8, 'ลาบหมูข้าวกล้อง', 600, 'เมนูนี้ให้พลังงานที่คงที่จากข้าวกล้องและโปรตีนจากหมูสับ เหมาะสำหรับเป็นมื้อหลักครับคุณdata', '2026-03-23 18:09:02'),
(280, 8, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 649, 'มื้อว่างที่ช่วยเติมพลังงานและโปรไบโอติกส์ ช่วยให้คุณdataอิ่มท้องและสดชื่นครับ', '2026-03-23 18:09:02'),
(281, 8, 'ส้มตำไทย', 150, 'เป็นเมนูที่มีกากใยสูง ช่วยเรื่องระบบขับถ่าย แคลอรี่ต่ำ เหมาะสำหรับเป็นมื้อกลางวันหรือมื้อเย็นที่ต้องการความเบาสบายท้องครับคุณdata', '2026-03-23 18:10:21'),
(282, 8, 'ปลากะพงทอดน้ำปลา', 550, 'คุณdataจะได้รับโปรตีนคุณภาพดีจากปลา ย่อยง่ายและไขมันต่ำ ดีต่อสุขภาพในระยะยาวครับ', '2026-03-23 18:10:21'),
(283, 8, 'แกงป่าไก่', 320, 'แกงป่าเป็นเมนูที่ปราศจากกะทิ ช่วยลดไขมันอิ่มตัว เหมาะมากสำหรับคุณdataที่ต้องการรักษาน้ำหนักครับ', '2026-03-23 18:10:21');
INSERT INTO `ai_saved_menus` (`id`, `user_id`, `menu_name`, `calories`, `description`, `created_at`) VALUES
(284, 8, 'ฟักทองนึ่ง', 120, 'เป็นมื้อว่างที่อุดมไปด้วยวิตามินเอและเบต้าแคโรทีน ให้ความหวานจากธรรมชาติช่วยให้อิ่มท้องได้ดีครับคุณdata', '2026-03-23 18:10:21'),
(285, 8, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 450, 'เมนูโปรตีนสูงจากอกไก่ ให้พลังงานดีและมีกากใยจากข้าวกล้อง ช่วยให้อิ่มนานและควบคุมระดับน้ำตาลในเลือดได้ดีครับ', '2026-03-23 18:11:35'),
(286, 8, 'แกงส้มกุ้งชะอมไข่ กับข้าวกล้อง', 550, 'เป็นเมนูที่มีสมุนไพรจากน้ำพริกแกงส้ม ช่วยในการย่อยและให้วิตามินสูง เหมาะสำหรับคุณdataที่ต้องการสารอาหารครบถ้วนครับ', '2026-03-23 18:11:35'),
(287, 8, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 480, 'เนื้อปลาเป็นแหล่งโปรตีนที่ย่อยง่ายและมีไขมันต่ำ ทานคู่กับข้าวไรซ์เบอร์รี่ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อน ดีต่อระบบขับถ่ายของคุณdataมากครับ', '2026-03-23 18:11:35'),
(288, 8, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 250, 'มื้อว่างที่อุดมไปด้วยโปรไบโอติกส์ที่ดีต่อลำไส้ของคุณdata พร้อมด้วยไขมันดีจากถั่วและวิตามินซีจากกีวี่ครับ', '2026-03-23 18:11:35'),
(293, 9, 'แกงจืดเต้าหู้หมูสับ', 350, 'เมนูนี้ดีต่อคุณadminมากครับ เพราะย่อยง่าย โซเดียมต่ำ และไม่มีกลูเตน ช่วยควบคุมระดับน้ำตาลในเลือดได้ดีครับ', '2026-03-25 04:46:44'),
(294, 9, 'ยำรวมมิตรทะเล', 280, 'เมนูโปรตีนสูงไขมันต่ำ เหมาะสำหรับคุณadminที่ต้องการควบคุมความดันและรักษาน้ำหนัก รสชาติจัดจ้านช่วยให้เจริญอาหารครับ', '2026-03-25 04:46:44'),
(295, 9, 'ฉู่ฉี่ปลาทู', 420, 'เป็นเมนูที่มีโอเมก้า 3 สูงจากปลาทู ช่วยบำรุงหัวใจสำหรับคุณadminครับ แนะนำทานคู่กับผักลวกนะครับ', '2026-03-25 04:46:44'),
(296, 9, 'มะละกอสุก', 120, 'เป็นผลไม้ที่มีกากใยสูง ช่วยเรื่องระบบขับถ่ายและดีต่อสุขภาพโดยรวมของคุณadminครับ', '2026-03-25 04:46:44');
INSERT INTO `chat_logs` (`id`, `user_id`, `sender`, `message`, `created_at`) VALUES
(1, 5, 'user', 'อยากกินไก่3มื้อเลย', '2026-02-12 15:13:08'),
(2, 5, 'ai', 'จัดไปครับ! กินไก่ 3 มื้อได้สบาย โปรตีนเน้นๆ แต่ด้วยเป้าหมาย **2,694 kcal** ต้องเน้นปริมาณและสารอาหารให้ครบนะครับ เชฟจัดเมนูมาให้แล้ว:\n\n1.  **มื้อเช้า:** ข้าวต้มอกไก่สับ ใส่ไข่ 2 ฟอง (เน้นพลังงานเริ่มต้นวัน)\n2.  **มื้อเที่ยง:** ข้าวราดกะเพราไก่ (ใช้เนื้อสะโพกบ้างก็ได้) + ไข่ดาว 2 ฟอง\n3.  **มื้อเย็น:** สเต็กอกไก่หรือน่องไก่ย่าง + มันบด + ผักย่างจุกๆ\n\n**ทริคจากเชฟ:** สลับกิน อก สะโพก น่อง บ้างจะได้ไม่เบื่อ และอย่าลืมเพิ่มข้าวหรือแป้งดีๆ ให้ถึงแคลอรี่ที่ตั้งไว้นะครับ! กินให้อร่อยครับ! ????✨', '2026-02-12 15:13:14'),
(3, 5, 'user', 'แนะนำเมนูอาหาร 2 เมนูสั้นๆ สำหรับคนเป็นโรค: 0 (ตอบเป็น Bullet points)', '2026-02-12 15:13:18'),
(4, 5, 'ai', 'สวัสดีครับเชฟจัดให้! ร่างกายแข็งแรงไม่มีโรคประจำตัวแบบนี้ ต้องการพลังงานเน้นๆ เพื่อให้ถึงเป้าหมาย 2,694 kcal จัดไป 2 เมนูครับ:\n\n*   **พาสต้าอกไก่ย่างซอสน้ำมันมะกอกและกระเทียม:** เน้นคาร์โบไฮเดรตจากเส้นพาสต้าและโปรตีนสูงจากอกไก่ ใช้น้ำมันมะกอกช่วยเพิ่มไขมันดีและพลังงานครับ\n*   **ข้าวกล้องกะเพราเนื้อสับไข่ดาว 2 ฟอง:** เมนูทำง่ายที่ให้สารอาหารครบถ้วน ทั้งโปรตีนจากเนื้อวัวและไข่ดาว ช่วยให้คุณอิ่มนานและได้พลังงานตามเป้าครับ\n\nทานให้อร่อยและรักษาสุขภาพนะครับ!', '2026-02-12 15:13:24'),
(5, 5, 'user', 'ขอคำคมสุขภาพสั้นๆ 1 ประโยค สำหรับคนเป็น: 0', '2026-02-12 15:13:24'),
(6, 5, 'ai', '\"กินดีวันนี้ เพื่อรักษาต้นทุนร่างกายที่แข็งแรงตลอดไปครับ!\"', '2026-02-12 15:13:27'),
(7, 5, 'user', 'แนะนำเมนูอาหาร 2 เมนูสั้นๆ สำหรับคนเป็นโรค: 0 (ตอบเป็น Bullet points)', '2026-02-12 15:15:49'),
(8, 5, 'ai', 'เชฟจัดให้ครับ! ร่างกายแข็งแรงและต้องการพลังงานสูงถึง 2,694 kcal แบบนี้ ต้องเมนูที่เน้นโปรตีนและสารอาหารครบถ้วนครับ\n\n*   **ข้าวอกไก่ย่างเทอริยากิ + ไข่ต้ม 2 ฟอง:** ได้โปรตีนเน้นๆ ช่วยซ่อมแซมกล้ามเนื้อ พลังงานดี อิ่มนานครับ\n*   **สเต็กปลาแซลมอน + มันบดผักโขม:** ได้ไขมันดี Omega-3 และคาร์โบไฮเดรตคุณภาพสูง เหมาะกับเป้าหมายแคลอรีของคุณครับ', '2026-02-12 15:15:55'),
(9, 5, 'user', 'ขอคำคมสุขภาพสั้นๆ 1 ประโยค สำหรับคนเป็น: 0', '2026-02-12 15:15:55'),
(10, 5, 'ai', '\"กินอาหารให้เป็นยา เพื่อไม่ต้องกินยาเป็นอาหารนะครับ!\"', '2026-02-12 15:15:59'),
(11, 5, 'user', 'อยากกินเนื้อกับไข่', '2026-02-12 15:25:00'),
(12, 5, 'user', 'อยากกินเนื้อกับไข่', '2026-02-12 15:26:21'),
(13, 5, 'user', 'อยากกินเนื้อกับไข่', '2026-02-12 15:26:24'),
(14, 5, 'user', 'อยากกินเนื้อกับไข่', '2026-02-12 15:29:21'),
(15, 5, 'ai', 'สวัสดีครับคุณผู้ใช้! เชฟยินดีมากครับที่ได้ดูแลมื้ออาหารของคุณในวันนี้ สำหรับความต้องการทานเนื้อและไข่ ซึ่งเป็นแหล่งโปรตีนและไขมันที่ดีเยี่ยม เมื่อพิจารณาจากเป้าหมายพลังงาน 2,694 kcal ต่อวันของคุณ เชฟขอแนะนำเมนูที่เน้นความอิ่มท้องและสารอาหารครบถ้วนดังนี้ครับ', '2026-02-12 15:29:30'),
(16, 5, 'user', 'อยากกินไก่กับไข่', '2026-02-12 17:21:54'),
(17, 5, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมยินดีมากที่คุณเลือกวัตถุดิบที่ดีอย่างไก่และไข่ครับ สำหรับเป้าหมาย 2,444 kcal ต่อวัน พร้อมทั้งดูแลเรื่องเบาหวานและความดันสูง ผมจะเน้นการปรุงที่ใช้ **โซเดียมต่ำ** และ **ไม่เติมน้ำตาล** โดยเน้นการนึ่ง ต้ม หรือผัดด้วยน้ำมันน้อยๆ เพื่อช่วยควบคุมระดับความดันและน้ำตาลในเลือดครับ แนะนำให้ทานร่วมกับข้าวไม่ขัดสีอย่างข้าวกล้องหรือไรซ์เบอร์รี่เพื่อให้ได้กากใยอาหารสูงครับ', '2026-02-12 17:22:04'),
(18, 6, 'user', 'อยากกินเมนูหมู', '2026-02-17 15:18:39'),
(19, 6, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมยินดีมากครับที่จะแนะนำเมนูหมูที่ทั้งอร่อยและได้รับสารอาหารที่ครบถ้วน การเลือกส่วนของเนื้อหมูอย่าง **\'สันใน\'** จะช่วยให้คุณได้รับโปรตีนคุณภาพสูงโดยที่มีไขมันต่ำครับ ผมได้คัดสรรเมนูที่เน้นการปรุงแบบดีต่อสุขภาพมาให้เลือกดังนี้ครับ', '2026-02-17 15:18:49'),
(20, 6, 'user', 'กินอะไรให้แฟนรัก', '2026-02-17 16:34:10'),
(21, 6, 'ai', 'การเลือกเมนูอาหารที่ช่วยเสริมสร้างบรรยากาศที่ดีและความรู้สึกผ่อนคลายจะช่วยให้ความสัมพันธ์ของคุณแน่นแฟ้นขึ้นครับ ผมขอแนะนำอาหารที่มีสารช่วยกระตุ้นสารความสุข (Endorphins) และบำรุงหัวใจ เพื่อให้คุณและคนที่คุณรักมีสุขภาพกายและใจที่ดีไปพร้อมกันครับ การลงมือทำด้วยตัวเองคือเครื่องปรุงที่พิเศษที่สุดที่จะทำให้แฟนรักแน่นอนครับ', '2026-02-17 16:34:27'),
(22, 6, 'user', 'เพิ่มโปรตีน', '2026-02-18 16:38:37'),
(23, 6, 'ai', 'สวัสดีครับ! ในฐานะเชฟและนักโภชนาการ ผมยินดีมากที่คุณต้องการเพิ่มสัดส่วนโปรตีนในมื้ออาหาร สำหรับเป้าหมายพลังงาน 2,007 แคลอรีต่อวัน การเน้นโปรตีนคุณภาพดีจะช่วยเสริมสร้างกล้ามเนื้อและทำให้คุณรู้สึกอิ่มท้องได้นานขึ้นครับ ผมได้จัดเตรียมเมนูที่มีโปรตีนสูงและสารอาหารครบถ้วนเพื่อให้เข้ากับเป้าหมายของคุณ ดังนี้ครับ', '2026-02-18 16:39:22'),
(24, 6, 'user', 'ผมมีวัตถุดิบ: ซี่โครงวัว, กระเทียม, กุ้งสดปอกเปลือก, ขึ้นฉ่ายและมะเขือเทศ, ซอสปรุงรสโซเดียมต่ำ 1 ช้อนโต๊ะ, ซอสหอยนางรมโซเดียมต่ำ 1 ช้อนโต๊ะ, ต้นหอมหั่นท่อน, ถั่วฝักยาวหั่นท่อน 100 กรัม, น้ำมะขามเปียก, น้ำมะขามเปียก 3 ช้อนโต๊ะ, น้ำเปล่าหรือน้ำซุป 150 มล., ผักชี, หมูสับไขมันต่ำ 100 กรัม, หอมแดงสไลด์ แนะนำเมนูที่ทำได้หน่อย', '2026-02-19 15:35:36'),
(25, 6, 'user', 'ผมมีวัตถุดิบ: ซี่โครงวัว, กระเทียมสับ, ข่า 3 แว่น, ซอสหอยนางรมลดโซเดียม, ข้าวกล้องหุงสุก 1 ถ้วย, ถั่วลันเตา, น้ำปลาลดโซเดียม, น้ำมะนาว 2 ช้อนโต๊ะ, ปลากะพงขาวหรือปลาทับทิม 250 กรัม, ไข่ไก่ แนะนำเมนูที่ทำได้หน่อย', '2026-02-19 15:37:24'),
(26, 6, 'ai', 'สวัสดีครับ! ยินดีที่ได้ดูแลเรื่องโภชนาการให้คุณนะครับ วัตถุดิบที่คุณมีถือว่ายอดเยี่ยมมากครับ มีทั้งโปรตีนคุณภาพสูงจากปลากะพงและไข่ไก่ รวมถึงซี่โครงวัวที่ให้รสชาติเข้มข้น และคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง สำหรับเป้าหมาย 1,757 kcal ของคุณ ผมขอแนะนำเมนูที่เน้นความสมดุลและลดโซเดียมดังนี้ครับ', '2026-02-19 15:37:38'),
(27, 6, 'user', 'เมนูไก่วันนี้', '2026-02-19 17:36:37'),
(28, 6, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมยินดีมากที่จะจัดเตรียมเมนูไก่ที่เหมาะสมกับเป้าหมาย 1757 kcal และสภาวะเบาหวานของคุณครับ สำหรับผู้ป่วยเบาหวาน เราจะเน้นโปรตีนไขมันต่ำอย่างอกไก่ และใช้การปรุงที่ไม่เติมน้ำตาล รวมถึงเน้นใยอาหารจากผักเพื่อช่วยชะลอการดูดซึมน้ำตาลเข้าสู่กระแสเลือดครับ', '2026-02-19 17:36:47'),
(29, 6, 'user', 'เมนูไก่วันนี้', '2026-02-21 02:23:59'),
(30, 6, 'ai', 'สวัสดีครับ! ยินดีที่ได้ดูแลโภชนาการให้คุณในวันนี้ครับ สำหรับเป้าหมายพลังงาน 1,757 แคลอรี ผมได้คัดสรรเมนูไก่ที่เน้นโปรตีนคุณภาพดีและสารอาหารครบถ้วนมาให้เลือก 3 สไตล์ เพื่อให้คุณอิ่มอร่อยและสุขภาพดีไปพร้อมกันครับ', '2026-02-21 02:24:09'),
(31, 6, 'user', 'ผมเป็นโรคอะไร ควรทานอาหารอะไรครับ', '2026-02-21 06:50:56'),
(32, 6, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ จากข้อมูลที่คุณระบุมา คุณมีภาวะ **เบาหวาน** และ **ความดันโลหิตสูง** ครับ \n\nแนวทางการรับประทานอาหารที่เหมาะสมสำหรับคุณคือ:\n1. **ควบคุมคาร์โบไฮเดรต:** เลือกทานแป้งไม่ขัดสี เช่น ข้าวกล้อง หรือธัญพืช เพื่อไม่ให้ระดับน้ำตาลในเลือดพุ่งสูงเร็วเกินไป\n2. **ลดโซเดียม:** หลีกเลี่ยงอาหารรสจัด อาหารแปรรูป และเครื่องปรุงรสที่มีเกลือสูง เพื่อช่วยควบคุมความดันโลหิต\n3. **เพิ่มใยอาหาร:** เน้นผักใบเขียวที่จะช่วยชะลอการดูดซึมน้ำตาล\n4. **โปรตีนคุณภาพดี:** เลือกเนื้อสัตว์ไม่ติดมัน ปลา หรือโปรตีนจากพืช\n\nด้วยเป้าหมาย 2507 kcal ต่อวัน คุณสามารถทานอาหารที่มีสารอาหารครบถ้วนในปริมาณที่พอเหมาะได้ดังนี้ครับ', '2026-02-21 06:51:14'),
(33, 7, 'user', 'เพิ่มโปรตีน', '2026-02-23 17:54:17'),
(34, 7, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมยินดีอย่างยิ่งที่จะแนะนำแนวทางการเพิ่มโปรตีนให้คุณครับ การเลือกโปรตีนคุณภาพสูงไม่เพียงช่วยเสริมสร้างกล้ามเนื้อและซ่อมแซมส่วนที่สึกหรอ แต่ยังช่วยให้คุณรู้สึกอิ่มนานขึ้นและรักษาระดับน้ำตาลในเลือดให้คงที่ด้วยครับ ผมขอแนะนำให้เลือกแหล่งโปรตีนหลากหลาย ทั้งจากเนื้อสัตว์ไม่ติดมัน ปลา และโปรตีนจากพืชครับ', '2026-02-23 17:54:33'),
(35, 7, 'user', 'สวัสดีครับ ผมคือใคร และคิดเมนูอาหารให้หน่อยครับ', '2026-02-24 02:42:00'),
(36, 7, 'user', 'หิวข้าว', '2026-02-24 02:42:24'),
(37, 7, 'user', 'เมนูไก่วันนี้', '2026-02-24 02:42:42'),
(38, 7, 'user', 'สวัสดีครับ ผมคือใคร และคิดเมนูอาหารให้หน่อยครับ', '2026-02-24 02:49:33'),
(39, 7, 'ai', 'สวัสดีครับคุณผู้ใช้ ในฐานะเชฟและนักโภชนาการ ผมยินดีอย่างยิ่งที่จะช่วยดูแลเรื่องอาหารให้คุณครับ\n\nสำหรับเป้าหมาย **2431 kcal** ต่อวัน พร้อมทั้งการดูแลโรค **เบาหวานและความดันโลหิตสูง** ผมได้จัดแผนการรับประทานอาหารที่เน้นคาร์โบไฮเดรตเชิงซ้อน (Complex Carbs) เพื่อช่วยควบคุมระดับน้ำตาลในเลือดให้คงที่ และใช้เมนูที่ลดโซเดียมเพื่อรักษาระดับความดันโลหิต โดยคัดเลือกจากวัตถุดิบคุณภาพดีและมีรสชาติอร่อยเพื่อให้คุณมีความสุขกับการทานอาหารสุขภาพครับ ดังนี้ครับ:|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":600,\"desc\":\"อกไก่หมักสมุนไพรไทยย่างจนนุ่ม ทานคู่กับควิโนอาที่มีใยอาหารสูงและดัชนีน้ำตาลต่ำ ช่วยให้อิ่มท้องและรักษาระดับน้ำตาลได้ดี\"},{\"name\":\"ปลานึ่งมะนาวสูตรโซเดียมต่ำ ทานคู่ข้าวกล้อง (มื้อกลางวัน)\",\"calories\":800,\"desc\":\"ปลากะพงสดนึ่งกับน้ำมะนาวพริกกระเทียมโดยลดการใช้เครื่องปรุงโซเดียมสูง เสิร์ฟพร้อมข้าวกล้องเพื่อเพิ่มกากใยและความชะลอการย่อยคาร์โบไฮเดรต\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":431,\"desc\":\"ทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดที่ให้ไขมันดี (HDL) มีประโยชน์ต่อหัวใจและหลอดเลือด พร้อมผักสลัดสดหลากสี\"},{\"name\":\"แกงเลียงกุ้งสดผักรวม (มื้อเย็น)\",\"calories\":600,\"desc\":\"แกงไทยสมุนไพรเข้มข้นที่เน้นผักพื้นบ้านและกุ้งสด สูตรลดเกลือแต่ใช้ความหอมจากพริกไทยและรากผักชี ช่วยขับลมและให้สารต้านอนุมูลอิสระสูง\"}]', '2026-02-24 02:49:56'),
(40, 7, 'user', 'ผมมีวัตถุดิบ: กะหล่ำปลีรองจาน, ขิงซอยละเอียด 1/2 ถ้วย, ข้าวกล้องหรือข้าวไรซ์เบอร์รี่ 1 ถ้วย, ซีอิ๊วขาวโซเดียมต่ำ 1 ช้อนโต๊ะ, น้ำมะขามเปียก 3 ช้อนโต๊ะ, ผักกาดขาว 200 กรัม, ปลากะพงขาว แนะนำเมนูที่ทำได้หน่อย', '2026-02-24 03:01:06'),
(41, 7, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมได้จัดสรรเมนูอาหารโดยเน้นวัตถุดิบที่คุณมี ได้แก่ **ปลากะพงขาว ขิงซอย และข้าวกล้อง** มาสร้างสรรค์เป็นเมนูหลักที่เหมาะสำหรับผู้ป่วย **เบาหวานและความดันสูง** ครับ\n\n**เหตุผลในการเลือกเมนู:**\n1. **ปลากะพงนึ่งซีอิ๊วขิงแก่:** ใช้ปลากะพงที่เป็นโปรตีนไขมันต่ำ ขิงช่วยระบบไหลเวียนโลหิต และใช้ซีอิ๊วขาวโซเดียมต่ำตามที่คุณมี เพื่อควบคุมความดันโลหิต\n2. **การควบคุมเบาหวาน:** เลือกใช้ข้าวกล้องและธัญพืชซึ่งมีค่าดัชนีน้ำตาลต่ำ (Low GI) ช่วยให้ระดับน้ำตาลในเลือดคงที่\n3. **การควบคุมความดัน:** เน้นเมนูต้มและนึ่ง ลดการปรุงรสจัดและใช้สมุนไพรในการเพิ่มรสชาติแทนเกลือ\n4. **การใช้ส่วนประกอบ:** ผมนำผักกาดขาวและน้ำมะขามเปียกของคุณมาปรุงเป็นแกงส้มในมื้อเย็น เพื่อให้ได้สารอาหารครบถ้วนตามเป้าหมาย 2,431 kcal ครับ|||MENUS|||[{\"name\":\"ข้าวผัดธัญพืชอกไก่ (มื้อเช้า)\",\"calories\":600,\"desc\":\"ข้าวกล้องผัดกับอกไก่ไม่ติดมัน ใส่ถั่วลันเตา แครอท และข้าวโพด ปรุงรสอ่อนๆ เพื่อพลังงานที่ยั่งยืนในตอนเช้า\"},{\"name\":\"ปลากะพงนึ่งซีอิ๊วขิงแก่และข้าวกล้อง (มื้อกลางวัน)\",\"calories\":700,\"desc\":\"ปลากะพงขาวสดนึ่งกับขิงซอยและซีอิ๊วโซเดียมต่ำ รองจานด้วยกะหล่ำปลีนึ่ง ทานคู่กับข้าวกล้อง 1 ถ้วย\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":431,\"desc\":\"ทูน่าในน้ำแร่ผสมกับอะโวคาโดหั่นเต๋า เพิ่มไขมันดีเพื่อบำรุงหัวใจและช่วยให้อิ่มนาน\"},{\"name\":\"แกงส้มผักรวมกุ้งสดและข้าวไรซ์เบอร์รี่ (มื้อเย็น)\",\"calories\":700,\"desc\":\"ใช้ผักกาดขาวและน้ำมะขามเปียกปรุงเป็นแกงส้มรสกลมกล่อม (ลดเค็ม) ใส่กุ้งสด ทานคู่กับข้าวไรซ์เบอร์รี่\"}]', '2026-02-24 03:01:24'),
(42, 7, 'user', 'คุณคือใครครับ', '2026-02-24 03:02:10'),
(43, 7, 'user', 'เมนูเพิ่มโปรตีน', '2026-02-24 03:02:54'),
(44, 7, 'ai', 'สวัสดีครับคุณผู้ใช้ ในฐานะเชฟและนักโภชนาการ ผมได้ออกแบบแผนการรับประทานอาหารไทยที่เน้น **โปรตีนสูง** เพื่อให้สอดคล้องกับเป้าหมาย 2,431 kcal ต่อวันของคุณครับ \n\nสำหรับการจัดเมนูครั้งนี้ ผมให้ความสำคัญกับข้อจำกัดด้านสุขภาพของคุณเป็นพิเศษ:\n1. **โรคเบาหวาน:** ผมเลือกใช้คาร์โบไฮเดรตเชิงซ้อนอย่างควิโนอาและข้าวกล้องที่มีค่าดัชนีน้ำตาลต่ำ เพื่อช่วยควบคุมระดับน้ำตาลให้คงที่ครับ\n2. **โรคความดันโลหิตสูง:** ทุกเมนูเน้นการปรุงแบบย่าง นึ่ง หรือผัดน้ำมันน้อย และใช้สมุนไพรในการชูรสชาติแทนการใช้เกลือหรือน้ำปลาปริมาณมาก เพื่อควบคุมระดับโซเดียมครับ\n3. **การเพิ่มโปรตีน:** ผมเลือกแหล่งโปรตีนคุณภาพเยี่ยมทั้งจากอกไก่ ไข่ และปลาแซลมอน เพื่อให้คุณได้รับสารอาหารครบถ้วนตามเป้าหมายครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":620,\"desc\":\"อกไก่หมักสมุนไพรไทยย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่ให้โปรตีนและไฟเบอร์สูง ช่วยให้อิ่มนานและดีต่อระดับน้ำตาล\"},{\"name\":\"ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)\",\"calories\":780,\"desc\":\"ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ชิ้นโต ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ ให้พลังงานและโปรตีนที่เหมาะสมกับช่วงกลางวัน\"},{\"name\":\"ไข่ตุ๋นทรงเครื่อง (มื้อว่าง)\",\"calories\":350,\"desc\":\"ไข่ตุ๋นเนื้อนุ่มใส่ไก่สับและเห็ดหอม เป็นอาหารว่างที่ให้โปรตีนสูงและย่อยง่าย\"},{\"name\":\"สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)\",\"calories\":681,\"desc\":\"ปลาแซลมอนย่างให้โปรตีนและไขมันดี (Omega-3) ซึ่งดีต่อหัวใจและความดัน เสิร์ฟพร้อมหน่อไม้ฝรั่งสดกรอบ\"}]', '2026-02-24 03:03:20'),
(45, 7, 'user', 'คุณคือใคร', '2026-02-24 03:16:43'),
(46, 7, 'ai', 'สวัสดีครับ ผมคือเชฟและนักโภชนาการอัจฉริยะส่วนตัวของคุณครับ ผมมีความเชี่ยวชาญในการออกแบบมื้ออาหารที่สมดุลทั้งในด้านรสชาติและคุณค่าทางโภชนาการ โดยเฉพาะการจัดเมนูอาหารสำหรับผู้ที่ต้องดูแลสุขภาพเป็นพิเศษ เช่น ผู้ที่มีภาวะเบาหวานและความดันโลหิตสูง \n\nผมพร้อมที่จะช่วยคุณวางแผนการรับประทานอาหารให้ได้พลังงานตามเป้าหมาย **2431 kcal ต่อวัน** โดยเน้นการเลือกวัตถุดิบที่มีดัชนีน้ำตาลต่ำ (Low GI) และควบคุมปริมาณโซเดียมอย่างเคร่งครัดเพื่อให้ปลอดภัยต่อโรคประจำตัวของคุณครับ หากคุณต้องการให้ผมจัดเมนูอาหารสำหรับวันนี้ หรือมีคำถามเรื่องโภชนาการ สามารถบอกผมได้เลยนะครับ', '2026-02-24 03:16:52'),
(47, 7, 'user', 'เมนูสุขภาพที่ฉันกินได้', '2026-02-24 03:40:26'),
(48, 7, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมได้จัดแผนการรับประทานอาหารที่ออกแบบมาเป็นพิเศษเพื่อให้พลังงานครบ 2,431 kcal ตามเป้าหมายของคุณครับ โดยเน้นการจัดการ **โรคเบาหวาน** ด้วยการเลือกใช้คาร์โบไฮเดรตเชิงซ้อน (GI ต่ำ) เช่น ข้าวกล้องและควิโนอา เพื่อควบคุมระดับน้ำตาลในเลือด และจัดการ **โรคความดันโลหิตสูง** ด้วยการเลือกเมนูโซเดียมต่ำ อุดมไปด้วยโพแทสเซียมและไขมันดี (Omega-3) จากปลาเพื่อช่วยบำรุงระบบหลอดเลือดและหัวใจครับ ทุกเมนูปรุงด้วยวิธีการย่าง นึ่ง หรือผัดน้ำมันน้อย เพื่อความปลอดภัยต่อสุขภาพ 100% ครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":600,\"desc\":\"อกไก่หมักสมุนไพรย่างจนนุ่ม ทานคู่กับควิโนอาที่อุดมไปด้วยโปรตีนและใยอาหาร ช่วยให้อิ่มนานและรักษาระดับน้ำตาลให้คงที่\"},{\"name\":\"ข้าวผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)\",\"calories\":750,\"desc\":\"ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ ให้พลังงานสูงจากคาร์โบไฮเดรตเชิงซ้อนและใยอาหาร\"},{\"name\":\"Quinoa Power Salad (มื้อว่าง)\",\"calories\":400,\"desc\":\"สลัดควิโนอาที่อัดแน่นไปด้วยผักใบเขียวและถั่ว ช่วยเพิ่มพลังงานระหว่างวันและให้แมกนีเซียมสูงซึ่งดีต่อความดันโลหิต\"},{\"name\":\"สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)\",\"calories\":681,\"desc\":\"แซลมอนย่างเกลือพริกไทยเพียงเล็กน้อยเพื่อให้ได้ไขมันดีโอเมก้า-3 เสิร์ฟพร้อมหน่อไม้ฝรั่งย่าง ช่วยเสริมสร้างระบบหัวใจและหลอดเลือด\"}]', '2026-02-24 03:40:42'),
(49, 7, 'user', 'เมนูสุขภาพที่ฉันกินได้', '2026-02-25 03:50:32'),
(50, 7, 'ai', 'สวัสดีครับคุณผู้ใช้ ในฐานะเชฟและนักโภชนาการ ผมได้ออกแบบเมนูอาหารที่เหมาะสมกับเป้าหมาย **2,431 แคลอรี่ต่อวัน** โดยคำนึงถึงโรคประจำตัวเป็นหลักครับ สำหรับ **โรคเบาหวาน** ผมเลือกใช้คาร์โบไฮเดรตเชิงซ้อนที่มีค่าดัชนีน้ำตาลต่ำ (Low GI) เช่น ควิโนอาและข้าวกล้อง เพื่อควบคุมระดับน้ำตาล และสำหรับ **ความดันโลหิตสูง** ผมเน้นการปรุงรสด้วยสมุนไพรไทยแทนการใช้โซเดียม และเลือกแหล่งโปรตีนที่มีโอเมก้า 3 สูงเพื่อบำรุงหลอดเลือดครับ ทุกเมนูที่เลือกมามีความปลอดภัยและช่วยส่งเสริมสุขภาพของคุณอย่างเต็มที่ครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":550,\"desc\":\"อกไก่หมักสมุนไพรพื้นบ้านย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่ให้ไฟเบอร์สูง ช่วยชะลอการดูดซึมน้ำตาล\"},{\"name\":\"ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)\",\"calories\":700,\"desc\":\"ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่สับ ปรุงรสด้วยซอสโซเดียมต่ำ ให้พลังงานที่ยาวนานและสารอาหารครบถ้วน\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":481,\"desc\":\"ทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดสด ให้ไขมันดี (HDL) ที่ช่วยลดความดันและบำรุงหัวใจ\"},{\"name\":\"สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)\",\"calories\":700,\"desc\":\"แซลมอนย่างสุกกำลังดี อุดมด้วยโอเมก้า 3 เสิร์ฟพร้อมหน่อไม้ฝรั่งและข้าวกล้อง เพื่อมื้อเย็นที่เบาสบายแต่สารอาหารสูง\"}]', '2026-02-25 03:50:54'),
(51, 7, 'user', 'เมนูสุขภาพที่ฉันกินได้', '2026-02-25 03:50:59'),
(52, 7, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมได้คัดสรรเมนูจากฐานข้อมูลที่เหมาะสมที่สุดสำหรับเป้าหมายพลังงาน 2,431 kcal ของคุณ โดยเน้นการจัดการโรคเบาหวานและความดันโลหิตสูงเป็นสำคัญครับ\n\nสำหรับ **โรคเบาหวาน**: ผมเลือกใช้คาร์โบไฮเดรตเชิงซ้อนที่มีดัชนีน้ำตาลต่ำ (Low GI) เช่น ควิโนอา ข้าวกล้อง และธัญพืช เพื่อให้ระดับน้ำตาลในเลือดคงที่\nสำหรับ **โรคความดันโลหิตสูง**: เมนูที่เลือกเน้นการปรุงแบบโซเดียมต่ำ หลีกเลี่ยงของทอด และใช้ไขมันดีจากปลาและอะโวคาโดเพื่อช่วยบำรุงระบบหลอดเลือดครับ\n\nเมนูเหล่านี้ปลอดภัยและครบถ้วนตามความต้องการของคุณแน่นอนครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":600,\"desc\":\"อกไก่ลอกหนังย่างสมุนไพร เสิร์ฟพร้อมควิโนอาที่ให้กากใยสูงและโปรตีนแน่น ช่วยคุมน้ำตาลได้ดีตั้งแต่เช้า\"},{\"name\":\"ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)\",\"calories\":850,\"desc\":\"ข้าวกล้องผัดกับถั่วและธัญพืช 7 สี พร้อมอกไก่สับ ปรุงรสอ่อนๆ เน้นสารอาหารครบถ้วนเพื่อพลังงานในช่วงบ่าย\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":381,\"desc\":\"ทูน่าในน้ำแร่ผสมอะโวคาโดสด ให้ไขมันดีช่วยลดคอเลสเตอรอลและโซเดียมต่ำ ดีต่อความดันโลหิต\"},{\"name\":\"ปลานึ่งมะนาวสูตรโซเดียมต่ำ (มื้อเย็น)\",\"calories\":600,\"desc\":\"เนื้อปลาขาวนึ่งสุกปรุงด้วยน้ำมะนาวแท้ พริก และกระเทียม ลดการใช้เครื่องปรุงรสเค็ม เพื่อสุขภาพหัวใจและหลอดเลือด\"}]', '2026-02-25 03:51:28'),
(53, 7, 'user', 'เมนูไก่วันนี้', '2026-02-25 03:52:31'),
(54, 7, 'ai', 'สวัสดีครับคุณผู้ดูแลสุขภาพ ในฐานะเชฟและนักโภชนาการ ผมได้คัดสรรเมนูที่มี **\'อกไก่\'** เป็นวัตถุดิบหลักจากฐานข้อมูล โดยคำนึงถึงเป้าหมายพลังงาน 2,431 kcal และข้อจำกัดด้านสุขภาพของคุณเป็นสำคัญครับ\n\n**สำหรับการดูแลเบาหวานและความดันสูง:**\n1. **ดัชนีน้ำตาลต่ำ:** เลือกใช้ควิโนอาและข้าวกล้องแทนข้าวขาว เพื่อช่วยควบคุมระดับน้ำตาลในเลือดให้คงที่\n2. **โซเดียมต่ำ:** เมนูที่เลือกเน้นการใช้สมุนไพรไทย (ขิง, ข่า, ตะไคร้, ใบมะกรูด) เพื่อเพิ่มรสชาติแทนการใช้เกลือหรือน้ำปลาในปริมาณมาก ซึ่งดีต่อระดับความดันโลหิตครับ\n3. **ไขมันต่ำ:** ใช้อกไก่ไม่ติดหนังและปรุงด้วยการย่าง นึ่ง หรือต้ม เพื่อลดไขมันอิ่มตัวครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":600,\"desc\":\"อกไก่หมักสมุนไพรไทยย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่มีใยอาหารสูง ช่วยให้อิ่มนานและคุมน้ำตาลได้ดี\"},{\"name\":\"อกไก่ย่างสมุนไพรกับข้าวกล้อง (มื้อกลางวัน)\",\"calories\":800,\"desc\":\"อกไก่ย่างหอมสมุนไพร เสิร์ฟพร้อมข้าวกล้องออร์แกนิก เพิ่มปริมาณข้าวและผักเคียงเพื่อให้ได้พลังงานตามเป้าหมาย\"},{\"name\":\"ก๋วยเตี๋ยวลุยสวนอกไก่ (มื้อว่าง)\",\"calories\":431,\"desc\":\"เมนูทานเล่นที่เน้นผักสดและอกไก่สับ ห่อด้วยแป้งก๋วยเตี๋ยวแผ่นบาง ทานคู่กับน้ำจิ้มสมุนไพรรสจัดจ้านสูตรลดโซเดียม\"},{\"name\":\"ต้มยำอกไก่น้ำใส (มื้อเย็น)\",\"calories\":600,\"desc\":\"ต้มยำรสกลมกล่อมด้วยสมุนไพรสด ใช้อกไก่ล้วน ไม่ใส่นมข้นจืดหรือน้ำพริกเผา เพื่อลดแคลอรี่และไขมันที่ไม่จำเป็น\"}]', '2026-02-25 03:52:46'),
(55, 7, 'user', 'หิวข้าว ขอเมนูเนื้อวันนี้', '2026-02-25 03:53:42'),
(56, 7, 'ai', 'สวัสดีครับ ในฐานะเชฟและนักโภชนาการ ผมได้จัดเตรียมแผนการทานอาหารที่เน้นเมนูเนื้อสัตว์ตามที่คุณต้องการ โดยคำนึงถึงเป้าหมายพลังงาน 2,431 kcal และความปลอดภัยต่อโรคประจำตัวอย่างเบาหวานและความดันสูงครับ\n\n**หัวใจสำคัญของเมนูชุดนี้:**\n1. **ควบคุมระดับน้ำตาล:** ใช้คาร์โบไฮเดรตเชิงซ้อน (ควิโนอา/ข้าวกล้อง) ที่มีใยอาหารสูง ช่วยชะลอการดูดซึมน้ำตาลเข้าสู่กระแสเลือด\n2. **ดูแลความดันโลหิต:** ปรุงรสด้วยสูตรโซเดียมต่ำ เน้นรสชาติจากสมุนไพรสดและขิง\n3. **พลังงานเหมาะสม:** มื้ออาหารมีความหนาแน่นของสารอาหารสูงเพื่อให้เพียงพอต่อความต้องการพลังงานรายวันของคุณครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":600,\"desc\":\"อกไก่ส่วนไม่ติดหนังหมักสมุนไพรไทยย่างจนนุ่ม เสิร์ฟคู่กับควิโนอาที่มีโปรตีนและใยอาหารสูง\"},{\"name\":\"ผัดกะเพราเนื้อสับไข่ดาวน้ำ (มื้อกลางวัน)\",\"calories\":750,\"desc\":\"เนื้อวัวส่วนไม่ติดมันผัดกับใบกะเพราหอมๆ ปรุงรสด้วยซีอิ๊วโซเดียมต่ำ เสิร์ฟพร้อมข้าวกล้องและไข่ดาวที่ใช้น้ำแทนน้ำมัน\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":431,\"desc\":\"เนื้อทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดสุก ให้ไขมันดีที่ช่วยบำรุงหัวใจและอิ่มท้องนาน\"},{\"name\":\"ปลากะพงนึ่งซีอิ๊วขิงแก่ (มื้อเย็น)\",\"calories\":650,\"desc\":\"ปลากะพงขาวสดนึ่งกับขิงแก่และขึ้นฉ่าย ช่วยลดความดันโลหิต ปรุงด้วยซีอิ๊วสูตรลดโซเดียม รับประทานคู่กับข้าวกล้อง\"}]', '2026-02-25 03:53:55'),
(57, 7, 'user', 'เพิ่มโปรตีน', '2026-02-25 03:55:09'),
(58, 7, 'ai', 'สวัสดีครับ! ในฐานะเชฟและนักโภชนาการ ผมได้จัดแผนการรับประทานอาหารที่เน้น **\'เพิ่มโปรตีน\'** ให้สอดคล้องกับเป้าหมาย 2,431 kcal ของคุณ โดยคำนึงถึงโรคเบาหวานและความดันโลหิตสูงเป็นสำคัญครับ\n\n**จุดเด่นของเมนูที่เลือกให้:**\n1. **การควบคุมน้ำตาล (สำหรับเบาหวาน):** เลือกใช้ \'ควิโนอา\' และ \'ข้าวกล้อง\' ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อนที่มีดัชนีน้ำตาลต่ำ ช่วยให้ระดับน้ำตาลในเลือดคงที่ และเพิ่มกากใยอาหาร\n2. **การควบคุมโซเดียม (สำหรับความดันสูง):** เน้นเมนูที่ใช้การย่างและนึ่ง ปรุงรสด้วยสมุนไพรไทย พริกไทย และมะนาว เพื่อลดการใช้เกลือและซอสปรุงรสที่มีโซเดียมสูง\n3. **เน้นโปรตีนลีน:** ใช้โปรตีนคุณภาพสูงจากอกไก่ เนื้อปลา และธัญพืช เพื่อช่วยซ่อมแซมส่วนที่สึกหรอและเสริมสร้างกล้ามเนื้อ โดยไม่มีไขมันอิ่มตัวส่วนเกินครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา (มื้อเช้า)\",\"calories\":550,\"desc\":\"อกไก่ลีนย่างด้วยสมุนไพรสด หอมนุ่ม เสิร์ฟคู่กับควิโนอาที่ให้โปรตีนสูงและดีต่อระดับน้ำตาล\"},{\"name\":\"ข้าวกล้องผัดธัญพืชรวมและอกไก่ (มื้อกลางวัน)\",\"calories\":750,\"desc\":\"ข้าวกล้องผัดกับธัญพืชหลากชนิดและอกไก่ ให้พลังงานที่ยาวนานและโปรตีนที่ครบถ้วน\"},{\"name\":\"สลัดทูน่าอะโวคาโด (มื้อว่าง)\",\"calories\":431,\"desc\":\"เนื้อทูน่าคุณภาพดีผสมกับอะโวคาโด ให้โปรตีนและไขมันดี (HDL) ช่วยบำรุงหัวใจและหลอดเลือด\"},{\"name\":\"สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง (มื้อเย็น)\",\"calories\":700,\"desc\":\"ปลาแซลมอนย่างที่อุดมด้วยโอเมก้า-3 และโปรตีน เสิร์ฟพร้อมหน่อไม้ฝรั่งกรอบ ปรุงรสอ่อนๆ เพื่อคุมความดัน\"}]', '2026-02-25 03:55:27'),
(59, 7, 'user', 'เพิ่มโปรตีน', '2026-02-25 04:06:44'),
(60, 7, 'ai', 'สวัสดีครับคุณผู้ใช้ ในฐานะเชฟและนักโภชนาการ ผมได้ออกแบบเมนูอาหารไทยที่เน้นการ **\'เพิ่มโปรตีน\'** ให้สอดคล้องกับเป้าหมาย 2,431 kcal ของคุณ โดยคำนึงถึงความปลอดภัยต่อโรคประจำตัวเป็นสำคัญครับ\n\n### หลักการจัดเมนูครั้งนี้:\n1. **ควบคุมระดับน้ำตาล (เบาหวาน):** เลือกใช้คาร์โบไฮเดรตเชิงซ้อนที่มีกากใยสูงและดัชนีน้ำตาลต่ำ\n2. **ควบคุมความดันโลหิต:** เน้นการปรุงรสด้วยสมุนไพรและซอสลดโซเดียม หลีกเลี่ยงอาหารแปรรูป\n3. **เพิ่มโปรตีน:** เลือกแหล่งโปรตีนคุณภาพดีจากหมูเนื้อแดง กุ้ง ปลา และโปรตีนจากพืชเพื่อให้ได้กรดอะมิโนครบถ้วนและช่วยซ่อมแซมส่วนที่สึกหรอครับ\n\nเมนูเหล่านี้เป็นเมนูใหม่ทั้งหมด ไม่ซ้ำกับที่คุณเพิ่งรับประทานไปแน่นอนครับ|||MENUS|||[{\"name\":\"ข้าวต้มข้าวกล้องหมูสับทรงเครื่องและไข่ลวก (มื้อเช้า)\",\"calories\":580,\"desc\":\"ข้าวกล้องหอมมะลิต้มสุกกับหมูสับเนื้อแดง (ไม่ติดมัน) ปรุงรสด้วยขิงแก่ซอยและเห็ดหอมสด เสริมโปรตีนด้วยไข่ลวก 2 ฟอง\"},{\"name\":\"กุ้งสดผัดบล็อกโคลี่และเห็ดแชมปิญองข้าวไรซ์เบอร์รี่ (มื้อกลางวัน)\",\"calories\":650,\"desc\":\"กุ้งแชบ๊วยตัวโตผัดกับบล็อกโคลี่และเห็ดโดยใช้น้ำมันรำข้าวเล็กน้อย ปรุงรสด้วยซีอิ๊วขาวลดโซเดียม เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่\"},{\"name\":\"เต้าหู้ขาวนึ่งจิ้มซีอิ๊วและถั่วแระญี่ปุ่น (มื้อว่าง)\",\"calories\":550,\"desc\":\"เต้าหู้ขาวถั่วเหลืองแท้นึ่งอุ่นๆ ทานคู่กับถั่วแระญี่ปุ่นต้ม เป็นของว่างโปรตีนสูงจากพืชและมีกากใยช่วยชะลอการดูดซึมน้ำตาล\"},{\"name\":\"เมี่ยงปลาทูย่างและขนมจีนข้าวกล้อง (มื้อเย็น)\",\"calories\":651,\"desc\":\"ปลาทูย่าง (ไม่ทอด) ทานคู่กับขนมจีนข้าวกล้องและผักสดหลากหลายชนิด ราดน้ำจิ้มถั่วตัดสูตรหวานน้อยและลดเกลือ ให้โปรตีนและโอเมก้า 3 สูง\"}]', '2026-02-25 04:07:18'),
(61, 7, 'user', 'เมนูไก่วันนี้', '2026-02-25 05:33:11'),
(62, 7, 'ai', 'สวัสดีครับ ผมได้จัดเตรียมเมนูแนะนำที่มี **\'ไก่\'** เป็นวัตถุดิบหลักตามที่คุณต้องการ โดยคำนวณสารอาหารให้ครบถ้วนตามเป้าหมาย 2181 kcal ต่อวันครับ\n\nสำหรับผู้ที่มีสภาวะ **เบาหวานและความดันโลหิตสูง** ผมได้เลือกใช้คาร์โบไฮเดรตเชิงซ้อน (ข้าวกล้องและข้าวไรซ์เบอร์รี่) ที่มีค่าดัชนีน้ำตาลต่ำเพื่อช่วยควบคุมระดับน้ำตาลในเลือด และเน้นการปรุงแบบนึ่ง ต้ม หรือผัดด้วยน้ำมันน้อย รวมถึงการใช้สมุนไพรไทย เช่น ขิง มะระ และมะนาว เพื่อช่วยชูรสชาติแทนการใช้โซเดียมในปริมาณสูง ซึ่งจะส่งผลดีต่อความดันโลหิตของคุณครับ ทุกเมนูที่เลือกมามั่นใจได้ว่าไม่ซ้ำกับประวัติการทานล่าสุดแน่นอนครับ|||MENUS|||[{\"name\":\"ข้าวต้มข้าวกล้องอกไก่สับและไข่ลวก (มื้อเช้า)\",\"calories\":500,\"desc\":\"ข้าวกล้องต้มจนนุ่ม อกไก่สับปรุงรสด้วยพริกไทย ใส่ขิงซอยและต้นหอมเพื่อช่วยระบบไหลเวียนโลหิต พร้อมไข่ลวก 1 ฟอง\"},{\"name\":\"อกไก่นึ่งมะนาวทานคู่กับข้าวกล้องและผัดผักบุ้ง (มื้อกลางวัน)\",\"calories\":700,\"desc\":\"อกไก่นึ่งราดซอสมะนาวพริกสดรสชาติจัดจ้านแต่โซเดียมต่ำ ทานคู่กับข้าวกล้องและผัดผักบุ้งไฟแดงที่ใช้น้ำมันมะกอกเล็กน้อย\"},{\"name\":\"ฝรั่งสดและเม็ดมะม่วงหิมพานต์อบ (มื้อว่าง)\",\"calories\":300,\"desc\":\"ฝรั่งแป้นสีทองซึ่งเป็นผลไม้น้ำตาลต่ำวิตามินซีสูง ทานคู่กับเม็ดมะม่วงหิมพานต์อบธรรมชาติไม่เติมเกลือเพื่อรับไขมันดี\"},{\"name\":\"ต้มจืดมะระยัดไส้ไก่สับและข้าวไรซ์เบอร์รี่ (มื้อเย็น)\",\"calories\":681,\"desc\":\"มะระที่มีสรรพคุณช่วยลดระดับน้ำตาลในเลือด ยัดไส้ด้วยอกไก่สับในน้ำซุปสมุนไพร เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่ที่มีไฟเบอร์สูง\"}]', '2026-02-25 05:33:37'),
(63, 7, 'user', 'เมนูไก่วันนี้', '2026-03-03 08:31:30'),
(64, 7, 'ai', 'สวัสดีครับคุณผู้ใช้ ในฐานะเชฟและนักโภชนาการ ผมได้ออกแบบเมนูอาหารไทยที่เน้น **\'อกไก่\'** ตามที่คุณต้องการ โดยคำนวณพลังงานให้ครบตามเป้าหมาย 2181 kcal/วัน\n\nสำหรับผู้ที่มีภาวะ **เบาหวานและคุณความดันโลหิตสูง** ผมได้เลือกใช้คาร์โบไฮเดรตเชิงซ้อนที่มีค่าดัชนีน้ำตาลต่ำ (Low GI) อย่างข้าวกล้องและขนมปังโฮลวีต เพื่อช่วยควบคุมระดับน้ำตาลในเลือด และเน้นการปรุงที่ใช้โซเดียมต่ำ โดยใช้สมุนไพรไทย เช่น ขิง และเครื่องแกงป่า เพื่อช่วยเพิ่มรสชาติแทนการใช้เกลือหรือน้ำปลาปริมาณมาก ซึ่งดีต่อระดับความดันโลหิตครับ ทุกเมนูผ่านการตรวจสอบแล้วว่าไม่ซ้ำกับรายการที่คุณเพิ่งทานไปครับ|||MENUS|||[{\"name\":\"แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม\",\"calories\":500,\"desc\":\"ใช้อกไก่ลอกหนังย่าง ขนมปังโฮลวีต 2 แผ่น และไข่ต้ม เพิ่มผักกาดคอสและมะเขือเทศ ให้ใยอาหารสูงและอิ่มนาน\"},{\"name\":\"ข้าวไรซ์เบอร์รี่อกไก่ผัดขิงและเห็ดหูหนู\",\"calories\":650,\"desc\":\"อกไก่ผัดกับขิงสดและเห็ดหูหนู ช่วยระบบไหลเวียนโลหิต ปรุงด้วยซีอิ๊วขาวโซเดียมต่ำ เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่\"},{\"name\":\"สลัดโรลอกไก่ฉีกน้ำจิ้มซีฟู้ดโยเกิร์ต\",\"calories\":331,\"desc\":\"เมนูว่างที่ใช้แป้งสลัดโรลบางๆ ห่อผักสดและอกไก่ฉีก น้ำจิ้มใช้โยเกิร์ตรสธรรมชาติผสมมะนาวและพริกสดแทนน้ำสลัดไขมันสูง\"},{\"name\":\"แกงป่าอกไก่ใส่ผักรวมและข้าวกล้อง\",\"calories\":700,\"desc\":\"แกงป่ารสจัดจ้านจากสมุนไพร ไม่ใส่กะทิ (ลดไขมันอิ่มตัว) ใส่ผักเปาะ ถั่วฝักยาว และกระชาย เสิร์ฟคู่กับข้าวกล้องร้อนๆ\"}]', '2026-03-03 08:31:46'),
