(111, 9, 'ai', 'สวัสดีครับ! ในฐานะเชฟและนักโภชนาการ ผมเข้าใจดีถึงเป้าหมายการเพิ่มน้ำหนักอย่างเร่งด่วนของคุณลูกค้า พร้อมทั้งข้อจำกัดด้านสุขภาพจากโรคเบาหวานและความดันสูง เมนูที่คัดสรรมาในวันนี้จึงเน้นโปรตีนสูง คาร์โบไฮเดรตเชิงซ้อน และไขมันดี เพื่อให้ได้พลังงานเพียงพอสำหรับการเพิ่มน้ำหนัก แต่ยังคงควบคุมปริมาณโซเดียมและน้ำตาลอย่างเคร่งครัด เพื่อความปลอดภัยและสุขภาพที่ดีของคุณลูกค้าครับ เมนูทั้งหมดเป็นสูตรที่ปรับให้เหมาะสม ไม่ซ้ำกับที่เพิ่งรับประทานไปแน่นอน และขอแนะนำให้รับประทานในปริมาณที่เหมาะสมและเพียงพอต่อเป้าหมายแคลอรี่ 3215 kcal/วัน โดยสามารถเพิ่มขนาดของแต่ละมื้อหรือเพิ่มไขมันดี เช่น น้ำมันมะกอก อะโวคาโด หรือถั่วต่างๆ เข้าไปในมื้ออาหารได้อย่างอิสระครับ|||MENUS|||[{\"name\":\"ก๋วยเตี๋ยวลุยสวนอกไก่\",\"calories\":750,\"desc\":\"ก๋วยเตี๋ยวลุยสวนแป้งโฮลวีท สอดไส้อกไก่ฉีก ผักสด และเห็ดต่างๆ เน้นโปรตีนและใยอาหารสูง ราดด้วยน้ำจิ้มซีฟู้ดสูตรลดโซเดียมและใช้น้ำตาลหญ้าหวาน เพื่อให้พลังงานและสารอาหารที่ครบถ้วนสำหรับมื้อเช้า\"},{\"name\":\"สปาเกตตีโฮลวีตผัดพริกแห้งและอกไก่\",\"Menu_Desc\":900,\"desc\":\"สปาเกตตีเส้นโฮลวีตผัดกับอกไก่หั่นเต๋า พริกแห้ง กระเทียม และสมุนไพร ปรุงรสด้วยซอสสูตรลดโซเดียม ใช้น้ำมันมะกอกอย่างดี พร้อมเพิ่มผักหลากสี เพื่อให้ได้คาร์โบไฮเดรตเชิงซ้อน โปรตีนสูง และไขมันดีในปริมาณมาก เหมาะกับการเพิ่มน้ำหนัก\"},{\"name\":\"กรีกโยเกิร์ตผสมข้าวโอ๊ต อกไก่ฉีก และเมล็ดเจีย\",\"calories\":400,\"desc\":\"กรีกโยเกิร์ตรสธรรมชาติไขมันเต็ม ผสมข้าวโอ๊ตดิบ อกไก่ฉีกละเอียด และเมล็ดเจีย ให้โปรตีนสูง คาร์โบไฮเดรตเชิงซ้อน และไขมันดี ช่วยเพิ่มพลังงานระหว่างวันได้อย่างรวดเร็วและดีต่อสุขภาพ\"},{\"name\":\"ลาบไก่สับสมุนไพร\",\"calories\":750,\"desc\":\"ลาบไก่สับจากอกไก่ล้วน ปรุงรสด้วยสมุนไพรไทย ข้าวคั่ว พริกป่น และมะนาวสด สูตรลดโซเดียม ไม่ใส่น้ำตาล เสิร์ฟพร้อมข้าวกล้องหอมมะลิในปริมาณที่มาก และผักสดนานาชนิด เพื่อให้โปรตีนสูงและใยอาหารครบถ้วน\"}]', '2026-03-07 16:58:38'),
(112, 9, 'user', 'เมนูสุขภาพที่ฉันกินได้', '2026-03-07 17:38:45');
INSERT INTO `chat_logs` (`id`, `user_id`, `sender`, `message`, `created_at`) VALUES
(113, 9, 'ai', 'ในฐานะเชฟและนักโภชนาการ ดิฉันได้คัดสรรเมนูสุขภาพ 4 มื้อ ที่มุ่งเน้นการเพิ่มน้ำหนักอย่างรวดเร็วและมีสุขภาพดีตามเป้าหมายของคุณ โดยคำนึงถึงโรคประจำตัวเบาหวานและความดันสูงเป็นสำคัญ เมนูทั้งหมดนี้จะเน้นคาร์โบไฮเดรตเชิงซ้อน โปรตีนคุณภาพดี ไขมันดี และใยอาหารสูง รวมถึงควบคุมปริมาณน้ำตาลและโซเดียมอย่างเคร่งครัด เพื่อให้มั่นใจว่าปลอดภัยต่อสุขภาพของคุณค่ะ เพื่อให้ได้แคลอรี่ตามเป้าหมาย 3215 kcal/วัน แนะนำให้ทานในปริมาณที่เหมาะสมและอาจเพิ่มส่วนของโปรตีนและคาร์โบไฮเดรตเชิงซ้อนในมื้อหลักค่ะ|||MENUS|||[{\"name\":\"ข้าวกล้องหน้าอกไก่ฉีกผัดขิง\",\"calories\":650,\"desc\":\"ข้าวกล้องหอมนุ่มทานคู่กับอกไก่ฉีกผัดขิงหอมๆ ปรุงรสอ่อนๆ ด้วยซีอิ๊วโซเดียมต่ำและน้ำมันรำข้าว อุดมด้วยคาร์โบไฮเดรตเชิงซ้อนและโปรตีนดี ช่วยให้อิ่มนานและได้รับพลังงานอย่างเพียงพอ\"},{\"name\":\"ไก่ผัดเม็ดมะม่วงหิมพานต์สูตรสุขภาพ\",\"calories\":850,\"desc\":\"อกไก่หั่นเต๋าผัดกับเม็ดมะม่วงหิมพานต์ พริกหวาน และหอมใหญ่ ปรุงรสด้วยซอสโซเดียมต่ำและน้ำตาลมะพร้าวเล็กน้อย (หากจำเป็น) เม็ดมะม่วงหิมพานต์ช่วยเพิ่มไขมันดีและแคลอรี่สูง เหมาะสำหรับเป้าหมายเพิ่มน้ำหนัก ทานคู่กับข้าวกล้อง\"},{\"name\":\"สมูทตี้โปรตีนกล้วยหอมและเนยถั่ว\",\"calories\":600,\"desc\":\"สมูทตี้ปั่นจากกล้วยหอมสุก เนยถั่วธรรมชาติไม่เติมน้ำตาลและเกลือ ผงโปรตีน (เลือกแบบที่ไม่มีน้ำตาล) และนมอัลมอนด์ไม่หวาน เป็นแหล่งพลังงาน โปรตีน และไขมันดีชั้นเยี่ยมสำหรับมื้อว่าง ช่วยเพิ่มแคลอรี่และเสริมสร้างกล้ามเนื้อ\"},{\"name\":\"ปลานิลนึ่งมะนาว ทานคู่กับผัดผักรวมมิตรกุ้งสดและข้าวกล้อง\",\"calories\":750,\"desc\":\"ปลานิลนึ่งสดใหม่ราดด้วยน้ำจิ้มมะนาวรสชาติกลมกล่อมสูตรโซเดียมต่ำ เสิร์ฟพร้อมผัดผักรวมมิตรกุ้งสดที่ใช้น้ำมันมะกอกในการผัด เพื่อให้ได้รับโปรตีนจากปลาและกุ้ง วิตามินจากผัก และคาร์โบไฮเดรตจากข้าวกล้องอย่างสมดุล เป็นมื้อเย็นที่เบาแต่ได้สารอาหารครบถ้วน\"}]', '2026-03-07 17:39:20'),
(114, 9, 'user', 'เมนูไก่วันนี้', '2026-03-08 03:07:19'),
(115, 9, 'ai', 'เรียนท่านผู้ใช้ ท่านเชฟและนักโภชนาการได้พิจารณาข้อมูลของท่านอย่างละเอียด ทั้งเป้าหมายการเพิ่มน้ำหนักแบบเร่งด่วน โรคประจำตัวเบาหวานและความดันสูง รวมถึงเมนูที่ท่านได้ทานไปแล้ว เพื่อให้มั่นใจว่าทุกเมนูที่แนะนำในวันนี้จะปลอดภัย มีประโยชน์ และช่วยให้ท่านบรรลุเป้าหมายได้อย่างมีประสิทธิภาพสูงสุด \\n\\nเมนูที่เลือกสรรมานี้เน้นโปรตีนจากอกไก่เป็นหลัก ซึ่งเป็นแหล่งโปรตีนชั้นดีที่ช่วยเสริมสร้างและซ่อมแซมกล้ามเนื้อ พร้อมด้วยคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้องและขนมปังโฮลวีตเพื่อให้พลังงานอย่างต่อเนื่อง และไขมันดีจากอะโวคาโด ถั่วแอลมอนด์ และเนยถั่วธรรมชาติ เพื่อเพิ่มพลังงานและสารอาหารที่จำเป็นต่อการเพิ่มน้ำหนักอย่างมีคุณภาพ \\n\\nสำหรับผู้ป่วยเบาหวานและความดันสูง ทุกเมนูจะถูกปรับให้ **ลดโซเดียมและงดการเติมน้ำตาลโดยเด็ดขาด** เพื่อควบคุมระดับน้ำตาลในเลือดและความดันโลหิตให้อยู่ในเกณฑ์ปกติ และเพื่อสนับสนุนเป้าหมายการเพิ่มน้ำหนักแบบเร่งด่วน ขอแนะนำให้ทานในปริมาณที่เหมาะสมและเพียงพอต่อความต้องการพลังงานของท่านในแต่ละมื้อค่ะ|||MENUS|||[{\"name\":\"แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม\",\"calories\":800,\"desc\":\"ขนมปังโฮลวีต 4 แผ่น ทาด้วยเนยถั่วธรรมชาติ (ไม่เติมน้ำตาลและเกลือ) สอดไส้อกไก่ย่างชิ้นใหญ่ ไข่ต้ม 2 ฟอง ผักกาด มะเขือเทศ และอะโวคาโดครึ่งลูก เพื่อเพิ่มพลังงานและไขมันดี\"},{\"name\":\"ผัดกะเพราอกไก่สับไข่ดาวน้ำกับข้าวกล้อง\",\"calories\":850,\"desc\":\"อกไก่สับ 200 กรัม ผัดกับใบกะเพรา พริก และกระเทียม ปรุงรสด้วยซีอิ๊วลดโซเดียมและพริกไทย งดการเติมน้ำตาล เสิร์ฟพร้อมข้าวกล้อง 250-300 กรัม และไข่ดาวน้ำ 1 ฟอง\"},{\"name\":\"ต้มยำอกไก่น้ำใสกับข้าวกล้อง\",\"calories\":700,\"desc\":\"ต้มยำอกไก่เนื้อแน่น 200 กรัม และเห็ดนานาชนิด ปรุงรสจัดจ้านด้วยสมุนไพรไทย เช่น ตะไคร้ ข่า ใบมะกรูด น้ำปลาลดโซเดียม และน้ำมะนาวสด งดการเติมน้ำตาล เสิร์ฟพร้อมข้าวกล้อง 250-300 กรัม\"},{\"name\":\"อกไก่ฉีกย่างคลุกเคล้ากับอะโวคาโดและถั่วแอลมอนด์\",\"calories\":650,\"desc\":\"อกไก่ย่างฉีก 150 กรัม คลุกเคล้ากับอะโวคาโด 1 ลูก และถั่วแอลมอนด์ไม่ใส่เกลือ 30 กรัม เป็นมื้อว่างที่อุดมด้วยโปรตีนและไขมันดี เพื่อพลังงานเสริม\"}]', '2026-03-08 03:07:44'),
(116, 9, 'user', 'ผมชื่ออะไร', '2026-03-08 03:10:59'),
(117, 9, 'ai', 'ขออภัยค่ะ ดิฉันไม่มีข้อมูลเกี่ยวกับชื่อของท่านในระบบค่ะ ดิฉันเป็นปัญญาประดิษฐ์ที่ได้รับมอบหมายให้เป็นเชฟและนักโภชนาการอัจฉริยะ พร้อมดูแลเรื่องเมนูอาหารเพื่อสุขภาพของท่านค่ะ', '2026-03-08 03:11:02'),
(118, 6, 'user', 'เมนูไก่วันนี้', '2026-03-08 03:36:19'),
(119, 6, 'user', 'เมนูไก่วันนี้', '2026-03-08 03:54:25'),
(120, 6, 'user', 'เมนูไก่วันนี้', '2026-03-08 03:55:38'),
(121, 6, 'ai', 'สวัสดีครับคุณลูกค้า ในฐานะเชฟและนักโภชนาการอัจฉริยะ ผมได้คัดสรรเมนูไก่สำหรับวันนี้มาให้ท่านถึง 4 มื้อ เพื่อสนับสนุนเป้าหมายในการเพิ่มกล้ามเนื้อแบบลีน พร้อมดูแลสุขภาพสำหรับผู้มีภาวะเบาหวานและความดันสูงอย่างเคร่งครัด เมนูที่เลือกเน้นโปรตีนคุณภาพสูงจากอกไก่ คาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้องหรือธัญพืช และใยอาหารจากผักสดหลากหลายชนิด โดยคำนึงถึงการลดปริมาณโซเดียม น้ำมัน และน้ำตาลในการปรุงเป็นสำคัญ เมนูเหล่านี้จะช่วยให้ท่านได้รับพลังงานเพียงพอต่อวัน (ประมาณ 2500 kcal) และสารอาหารครบถ้วน โดยไม่มีเมนูใดซ้ำกับที่ท่านเคยรับประทานไปแล้ว และปลอดภัยสำหรับสุขภาพของท่านครับ|||MENUS|||[{\"name\":\"อกไก่นึ่งเห็ดหอมและขิง\",\"calories\":600,\"desc\":\"อกไก่นุ่มนึ่งพร้อมเห็ดหอมและขิงหอมๆ ปรุงรสอ่อนๆ เพื่อสุขภาพดี เสิร์ฟพร้อมข้าวกล้อง (200 กรัม) เพื่อพลังงานและใยอาหาร\"},{\"name\":\"ไก่ผัดเม็ดมะม่วงหิมพานต์สูตรสุขภาพ\",\"calories\":800,\"desc\":\"ไก่ผัดเม็ดมะม่วงหิมพานต์ที่ปรุงอย่างพิถีพิถัน ลดน้ำมันและโซเดียม เน้นโปรตีนจากอกไก่ ไขมันดีจากเม็ดมะม่วง และใยอาหารจากผักหลากสี เสิร์ฟพร้อมข้าวกล้อง\"},{\"name\":\"สลัดโรลอกไก่ฉีกน้ำจิ้มซีฟู้ดโยเกิร์ต\",\"calories\":250,\"desc\":\"สลัดโรลที่อุดมด้วยผักสดกรอบและอกไก่ฉีกไร้มัน ทานคู่กับน้ำจิ้มซีฟู้ดโยเกิร์ตสูตรไร้น้ำมันและลดโซเดียม เหมาะสำหรับมื้อว่างเบาๆ\"},{\"name\":\"ผัดผักรวมมิตรน้ำมันหอยอกไก่\",\"calories\":850,\"desc\":\"อกไก่หั่นชิ้นผัดกับผักรวมมิตรหลากหลายชนิด ปรุงรสด้วยน้ำมันหอยสูตรลดโซเดียมและใช้น้ำมันรำข้าวในปริมาณที่พอเหมาะ เสิร์ฟพร้อมข้าวกล้อง เพื่อความอิ่มและสารอาหารครบถ้วน\"}]', '2026-03-08 03:56:08'),
(122, 6, 'user', 'เมนูไก่วันนี้', '2026-03-08 04:11:55'),
(123, 6, 'ai', 'สวัสดีครับคุณkajornsak ในฐานะเชฟและนักโภชนาการ ผมได้คัดสรรเมนูไก่สำหรับวันนี้มาให้คุณโดยเฉพาะ เพื่อสนับสนุนเป้าหมายในการเพิ่มกล้ามเนื้อแบบลีน พร้อมทั้งดูแลสุขภาพเรื่องเบาหวานและความดันสูงอย่างเคร่งครัด เมนูที่เลือกมาเน้นโปรตีนคุณภาพสูง คาร์โบไฮเดรตเชิงซ้อน และผักหลากหลายชนิด ปรุงรสด้วยเครื่องปรุงลดโซเดียมและน้ำตาลเป็นหลัก เพื่อให้มั่นใจว่าปลอดภัยและดีต่อสุขภาพของคุณครับ ทุกเมนูจะไม่ซ้ำกับที่คุณได้ทานไปแล้วแน่นอนครับ|||MENUS|||[{\"name\":\"ข้าวกล้องผัดธัญพืชรวมและอกไก่\",\"calories\":600,\"desc\":\"ข้าวกล้องหอมนุ่มผัดกับธัญพืชหลากหลายชนิด อาทิ ข้าวโพด ถั่วลันเตา และอกไก่หั่นชิ้น ปรุงรสอย่างกลมกล่อมด้วยซีอิ๊วขาวลดโซเดียมและน้ำมันหอยสูตรไขมันต่ำ เน้นโปรตีนและใยอาหารสูง เหมาะสำหรับมื้อหลักที่ต้องการพลังงาน\"},{\"name\":\"ก๋วยเตี๋ยวลุยสวนอกไก่\",\"calories\":550,\"desc\":\"เมนูเพื่อสุขภาพที่อัดแน่นไปด้วยผักสดนานาชนิด ห่อด้วยแผ่นแป้งบางเบาพร้อมไส้อกไก่สับปรุงรสน้อยๆ เสิร์ฟพร้อมน้ำจิ้มซีฟู้ดสูตรลดโซเดียมและน้ำตาล เพื่อรสชาติที่สดชื่นและดีต่อสุขภาพหัวใจ\"},{\"name\":\"ผัดกะเพราอกไก่สับไข่ดาวน้ำ\",\"calories\":750,\"desc\":\"อกไก่สับผัดกะเพราถึงเครื่อง ปรุงรสแบบลดโซเดียมและน้ำตาลเพื่อให้เหมาะกับผู้ป่วยเบาหวานและความดันสูง เสิร์ฟพร้อมข้าวกล้องหุงสุก และไข่ดาวน้ำไร้น้ำมัน โปรตีนสูง ช่วยเสริมสร้างกล้ามเนื้อได้ดี\"},{\"name\":\"แซนด์วิชอกไก่ย่างขนมปังโฮลวีตและไข่ต้ม\",\"calories\":500,\"desc\":\"ขนมปังโฮลวีตเต็มแผ่นประกบด้วยอกไก่ย่างหอมๆ และไข่ต้มหั่นชิ้น พร้อมผักสดกรอบๆ เช่น ผักกาดหอมและมะเขือเทศ เป็นมื้อว่างที่อุดมไปด้วยโปรตีนและใยอาหาร ช่วยให้อิ่มนานและควบคุมระดับน้ำตาลได้ดี\"}]', '2026-03-08 04:12:18'),
(124, 6, 'user', 'หิวข้าว', '2026-03-08 04:13:54'),
(125, 6, 'ai', 'สวัสดีครับคุณkajornsak ในฐานะเชฟและนักโภชนาการอัจฉริยะ ผมเข้าใจว่าคุณกำลังมองหาเมนูที่ช่วยเสริมสร้างกล้ามเนื้อแบบลีน พร้อมดูแลสุขภาพในเรื่องเบาหวานและความดันสูงด้วยนะครับ ผมได้คัดสรร 4 เมนูมื้อหลักและมื้อว่างที่หลากหลาย ปลอดภัย และดีต่อสุขภาพของคุณkajornsak มาให้เรียบร้อยแล้วครับ\n\nเมนูเหล่านี้ได้รับการออกแบบมาเพื่อให้มีโปรตีนคุณภาพดี คาร์โบไฮเดรตเชิงซ้อน และไขมันดีในปริมาณที่เหมาะสม เพื่อสนับสนุนเป้าหมายการเพิ่มกล้ามเนื้อของคุณkajornsak พร้อมทั้งควบคุมระดับน้ำตาลและความดันโลหิต โดยเน้นการปรุงรสที่อ่อนโยนและใช้ส่วนผสมสดใหม่ครับ นอกจากนี้ ผมยังได้ตรวจสอบอย่างละเอียดแล้วว่าเมนูเหล่านี้ไม่ซ้ำกับรายการที่คุณkajornsakเพิ่งทานไป และปลอดภัยสำหรับโรคประจำตัวของคุณkajornsakครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา\",\"calories\":550,\"desc\":\"อกไก่นุ่มหมักสมุนไพรย่างจนหอมกรุ่น เสิร์ฟคู่กับควิโนอาหุงสุก ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อนที่ดีต่อผู้ป่วยเบาหวาน และผักนึ่งหลากสีสัน ปรุงรสอ่อนเพื่อสุขภาพที่ดี\"},{\"name\":\"ปลานึ่งมะนาวสูตรโซเดียมต่ำ\",\"calories\":650,\"desc\":\"ปลากะพงเนื้อนุ่มนึ่งกับน้ำซุปมะนาวรสจัดจ้านแต่โซเดียมต่ำ ใส่ผักชีฝรั่ง พริก และกระเทียม ทานคู่กับข้าวกล้องหอมมะลิ เพื่อให้ได้โปรตีนและคาร์โบไฮเดรตที่สมบูรณ์\"},{\"name\":\"แซลมอนย่างซีอิ๊วและบล็อกโคลี่นึ่ง\",\"calories\":680,\"desc\":\"เนื้อปลาแซลมอนชิ้นโตย่างซีอิ๊วสูตรลดโซเดียมหอมกรุ่น ซึ่งอุดมไปด้วยโอเมก้า 3 ที่ดีต่อหัวใจและหลอดเลือด เสิร์ฟเคียงกับบล็อกโคลี่นึ่งร้อนๆ เพื่อเพิ่มวิตามินและใยอาหาร\"},{\"name\":\"สลัดทูน่าอะโวคาโด\",\"calories\":300,\"desc\":\"ทูน่าในน้ำแร่คลุกเคล้ากับอะโวคาโดหั่นเต๋า มะเขือเทศเชอร์รี่ และผักสลัดหลากสี อุดมด้วยโปรตีน ไขมันดี และใยอาหาร ปรุงรสด้วยน้ำสลัดใสไขมันต่ำเพื่อสุขภาพ\"}]', '2026-03-08 04:14:17'),
(126, 9, 'user', 'ผมชื่ออะไร', '2026-03-08 04:15:19'),
(127, 9, 'ai', 'สวัสดีครับ/ค่ะ คุณKha', '2026-03-08 04:15:23'),
(128, 9, 'user', 'ให้คุณเป็นผู้ชายนะครับเชฟ', '2026-03-08 04:16:03'),
(129, 9, 'ai', 'สวัสดีครับ คุณKha ในฐานะเชฟและนักโภชนาการ ผมได้พิจารณาข้อมูลของคุณKha อย่างถี่ถ้วน ทั้งเป้าหมายการเพิ่มน้ำหนักแบบเร่งด่วนที่ 3215 กิโลแคลอรีต่อวัน และข้อจำกัดด้านสุขภาพของคุณKha ได้แก่ โรคเบาหวานและความดันสูง รวมถึงเมนูที่เพิ่งทานไปเมื่อเร็วๆ นี้ ผมได้คัดสรรเมนูอาหารไทยที่อร่อย มีประโยชน์ และเหมาะสมกับความต้องการของคุณKha มาให้ 4 มื้อ ดังนี้ครับ\n\nเมนูเหล่านี้เน้นโปรตีนไม่ติดมัน คาร์โบไฮเดรตเชิงซ้อน และไขมันดี เพื่อช่วยให้คุณKha ได้รับพลังงานเพียงพอสำหรับการเพิ่มน้ำหนักอย่างมีสุขภาพดี โดยยังคงควบคุมระดับน้ำตาลในเลือดและความดันโลหิต การปรุงเน้นลดโซเดียมและน้ำตาล แต่ยังคงรสชาติที่อร่อยกลมกล่อมครับ|||MENUS|||[{\"name\":\"อกไก่นุ่มย่างสมุนไพรและควิโนอา\",\"calories\":700,\"desc\":\"เมนูเช้าที่ให้พลังงานสูงจากควิโนอา ซึ่งเป็นคาร์โบไฮเดรตเชิงซ้อน มีโปรตีนสูงจากอกไก่ และไขมันดีจากสมุนไพรและน้ำมันมะกอกที่ใช้ย่าง ช่วยให้อิ่มนานและมีพลังงานเพียงพอสำหรับการเริ่มต้นวัน\"},{\"name\":\"สเต็กปลาแซลมอนย่างเกลือพริกไทยและหน่อไม้ฝรั่ง\",\"calories\":1000,\"desc\":\"มื้อกลางวันที่อุดมด้วยกรดไขมันโอเมก้า 3 จากแซลมอน ซึ่งดีต่อสุขภาพหัวใจและสมอง โปรตีนสูง และแคลอรี่ที่เหมาะสมสำหรับการเพิ่มน้ำหนัก เสิร์ฟพร้อมหน่อไม้ฝรั่งและข้าวกล้องหอมมะลิหรือควิโนอา เพื่อพลังงานและใยอาหารที่ครบถ้วน\"},{\"name\":\"สลัดทูน่าอะโวคาโด\",\"calories\":500,\"desc\":\"มื้อว่างที่ช่วยเติมพลังงานระหว่างวันได้อย่างมีสุขภาพดี ด้วยโปรตีนจากทูน่า (เลือกทูน่าในน้ำแร่หรือน้ำมันมะกอก) และไขมันดีจากอะโวคาโด ช่วยให้รู้สึกอิ่มและได้รับสารอาหารที่สำคัญ\"},{\"name\":\"ข้าวผัดธัญพืชอกไก่\",\"calories\":900,\"desc\":\"มื้อเย็นที่ให้คาร์โบไฮเดรตเชิงซ้อนจากธัญพืชหลากหลายชนิด พร้อมโปรตีนจากอกไก่ ปรุงรสอ่อนโดยใช้สมุนไพรและเครื่องเทศ เพื่อลดโซเดียมและน้ำตาล แต่ยังคงความอร่อยและได้สารอาหารครบถ้วน\"}]', '2026-03-08 04:16:28'),
(130, 9, 'user', 'ผมมีวัตถุดิบ: กุ้งสดปอกเปลือก 150 กรัม แนะนำเมนูที่ทำได้หน่อย', '2026-03-08 04:18:35'),
(131, 9, 'ai', 'สวัสดีครับคุณKha ในฐานะเชฟและนักโภชนาการ ผมได้คัดสรรเมนูอาหารไทย 4 มื้อ ที่คำนึงถึงเป้าหมายการเพิ่มน้ำหนักอย่างเร่งด่วนของคุณ พร้อมดูแลสุขภาพเรื่องโรคเบาหวานและความดันสูงอย่างเคร่งครัด โดยเน้นอาหารที่มีโปรตีนสูง คาร์โบไฮเดรตเชิงซ้อน และไขมันดีในปริมาณที่เหมาะสม เพื่อให้คุณได้รับพลังงานเพียงพอต่อวัน โดยลดปริมาณโซเดียมและน้ำตาลในทุกเมนูครับ\n\nสำหรับวัตถุดิบกุ้งสดปอกเปลือก 150 กรัมที่คุณมี ผมได้นำมาใส่ในเมนู \'ผัดบล็อกโคลี่กุ้งสด\' เพื่อให้คุณได้รับโปรตีนคุณภาพดี และใยอาหารจากบล็อกโคลี่อย่างเต็มที่ครับ \n\nทุกเมนูที่แนะนำนี้ปลอดภัย 100% สำหรับคุณKha ที่ไม่มีประวัติแพ้อาหาร และจะช่วยให้คุณทานอาหารได้อย่างหลากหลาย ไม่ซ้ำซากกับเมนูที่คุณเคยทานมาอย่างแน่นอนครับ|||MENUS|||[{\"name\":\"ไข่ตุ๋นทรงเครื่อง\",\"calories\":550,\"desc\":\"ไข่ตุ๋นเนื้อเนียนนุ่ม ปรุงรสอ่อนๆ ใส่เนื้ออกไก่สับไม่ติดมันและผักหลากสี เสิร์ฟพร้อมข้าวกล้องหอมนุ่ม เพื่อเพิ่มโปรตีนและคาร์โบไฮเดรตเชิงซ้อน เป็นมื้อเช้าที่อิ่มสบายและมีประโยชน์\"},{\"name\":\"พาสต้าโฮลวีทผัดพริกแห้งและทูน่า\",\"calories\":700,\"desc\":\"พาสต้าโฮลวีทเหนียวนุ่ม ผัดคลุกเคล้ากับทูน่าในน้ำแร่ พริกแห้ง และกระเทียม ปรุงรสด้วยน้ำมันมะกอกและสมุนไพร ให้พลังงานสูงจากคาร์โบไฮเดรตเชิงซ้อนและโปรตีนดี\"},{\"name\":\"ผัดบล็อกโคลี่กุ้งสด\",\"calories\":750,\"desc\":\"บล็อกโคลี่สดกรอบผัดกับกุ้งสดตัวโต ปรุงรสด้วยซอสสูตรลดโซเดียมและน้ำมันหอยลดเค็ม เพิ่มความหอมด้วยกระเทียม เสิร์ฟพร้อมข้าวกล้องร้อนๆ เป็นเมนูที่อุดมไปด้วยโปรตีน ใยอาหาร และแร่ธาตุ\"},{\"name\":\"เส้นโซบะเย็นซอสถั่วใส่เต้าหู้ย่าง\",\"calories\":600,\"desc\":\"เส้นโซบะเหนียวนุ่ม ท็อปด้วยเต้าหู้ขาวแผ่นย่างหอมๆ และผักสดนานาชนิด ราดด้วยซอสถั่วลิสงสูตรเฉพาะที่ลดโซเดียมและน้ำตาล ให้พลังงานและโปรตีนที่ดีต่อร่างกาย เป็นมื้อว่างที่อิ่มและมีประโยชน์\"}]', '2026-03-08 04:18:59'),
(132, 9, 'user', 'เมนูไก่วันนี้', '2026-03-08 04:24:05'),
(133, 9, 'ai', 'สวัสดีครับคุณKha! ในฐานะเชฟและนักโภชนาการ ผมยินดีอย่างยิ่งที่จะรังสรรค์เมนูไก่แสนอร่อยและมีประโยชน์สำหรับคุณKha ในวันนี้ครับ ผมได้คัดสรรเมนูที่หลากหลาย ครบ 4 มื้อ และที่สำคัญคือปลอดภัย 100% สำหรับผู้มีภาวะเบาหวานและความดันสูงของคุณKha โดยเน้นการปรุงแบบลดโซเดียม ลดน้ำตาล และใช้ไขมันดีเท่าที่จำเป็นครับ เมนูเหล่านี้จะไม่ซ้ำกับที่เคยทานไปแน่นอนครับ มาดูกันเลยนะครับ!|||MENUS|||[{\"name\":\"ข้าวต้มข้าวกล้องอกไก่ฉีกและขิงซอย - มื้อเช้า\",\"calories\":380,\"ingredients\":\"- ข้าวกล้องหุงสุก 1 ถ้วย (ประมาณ 100 กรัม)\\n- อกไก่ลวกฉีก 100 กรัม\\n- ขิงซอย 2 ช้อนโต๊ะ\\n- ขึ้นฉ่ายหั่นท่อน 1 ช้อนโต๊ะ\\n- น้ำซุปไก่ (ไม่ใส่ผงชูรส) 2 ถ้วย\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนชา\\n- พริกไทยป่นเล็กน้อย\",\"instructions\":\"1. ต้มน้ำซุปไก่ให้เดือด ใส่ข้าวกล้องที่หุงสุกแล้วลงไป เคี่ยวจนข้าวเริ่มบานและนุ่ม (อาจเติมน้ำได้หากข้นเกินไป)\\n2. ใส่อกไก่ฉีกลงไป คนให้เข้ากัน\\n3. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยป่นเล็กน้อย ชิมรสตามชอบ\\n4. ตักใส่ชาม โรยหน้าด้วยขิงซอยและขึ้นฉ่ายหั่นท่อน\\n5. เสิร์ฟร้อนๆ เพื่อมื้อเช้าที่อิ่มสบายท้องและย่อยง่ายสำหรับคุณKha ครับ\",\"desc\":\"เมนูย่อยง่าย ให้พลังงานดีเยี่ยมสำหรับเริ่มต้นวันใหม่ของคุณKha อกไก่ให้โปรตีนสูง ขิงช่วยขับลมและบำรุงธาตุ ข้าวกล้องให้คาร์โบไฮเดรตเชิงซ้อนที่ดีต่อการควบคุมระดับน้ำตาลในเลือดและปลอดภัยสำหรับผู้ป่วยความดันสูงเพราะมีโซเดียมต่ำครับ\"},{\"name\":\"ข้าวกล้องอกไก่ผัดขิงเห็ดหอม - มื้อกลางวัน\",\"calories\":600,\"ingredients\":\"- ข้าวกล้องหุงสุก 1.5 ถ้วย (ประมาณ 150 กรัม)\\n- อกไก่หั่นชิ้น 150 กรัม\\n- ขิงซอย 3 ช้อนโต๊ะ\\n- เห็ดหอมสดหั่นเต๋า 1\\/2 ถ้วย\\n- ต้นหอมหั่นท่อน 2 ช้อนโต๊ะ\\n- พริกชี้ฟ้าหั่นแฉลบ (ถ้าชอบ) 1 ช้อนโต๊ะ\\n- น้ำมันรำข้าว 1 ช้อนโต๊ะ\\n- ซีอิ๊วขาวลดโซเดียม 1.5 ช้อนโต๊ะ\\n- น้ำมันหอยลดโซเดียม 1 ช้อนโต๊ะ\\n- น้ำเปล่าเล็กน้อย\",\"instructions\":\"1. ตั้งกระทะ ใส่น้ำมันรำข้าวพอร้อน ใส่อกไก่ลงไปผัดพอสุก\\n2. ใส่ขิงซอยและเห็ดหอมลงไปผัดให้เข้ากันจนมีกลิ่นหอม\\n3. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและน้ำมันหอยลดโซเดียม เติมน้ำเปล่าเล็กน้อยเพื่อไม่ให้แห้งเกินไป\\n4. ใส่ต้นหอมและพริกชี้ฟ้า (ถ้าใช้) ลงไปผัดเร็วๆ พอผักสลด ปิดไฟ\\n5. ตักอกไก่ผัดขิงเห็ดหอมราดบนข้าวกล้องหุงสุก พร้อมเสิร์ฟความอร่อยให้คุณKha ในมื้อกลางวันครับ\",\"desc\":\"เมนูนี้จัดเต็มด้วยรสชาติหอมจากขิงและเห็ดหอมครับ อกไก่เป็นโปรตีนลีนชั้นดี ขิงช่วยกระตุ้นการเผาผลาญและลดไขมัน ส่วนการใช้ซีอิ๊วและน้ำมันหอยลดโซเดียมช่วยให้คุณKha ทานได้อย่างสบายใจเรื่องความดันครับ\"},{\"name\":\"ลาบอกไก่สมุนไพร - มื้อเย็น\",\"calories\":350,\"ingredients\":\"- อกไก่บดละเอียด 200 กรัม\\n- หอมแดงซอย 2 ช้อนโต๊ะ\\n- ต้นหอมซอย 2 ช้อนโต๊ะ\\n- ผักชีฝรั่งซอย 1 ช้อนโต๊ะ\\n- ใบสะระแหน่ (สำหรับโรยหน้า) 1\\/4 ถ้วย\\n- พริกป่น (ตามชอบ) 1 ช้อนชา\\n- ข้าวคั่ว 2 ช้อนโต๊ะ\\n- น้ำปลาลดโซเดียม 2 ช้อนโต๊ะ\\n- น้ำมะนาว 3 ช้อนโต๊ะ\\n- ผักสดเคียง (เช่น กะหล่ำปลี แตงกวา ถั่วฝักยาว)\",\"instructions\":\"1. ลวกอกไก่บดในน้ำเดือดจนสุก ตักขึ้นพักให้สะเด็ดน้ำ\\n2. ในชามผสม ใส่อกไก่บดลวกลงไป ตามด้วยหอมแดงซอย ต้นหอมซอย ผักชีฝรั่ง พริกป่น และข้าวคั่ว\\n3. ปรุงรสด้วยน้ำปลาลดโซเดียมและน้ำมะนาว คลุกเคล้าให้ส่วนผสมเข้ากันดี\\n4. ชิมรสชาติให้อร่อยถูกใจ (เน้นเปรี้ยวนำ เค็มตาม และเผ็ดตามชอบ)\\n5. ตักลาบใส่จาน โรยหน้าด้วยใบสะระแหน่ และเสิร์ฟพร้อมผักสดเคียงหลากหลายชนิดสำหรับคุณKha ครับ\",\"desc\":\"เมนูลาบไก่สมุนไพรเป็นตัวเลือกที่ยอดเยี่ยมสำหรับมื้อเย็นของคุณKha ครับ เพราะให้โปรตีนสูงจากอกไก่และมีสมุนไพรนานาชนิดช่วยเรื่องระบบย่อยอาหาร การใช้ข้าวคั่วช่วยเพิ่มกลิ่นหอมและใยอาหาร พร้อมกับน้ำปลาลดโซเดียม ทำให้เป็นเมนูที่สดชื่นและปลอดภัยต่อสุขภาพหัวใจและเบาหวานครับ\"},{\"name\":\"สลัดโรลอกไก่ฉีกน้ำจิ้มซีฟู้ดโยเกิร์ต - มื้อว่าง\",\"calories\":450,\"ingredients\":\"- แผ่นแป้งปอเปี๊ยะสด 5 แผ่น\\n- อกไก่ลวกฉีก 100 กรัม\\n- ผักกาดแก้ว 1 ต้น (ฉีกเป็นใบ)\\n- แครอทหั่นเส้น 1\\/4 ถ้วย\\n- แตงกวาหั่นเส้น 1\\/4 ถ้วย\\n- ใบโหระพาหรือสะระแหน่เล็กน้อย\\n- สำหรับน้ำจิ้มซีฟู้ดโยเกิร์ต:\\n  - โยเกิร์ตรสธรรมชาติ (ไขมันต่ำ) 1 ถ้วย\\n  - น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\\n  - น้ำมะนาว 2 ช้อนโต๊ะ\\n  - พริกขี้หนูสวนซอย 1 ช้อนโต๊ะ (ตามชอบ)\\n  - กระเทียมสับ 1 ช้อนชา\\n  - หญ้าหวาน หรือสารให้ความหวานแทนน้ำตาล (เล็กน้อย ถ้าจำเป็น)\",\"instructions\":\"1. ทำน้ำจิ้ม: ผสมโยเกิร์ต, น้ำปลาลดโซเดียม, น้ำมะนาว, พริกขี้หนู, กระเทียม และหญ้าหวาน (ถ้าใช้) ให้เข้ากันดี พักไว้\\n2. เตรียมแผ่นแป้งปอเปี๊ยะ: ชุบแผ่นแป้งในน้ำอุ่นพอให้นุ่ม (ไม่ต้องแช่นาน)\\n3. จัดวางผักกาดแก้ว, แครอท, แตงกวา, ใบโหระพา\\/สะระแหน่ และอกไก่ฉีกลงบนแผ่นแป้งที่ชุบน้ำ\\n4. ม้วนแผ่นแป้งให้แน่น เริ่มจากด้านล่างขึ้นไป พับด้านข้างเข้าหากัน แล้วม้วนจนสุด\\n5. หั่นสลัดโรลเป็นชิ้นพอดีคำ จัดเรียงใส่จาน\\n6. เสิร์ฟพร้อมน้ำจิ้มซีฟู้ดโยเกิร์ตที่เตรียมไว้ เป็นมื้อว่างสุดสดชื่นของคุณKha ครับ\",\"desc\":\"สลัดโรลอกไก่ฉีกเป็นมื้อว่างที่เหมาะสำหรับคุณKha ที่ต้องการความสดชื่นและประโยชน์ครบถ้วนครับ อกไก่ให้โปรตีนสูง ผักสดให้วิตามินและใยอาหาร น้ำจิ้มซีฟู้ดโยเกิร์ตปรุงด้วยโยเกิร์ตไขมันต่ำและลดโซเดียม ช่วยลดความเสี่ยงทั้งเบาหวานและความดันสูงได้อย่างดีเยี่ยมเลยครับ\"}]', '2026-03-08 04:24:37'),
(134, 9, 'user', 'กินไรดี', '2026-03-08 04:26:29'),
(135, 9, 'ai', 'สวัสดีครับคุณKha ในฐานะเชฟและนักโภชนาการอัจฉริยะ ผมเข้าใจเลยครับว่าคุณKhaกำลังเร่งเพิ่มน้ำหนัก และมีข้อจำกัดเรื่องโรคเบาหวานและความดันสูงเป็นพิเศษ ไม่ต้องกังวลนะครับ ผมได้คัดสรรเมนูอาหารไทยที่มีคุณค่าทางโภชนาการสูง ปลอดภัย 100% สำหรับคุณKha และที่สำคัญคือไม่ซ้ำกับเมนูที่คุณKhaเพิ่งทานไปแน่นอนครับ\n\nเป้าหมายของคุณKhaคือ 3215 kcal/วัน ผมจึงเน้นเมนูที่ให้พลังงานสูง โปรตีนเพียงพอจากเนื้อสัตว์ไม่ติดมันและธัญพืช รวมถึงไขมันดีจากอะโวคาโดและน้ำมันรำข้าว เพื่อช่วยให้คุณKhaเพิ่มน้ำหนักได้อย่างมีประสิทธิภาพ และยังคงควบคุมระดับน้ำตาลและความดันโลหิตได้ดี โดยเน้นการปรุงรสแบบลดโซเดียม ลดน้ำตาล และใช้ข้าวกล้องหรือวุ้นเส้นเป็นหลักครับ ลองดูเมนูที่ผมแนะนำสำหรับคุณKhaได้เลยครับ!|||MENUS|||[{\"name\":\"โจ๊กข้าวกล้องหมูสับและเห็ดหอม - มื้อเช้า\",\"calories\":720,\"ingredients\":\"- ข้าวกล้องหุงสุก 300 กรัม\\n- หมูสับไม่ติดมัน 150 กรัม\\n- เห็ดหอมสดหั่นเต๋า 50 กรัม\\n- ไข่ไก่ 1 ฟอง\\n- น้ำซุปกระดูกหมู\\/ไก่ (ไม่ปรุงรส) 4 ถ้วย\\n- ขิงซอย 2 ช้อนโต๊ะ\\n- ต้นหอมซอย 1 ช้อนโต๊ะ\\n- น้ำมันงา 1 ช้อนชา\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนโต๊ะ\\n- พริกไทยป่นเล็กน้อย\",\"instructions\":\"1. ต้มน้ำซุปให้เดือด ใส่ข้าวกล้องหุงสุกลงไป เคี่ยวไฟอ่อนประมาณ 20-30 นาที จนข้าวเริ่มเปื่อยนุ่มและข้นขึ้น\\n2. ปรุงรสหมูสับด้วยซีอิ๊วขาวลดโซเดียมเล็กน้อย นำลงลวกในน้ำซุปจนสุก ตักขึ้นพักไว้\\n3. ใส่เห็ดหอมลงในหม้อโจ๊ก เคี่ยวต่ออีก 5 นาที\\n4. ตอกไข่ใส่ชาม ตีให้เข้ากัน จากนั้นค่อยๆ เทไข่ลงในหม้อโจ๊ก คนให้เป็นสาย\\n5. ตักโจ๊กใส่ชาม วางหมูสับที่ลวกไว้ด้านบน โรยด้วยขิงซอย ต้นหอมซอย และพริกไทยป่น\\n6. เหยาะน้ำมันงาเล็กน้อยเพื่อเพิ่มกลิ่นหอมและไขมันดี เสิร์ฟขณะร้อน\",\"desc\":\"เมนูย่อยง่ายแต่ให้พลังงานสูง เหมาะสำหรับมื้อเช้าของคุณKhaครับ มีคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง โปรตีนจากหมูสับและไข่ และไขมันดีจากน้ำมันงา ช่วยควบคุมระดับน้ำตาลได้ดีและดีต่อความดัน\"},{\"name\":\"ผัดไทยวุ้นเส้นอกไก่สูตรลดโซเดียม - มื้อกลางวัน\",\"calories\":980,\"ingredients\":\"- วุ้นเส้นแห้ง 150 กรัม (แช่น้ำให้นิ่ม)\\n- อกไก่หั่นชิ้น 150 กรัม\\n- เต้าหู้ขาวแข็งหั่นเต๋า 100 กรัม\\n- ไข่ไก่ 1 ฟอง\\n- ถั่วงอก 1 ถ้วย\\n- กุยช่ายหั่นท่อน 1\\/2 ถ้วย\\n- ถั่วลิสงคั่วบดหยาบ 2 ช้อนโต๊ะ\\n- น้ำมันรำข้าว 2 ช้อนโต๊ะ\\n- ซอสผัดไทยสูตรลดโซเดียม:\\n  - น้ำมะขามเปียก 3 ช้อนโต๊ะ\\n  - น้ำปลาลดโซเดียม 2 ช้อนโต๊ะ\\n  - น้ำตาลมะพร้าว 1 ช้อนโต๊ะ\\n  - พริกป่น (ตามชอบ)\\n- มะนาวหั่นซีก 1 ซีก\",\"instructions\":\"1. เตรียมซอสผัดไทยโดยผสมน้ำมะขามเปียก น้ำปลาลดโซเดียม และน้ำตาลมะพร้าว คนให้เข้ากัน พักไว้\\n2. ตั้งกระทะใส่น้ำมันรำข้าวเล็กน้อย พอร้อนนำเต้าหู้ลงทอดพอเหลือง ตักขึ้นพักไว้\\n3. ใส่เนื้ออกไก่ลงผัดพอสุก ดันไปข้างกระทะ ตอกไข่ใส่ลงไป ยีให้พอสุก\\n4. ใส่วุ้นเส้นที่แช่น้ำแล้วลงไปผัดให้เข้ากันกับไก่และไข่\\n5. ราดซอสผัดไทยลงไป ผัดให้เส้นดูดซับน้ำซอสจนทั่ว\\n6. ใส่ถั่วงอกและกุยช่าย ผัดอย่างรวดเร็วจนผักสลด ปิดไฟ\\n7. ตักใส่จาน โรยด้วยถั่วลิสงคั่วบด เสิร์ฟพร้อมมะนาว\",\"desc\":\"ผัดไทยสูตรนี้เน้นวุ้นเส้นและอกไก่ ให้พลังงานสูงจากคาร์โบไฮเดรต โปรตีน และไขมันดีจากถั่วลิสง ลดโซเดียมเพื่อคุณKhaครับ เหมาะสำหรับมื้อกลางวันที่ต้องการพลังงานไปทำงานต่อ\"},{\"name\":\"ปลากะพงนึ่งซีอิ๊วขิงแก่กับข้าวกล้อง - มื้อเย็น\",\"calories\":950,\"ingredients\":\"- ปลากะพง 1 ชิ้นใหญ่ (ประมาณ 250 กรัม)\\n- ข้าวกล้องหุงสุก 400 กรัม (ประมาณ 2 ถ้วย)\\n- เห็ดหอมสดหั่นเส้น 50 กรัม\\n- ขิงแก่ซอย 1\\/4 ถ้วย\\n- ต้นหอมหั่นท่อน 2-3 ต้น\\n- ขึ้นฉ่ายหั่นท่อน 2-3 ต้น\\n- พริกไทยดำป่นเล็กน้อย\\n- ซีอิ๊วขาวลดโซเดียม 2 ช้อนโต๊ะ\\n- น้ำมันงา 1 ช้อนโต๊ะ\\n- น้ำสต็อกผักหรือน้ำเปล่า 2 ช้อนโต๊ะ\",\"instructions\":\"1. ล้างทำความสะอาดปลากะพง ซับให้แห้ง บั้งข้างตัวปลาเล็กน้อย\\n2. จัดปลาลงในจานสำหรับนึ่ง วางขิงซอยครึ่งหนึ่งและเห็ดหอมลงบนตัวปลา\\n3. ผสมซีอิ๊วขาวลดโซเดียม น้ำมันงา และน้ำสต็อกผัก คนให้เข้ากัน ราดบนตัวปลา\\n4. นำไปนึ่งในน้ำเดือด ประมาณ 15-20 นาที หรือจนปลากะพงสุก\\n5. เมื่อปลาสุก โรยขิงซอยที่เหลือ ต้นหอม และขึ้นฉ่ายลงบนตัวปลา ปิดฝานึ่งต่ออีก 1-2 นาทีพอผักสลด\\n6. ตักปลากะพงนึ่งซีอิ๊วขิงแก่ เสิร์ฟพร้อมข้าวกล้องร้อนๆ\\n7. เพิ่มคุณค่าทางโภชนาการด้วยการเหยาะน้ำมันงาเพิ่มเล็กน้อยตอนเสิร์ฟ\",\"desc\":\"เมนูนี้ดีต่อสุขภาพของคุณKhaมากๆ ครับ มีโปรตีนสูงจากปลากะพง ไขมันต่ำ และลดโซเดียม ขิงช่วยเพิ่มรสชาติและคุณประโยชน์ หาทานคู่กับข้าวกล้องปริมาณเหมาะสมเพื่อเพิ่มพลังงานให้ถึงเป้าหมายนะครับ\"},{\"name\":\"สลัดทูน่าอะโวคาโด - มื้อว่าง\",\"calories\":650,\"ingredients\":\"- ทูน่าในน้ำแร่ (สะเด็ดน้ำ) 1 กระป๋องใหญ่ (ประมาณ 185 กรัมเนื้อ)\\n- อะโวคาโดสุกหั่นเต๋า 1 ลูกใหญ่\\n- ผักสลัดรวม (กรีนโอ๊ค, เรดโอ๊ค, คอส) 1 ถ้วย\\n- มะเขือเทศเชอร์รี่ผ่าครึ่ง 1\\/2 ถ้วย\\n- หอมใหญ่ซอยละเอียด 2 ช้อนโต๊ะ\\n- น้ำมันมะกอก Extra Virgin 2 ช้อนโต๊ะ\\n- น้ำมะนาว 2 ช้อนโต๊ะ\\n- เกลือชมพูเล็กน้อย\\n- พริกไทยดำบดสด (ตามชอบ)\",\"instructions\":\"1. เตรียมผักสลัดและมะเขือเทศ ล้างให้สะอาด พักให้สะเด็ดน้ำ จัดใส่จาน\\n2. หั่นอะโวคาโดเป็นเต๋าเล็กๆ และหอมใหญ่ซอย เตรียมไว้\\n3. ในชามผสม ใส่ทูน่าที่สะเด็ดน้ำแล้ว อะโวคาโด และหอมใหญ่ซอย\\n4. ทำน้ำสลัดโดยผสมน้ำมันมะกอก น้ำมะนาว เกลือชมพู และพริกไทยดำ คนให้เข้ากัน\\n5. ราดน้ำสลัดลงบนส่วนผสมทูน่าและอะโวคาโด คลุกเคล้าเบาๆ ให้เข้ากัน\\n6. ตักส่วนผสมทูน่าอะโวคาโดวางลงบนจานผักสลัดที่เตรียมไว้\\n7. เสิร์ฟทันทีเพื่อความสดใหม่\",\"desc\":\"สลัดทูน่าอะโวคาโดเป็นเมนูว่างที่ให้พลังงานสูงและอุดมไปด้วยไขมันดีจากอะโวคาโดและน้ำมันมะกอก ซึ่งจำเป็นสำหรับการเพิ่มน้ำหนักของคุณKhaครับ มีโปรตีนจากทูน่า และใยอาหารจากผัก ช่วยบำรุงหัวใจและควบคุมระดับน้ำตาลได้เป็นอย่างดี\"}]', '2026-03-08 04:26:59'),
(136, 9, 'user', 'เมนูไก่วันนี้', '2026-03-08 04:29:48'),
(137, 9, 'ai', 'ครับคุณKha! ในฐานะเชฟและนักโภชนาการ ผมเข้าใจดีว่าคุณKhaกำลังมองหาเมนูไก่ที่น่าสนใจและช่วยเพิ่มน้ำหนักแบบเร่งด่วนตามเป้าหมาย 3215 kcal/วัน ซึ่งผมได้คัดสรรเมนูพิเศษสำหรับคุณKhaโดยเฉพาะเลยครับ\n\nเมนูทั้งหมดนี้ผมเน้นให้มีปริมาณโปรตีนจากอกไก่ที่เพียงพอต่อการสร้างกล้ามเนื้อ และยังเพิ่มพลังงานจากข้าวกล้องและไขมันดีอย่างเม็ดมะม่วงหิมพานต์ เพื่อให้คุณKhaได้รับแคลอรี่ตามเป้าหมายอย่างมีคุณภาพและอร่อยถูกปากแน่นอนครับ\n\nที่สำคัญที่สุดคือ ทุกเมนูถูกปรับให้เหมาะสมและปลอดภัยสำหรับคุณKhaที่มีโรคประจำตัวเบาหวานและความดันสูง โดยการลดโซเดียมและควบคุมปริมาณน้ำตาล (เลือกใช้สารให้ความหวานแทนน้ำตาล) และเน้นผักและธัญพืชเพื่อให้ได้รับใยอาหารที่จำเป็นครับ คุณKhaสามารถมั่นใจได้เลยว่าจะได้ทานอาหารอร่อย ปลอดภัย และดีต่อสุขภาพครบทั้ง 4 มื้อในวันนี้แน่นอนครับ!|||MENUS|||[{\"name\":\"ข้าวต้มอกไก่เห็ดหอม\",\"calories\":650,\"ingredients\":\"- ข้าวกล้องหุงสุก 1 ถ้วยตวง\\n- อกไก่หั่นชิ้นพอดีคำ 150 กรัม\\n- เห็ดหอมสดหั่น 5-6 ดอก\\n- ขิงซอยละเอียด 30 กรัม\\n- ต้นหอมซอยและผักชีสำหรับโรยหน้า\\n- น้ำซุปไก่ไขมันต่ำ (หรือน้ำเปล่า) 4 ถ้วยตวง\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนโต๊ะ\\n- พริกไทยขาวป่นเล็กน้อย\",\"instructions\":\"1. ต้มน้ำซุปให้เดือด ใส่ข้าวกล้องหุงสุกและอกไก่ลงไปต้มจนไก่สุกและข้าวเริ่มนิ่ม\\n2. ใส่เห็ดหอมและขิงซอยลงไป เคี่ยวต่ออีกประมาณ 5 นาที\\n3. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยขาว คนให้เข้ากัน\\n4. ตักใส่ชาม โรยหน้าด้วยต้นหอมซอยและผักชี เสิร์ฟร้อนๆ เพื่อเป็นมื้อเช้าที่อิ่มสบายท้องของคุณKhaครับ\",\"desc\":\"เมนูย่อยง่ายแต่ให้พลังงานสูง เหมาะสำหรับมื้อเช้า ช่วยควบคุมระดับน้ำตาลและโซเดียมได้ดีครับ\"},{\"name\":\"ไก่ผัดเม็ดมะม่วงหิมพานต์กับข้าวกล้อง\",\"calories\":950,\"ingredients\":\"- อกไก่หั่นชิ้น 200 กรัม\\n- เม็ดมะม่วงหิมพานต์อบ 1\\/2 ถ้วยตวง\\n- ข้าวกล้องหุงสุก 1.5 ถ้วยตวง\\n- พริกหวาน 3 สี หั่นเต๋า 1\\/2 ถ้วย\\n- หอมใหญ่หั่นเสี้ยว 1\\/4 ลูก\\n- แครอทหั่นแว่น 1\\/4 ถ้วย\\n- ต้นหอมหั่นท่อน\\n- พริกแห้งทอด (หั่นหรือไม่หั่นก็ได้) 2-3 เม็ด\\n- น้ำมันรำข้าว 2 ช้อนโต๊ะ\\n- ซีอิ๊วขาวลดโซเดียม 1.5 ช้อนโต๊ะ\\n- น้ำมันหอยลดโซเดียม 1 ช้อนโต๊ะ\\n- น้ำเปล่า 2 ช้อนโต๊ะ\\n- สารให้ความหวานแทนน้ำตาลเล็กน้อย (ตามชอบ)\",\"instructions\":\"1. ตั้งกระทะใส่น้ำมันรำข้าวพอร้อน ใส่พริกแห้งทอดลงผัดให้หอม ตักพริกแห้งออกพักไว้\\n2. ใส่อกไก่ลงไปผัดจนสุกเหลือง\\n3. ใส่หอมใหญ่ แครอท และพริกหวานลงไปผัดพอสุก\\n4. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียม น้ำมันหอยลดโซเดียม และสารให้ความหวานแทนน้ำตาล เติมน้ำเปล่าเล็กน้อย\\n5. ใส่เม็ดมะม่วงหิมพานต์และต้นหอมลงไปผัดคลุกเคล้าให้เข้ากัน\\n6. ตักราดบนข้าวกล้องร้อนๆ โรยด้วยพริกแห้งทอดที่พักไว้ พร้อมเสิร์ฟเป็นมื้อกลางวันที่ให้พลังงานสูงของคุณKhaครับ\",\"desc\":\"เมนูนี้อุดมด้วยโปรตีนจากไก่ และไขมันดีจากเม็ดมะม่วงหิมพานต์ ช่วยเพิ่มน้ำหนักอย่างมีคุณภาพและให้พลังงานสูงครับ\"},{\"name\":\"อกไก่ผัดพริกแกงถั่วฝักยาวกับข้าวกล้อง\",\"calories\":950,\"ingredients\":\"- อกไก่หั่นชิ้น 200 กรัม\\n- ถั่วฝักยาวหั่นท่อน 1.5 ถ้วย\\n- พริกแกงเผ็ดลดโซเดียม 2 ช้อนโต๊ะ\\n- น้ำมันรำข้าว 2 ช้อนโต๊ะ\\n- น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\\n- ใบมะกรูดฉีก 3-4 ใบ\\n- นมสดไขมันต่ำ (หรือกะทิธัญพืช) 1\\/4 ถ้วย\\n- สารให้ความหวานแทนน้ำตาลเล็กน้อย (ตามชอบ)\\n- ข้าวกล้องหุงสุก 1.5 ถ้วยตวง\",\"instructions\":\"1. ตั้งกระทะใส่น้ำมันรำข้าวพอร้อน ใส่พริกแกงเผ็ดลงผัดให้หอมจนแตกมัน\\n2. ใส่อกไก่ลงไปผัดจนสุกทั่ว\\n3. ใส่ถั่วฝักยาวลงไปผัดพอสุก เติมนมสดไขมันต่ำ (หรือกะทิธัญพืช) ลงไปเล็กน้อย\\n4. ปรุงรสด้วยน้ำปลาลดโซเดียม และสารให้ความหวานแทนน้ำตาล ใส่ใบมะกรูดฉีก\\n5. ผัดคลุกเคล้าให้เข้ากันดี ตักราดบนข้าวกล้องร้อนๆ พร้อมเสิร์ฟเป็นมื้อเย็นที่รสชาติจัดจ้านของคุณKhaครับ\",\"desc\":\"เมนูรสชาติเข้มข้นที่ให้โปรตีนสูงและใยอาหารจากถั่วฝักยาว ช่วยเพิ่มพลังงานได้ดีและยังคงคุมโซเดียมและน้ำตาลครับ\"},{\"name\":\"ยำวุ้นเส้นอกไก่ฉีก\",\"calories\":665,\"ingredients\":\"- อกไก่ต้มฉีกเป็นเส้น 150 กรัม\\n- วุ้นเส้นแห้งแช่น้ำให้นิ่มลวกสุก 100 กรัม\\n- แครอทซอย 1\\/4 ถ้วย\\n- ขึ้นฉ่ายหั่นท่อน 1\\/4 ถ้วย\\n- หอมใหญ่ซอยบางๆ 1\\/4 ลูก\\n- ถั่วลิสงคั่วบดหยาบ 1\\/4 ถ้วย\\n- น้ำยำ:\\n  - น้ำปลาลดโซเดียม 1.5 ช้อนโต๊ะ\\n  - น้ำมะนาวคั้นสด 3 ช้อนโต๊ะ\\n  - พริกสดซอย (ตามชอบ)\\n  - สารให้ความหวานแทนน้ำตาล 1 ช้อนชา\",\"instructions\":\"1. เตรียมน้ำยำโดยผสมน้ำปลาลดโซเดียม น้ำมะนาว พริกสดซอย และสารให้ความหวานแทนน้ำตาล คนให้เข้ากัน ชิมรสตามชอบ\\n2. ในชามผสม ใส่วุ้นเส้นลวกสุก อกไก่ฉีก แครอท ขึ้นฉ่าย และหอมใหญ่ซอย\\n3. ราดน้ำยำลงไป คลุกเคล้าให้เข้ากันเบาๆ\\n4. ใส่ถั่วลิสงคั่วบดลงไป คลุกเคล้าอีกครั้ง\\n5. ตักใส่จาน พร้อมเสิร์ฟเป็นมื้อว่างที่อิ่มท้องและดีต่อสุขภาพสำหรับคุณKhaครับ\",\"desc\":\"เมนูนี้สดชื่นและให้โปรตีนสูง พร้อมใยอาหารจากผักและวุ้นเส้น เหมาะเป็นมื้อว่างที่ช่วยเสริมพลังงานเพื่อเพิ่มน้ำหนักครับ\"}]', '2026-03-08 04:30:23'),
(138, 12, 'user', 'ขอคุยกับเจ้าของเว็บหน่อยครับ', '2026-03-09 04:59:39'),
(139, 12, 'ai', 'สวัสดีครับคุณโจจิ! ผมคือเชฟและนักโภชนาการอัจฉริยะที่พร้อมดูแลเรื่องอาหารและสุขภาพให้คุณโจจิอย่างเต็มที่เลยครับ แม้ว่าผมจะไม่ได้เป็นเจ้าของเว็บไซต์โดยตรง แต่ผมเป็นผู้ช่วยอัจฉริยะที่ถูกออกแบบมาเพื่อให้บริการและตอบทุกคำถามของคุณโจจิโดยเฉพาะเลยครับ มีอะไรให้ผมรับใช้ หรืออยากให้ผมช่วยดูแลเรื่องเมนูอาหารเพื่อสุขภาพสำหรับคุณโจจิในวันนี้ไหมครับ?', '2026-03-09 04:59:43'),
(140, 12, 'user', 'กินน้ำโค้กได้มั้ย', '2026-03-09 05:00:16'),
(141, 12, 'ai', 'ครับคุณโจจิ สำหรับคำถามเรื่องการดื่มน้ำโค้กเพื่อสุขภาพและการลดน้ำหนักอย่างยั่งยืนของคุณโจจินั้น ในฐานะเชฟและนักโภชนาการ ผมขอแนะนำว่า น้ำโค้กปกติมีปริมาณน้ำตาลค่อนข้างสูงนะครับ ซึ่งเป็นสาเหตุหนึ่งที่ทำให้ได้รับแคลอรี่เกินความจำเป็นและอาจขัดขวางเป้าหมายการลดน้ำหนักของคุณโจจิได้ครับ การบริโภคน้ำตาลที่มากเกินไปยังส่งผลเสียต่อสุขภาพในระยะยาวอีกด้วยครับ\n\nหากคุณโจจิมีความต้องการดื่มเครื่องดื่มที่มีรสชาติ ผมแนะนำให้ลองพิจารณาเครื่องดื่มทางเลือกที่มีน้ำตาลน้อยหรือไม่เติมน้ำตาลเลย เช่น น้ำเปล่าผสมมะนาวฝาน น้ำโซดาใส่ผลไม้สด หรือโค้กซีโร่/โค้กไลท์ ซึ่งเป็นทางเลือกที่ดีกว่าในแง่ของแคลอรี่ครับ แต่ถึงแม้จะเป็นแบบไม่มีน้ำตาล การดื่มในปริมาณที่พอเหมาะก็เป็นสิ่งสำคัญที่สุดนะครับ เพื่อสุขภาพที่ดีและเป้าหมายการลดน้ำหนักอย่างยั่งยืนของคุณโจจิครับ', '2026-03-09 05:00:20'),
(142, 12, 'user', 'หินเข่าอีทอิหยังดี', '2026-03-09 05:01:33'),
(143, 12, 'ai', 'สวัสดีครับคุณโจจิ! ในฐานะเชฟและนักโภชนาการ ผมยินดีมากครับที่จะช่วยจัดเมนูอร่อยๆ และดีต่อสุขภาพให้คุณโจจิ เพื่อให้การลดน้ำหนักเป็นไปอย่างยั่งยืนตามเป้าหมายที่ตั้งใจไว้เลยนะครับ\n\nสำหรับเมนูในวันนี้ ผมได้คัดสรรอาหารไทยที่หลากหลาย ปรุงง่าย และเน้นโปรตีนกับใยอาหารสูง เพื่อให้คุณโจจิอิ่มสบายท้อง ได้รับสารอาหารครบถ้วน และไม่รู้สึกขาดสารอาหารหรือหิวบ่อยครับ ที่สำคัญคือเมนูเหล่านี้ปลอดภัย 100% สำหรับคุณโจจิที่ไม่มีโรคประจำตัวและไม่มีประวัติแพ้อาหารใดๆ ครับ|||MENUS|||[{\"name\":\"แกงจืดเต้าหู้หมูสับ\",\"calories\":320,\"ingredients\":\"- หมูสับติดมันน้อย 80 กรัม\\n- เต้าหู้ไข่ 1 หลอด\\n- ผักกาดขาว 100 กรัม\\n- แครอทหั่นแว่น 30 กรัม\\n- วุ้นเส้นแช่น้ำ 30 กรัม\\n- น้ำซุปกระดูกหมู\\/ไก่ 2 ถ้วย\\n- ซีอิ๊วขาว 1 ช้อนโต๊ะ\\n- พริกไทยป่นเล็กน้อย\\n- ผักชีสำหรับโรยหน้า 1 ช้อนโต๊ะ\\n- กระเทียมเจียว 1 ช้อนชา (ถ้าชอบ)\",\"instructions\":\"1. ตั้งน้ำซุปให้เดือด ปรุงรสด้วยซีอิ๊วขาว\\n2. ปั้นหมูสับเป็นก้อนพอดีคำ ใส่ลงในน้ำซุปที่เดือดจนสุก\\n3. ใส่แครอทและผักกาดขาวลงไป ต้มจนผักเริ่มนิ่ม\\n4. ใส่เต้าหู้ไข่และวุ้นเส้นลงไป ต้มต่ออีก 2-3 นาที\\n5. ปิดไฟ ตักใส่ชาม โรยหน้าด้วยผักชีและพริกไทยป่น (และกระเทียมเจียวถ้าต้องการ)\",\"desc\":\"เมนูเบาๆ ย่อยง่าย ได้โปรตีนจากหมูและเต้าหู้ พร้อมใยอาหารจากผัก เหมาะสำหรับมื้อเช้าของคุณโจจิ ช่วยให้อิ่มสบายท้องและได้รับพลังงานอย่างพอเหมาะครับ\"},{\"name\":\"ลาบหมู\",\"calories\":380,\"ingredients\":\"- หมูสับติดมันน้อย 150 กรัม\\n- หอมแดงซอย 2 ช้อนโต๊ะ\\n- ต้นหอมซอย 1 ช้อนโต๊ะ\\n- ผักชีฝรั่งซอย 1 ช้อนโต๊ะ\\n- สะระแหน่ 1 กำมือ\\n- ข้าวคั่ว 1.5 ช้อนโต๊ะ\\n- พริกป่น 1 ช้อนชา (ปรับตามชอบ)\\n- น้ำปลา 1.5 ช้อนโต๊ะ\\n- น้ำมะนาว 2 ช้อนโต๊ะ\\n- น้ำตาลทรายปลายช้อนชา (หรือไม่ใส่เลย)\\n- ผักสดสำหรับแกล้ม (กะหล่ำปลี แตงกวา ถั่วฝักยาว)\",\"instructions\":\"1. รวนหมูสับในกระทะโดยไม่ใช้น้ำมันจนสุก (อาจเติมน้ำเปล่าเล็กน้อยเพื่อไม่ให้แห้งติดกระทะ) พักให้เย็น\\n2. ในชามผสม ใส่หมูรวน, ข้าวคั่ว, พริกป่น, น้ำปลา, น้ำมะนาว และน้ำตาล (ถ้าใช้) คลุกเคล้าให้เข้ากัน\\n3. ใส่หอมแดงซอย, ต้นหอมซอย, ผักชีฝรั่งซอย และใบสะระแหน่ คลุกเคล้าเบาๆ อีกครั้ง\\n4. ตักใส่จาน เสิร์ฟพร้อมผักสด\",\"desc\":\"ลาบหมูเป็นเมนูโปรตีนสูง ไขมันต่ำ (หากเลือกหมูไม่ติดมัน) รสจัดจ้านจากสมุนไพรสด ช่วยเพิ่มความสดชื่นและกระตุ้นการเผาผลาญได้ดีสำหรับคุณโจจิครับ แนะนำให้ทานคู่กับข้าวกล้องหรือผักสดเยอะๆ ครับ\"},{\"name\":\"ส้มตำไทย\",\"calories\":180,\"ingredients\":\"- มะละกอดิบสับ 1 ถ้วย\\n- ถั่วฝักยาวหั่น 2 ฝัก\\n- มะเขือเทศสีดา 5 ลูก\\n- พริกขี้หนูสด 1-2 เม็ด (ปรับตามชอบ)\\n- กระเทียม 1 กลีบ\\n- ถั่วลิสงคั่ว 1 ช้อนโต๊ะ\\n- กุ้งแห้ง 1 ช้อนโต๊ะ\\n- น้ำปลา 1 ช้อนโต๊ะ\\n- น้ำมะนาว 2 ช้อนโต๊ะ\\n- น้ำตาลปี๊บ 1 ช้อนชา\",\"instructions\":\"1. โขลกพริกขี้หนูและกระเทียมพอหยาบในครก\\n2. ใส่ถั่วฝักยาวลงไป โขลกพอแตก\\n3. เติมน้ำปลา, น้ำมะนาว, น้ำตาลปี๊บ และกุ้งแห้ง โขลกและคนให้น้ำตาลละลาย\\n4. ใส่มะละกอสับและมะเขือเทศลงไป โขลกและเคล้าเบาๆ ให้เข้ากัน\\n5. ใส่ถั่วลิสงคั่ว โขลกเบาๆ อีกครั้ง ตักใส่จาน เสิร์ฟได้เลย\",\"desc\":\"ส้มตำไทยเป็นเมนูเบาๆ ที่อุดมด้วยใยอาหารและวิตามินซีจากมะละกอและผักต่างๆ ช่วยเรื่องระบบขับถ่ายและให้ความสดชื่น เหมาะสำหรับเป็นของว่างยามบ่ายของคุณโจจิครับ\"},{\"name\":\"ปลากะพงนึ่งมะนาว\",\"calories\":450,\"ingredients\":\"- ปลากะพงสด 1 ตัว (ประมาณ 300-400 กรัม)\\n- กระเทียมสับ 2 ช้อนโต๊ะ\\n- พริกขี้หนูสับ 1-2 ช้อนโต๊ะ (ปรับตามชอบ)\\n- รากผักชีสับ 1 ช้อนโต๊ะ\\n- น้ำปลา 3 ช้อนโต๊ะ\\n- น้ำมะนาว 4 ช้อนโต๊ะ\\n- น้ำซุป 1\\/2 ถ้วย\\n- น้ำตาลทราย 1 ช้อนชา\\n- คื่นช่ายซอย 2 ช้อนโต๊ะ\\n- มะนาวฝานสำหรับตกแต่ง\",\"instructions\":\"1. ล้างปลาให้สะอาด บั้งข้างตัวปลาทั้งสองด้าน\\n2. ผสมน้ำปลา, น้ำมะนาว, น้ำซุป, น้ำตาลทราย, กระเทียมสับ, พริกขี้หนูสับ และรากผักชีสับ ให้เข้ากัน พักไว้\\n3. นำปลาไปนึ่งในลังถึงที่น้ำเดือดจัด ประมาณ 15-20 นาที หรือจนกว่าปลาจะสุก\\n4. เมื่อปลาสุก เทน้ำปรุงที่เตรียมไว้ราดลงบนตัวปลา นึ่งต่ออีก 2-3 นาทีเพื่อให้รสชาติซึมเข้าเนื้อปลา\\n5. ตักปลาพร้อมน้ำปรุงใส่จาน โรยหน้าด้วยคื่นช่ายซอยและมะนาวฝาน เสิร์ฟร้อนๆ\",\"desc\":\"ปลากะพงนึ่งมะนาวเป็นเมนูที่ให้โปรตีนสูง ไขมันต่ำ และได้ประโยชน์จากสมุนไพรต่างๆ ช่วยบำรุงสุขภาพและควบคุมน้ำหนักได้ดีสำหรับคุณโจจิครับ การนึ่งเป็นวิธีปรุงที่ช่วยรักษาสารอาหารได้ดีที่สุดครับ\"}]', '2026-03-09 05:01:57'),
(144, 9, 'user', 'ผมมีวัตถุดิบ: เห็ดหอมแห้ง, แครอท, แซลมอน แนะนำเมนูที่ทำได้หน่อย', '2026-03-09 14:37:46'),
(145, 9, 'ai', 'ครับคุณKha! ในฐานะเชฟและนักโภชนาการ ผมเข้าใจดีเลยว่าคุณKha กำลังต้องการเพิ่มน้ำหนักแบบเร่งด่วน แต่ก็ต้องใส่ใจเรื่องเบาหวานและความดันสูงเป็นพิเศษ ซึ่งเป็นความท้าทายที่ผมยินดีช่วยครับ\n\nสำหรับวัตถุดิบที่คุณKhaมี ทั้งเห็ดหอมแห้ง แครอท และแซลมอน ล้วนเป็นวัตถุดิบคุณภาพดีและมีประโยชน์ต่อสุขภาพของคุณKhaอย่างมากครับ แซลมอนอุดมด้วยโอเมก้า 3 ที่ดีต่อหัวใจ ส่วนเห็ดหอมและแครอทก็เต็มไปด้วยใยอาหารและวิตามิน ผมได้นำวัตถุดิบเหล่านี้มาสร้างสรรค์เป็นเมนูที่หลากหลาย อร่อย ได้พลังงานเพียงพอสำหรับการเพิ่มน้ำหนัก พร้อมทั้งควบคุมโซเดียมและน้ำตาลเพื่อให้เหมาะสมกับภาวะเบาหวานและความดันสูงของคุณKhaครับ เมนูที่จัดให้วันนี้รับรองว่าไม่ซ้ำกับที่เคยทานมาแน่นอนครับ|||MENUS|||[{\"name\":\"ข้าวผัดแซลมอนเห็ดหอมแครอท\",\"calories\":880,\"ingredients\":\"- ข้าวกล้องหุงสุก 200 กรัม\\n- เนื้อปลาแซลมอนหั่นเต๋า 150 กรัม\\n- เห็ดหอมแห้งแช่น้ำหั่นเต๋าเล็ก 30 กรัม\\n- แครอทหั่นเต๋าเล็ก 30 กรัม\\n- ไข่ไก่ 1 ฟอง\\n- กระเทียมสับ 1 ช้อนโต๊ะ\\n- น้ำมันรำข้าว 2 ช้อนโต๊ะ\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนโต๊ะ\\n- พริกไทยป่นเล็กน้อย\\n- ต้นหอมซอยสำหรับโรยหน้า\",\"instructions\":\"1. ตั้งกระทะ ใส่น้ำมันรำข้าวพอร้อน ใส่กระเทียมสับลงเจียวให้หอม\\n2. ใส่เนื้อปลาแซลมอนลงไปผัดพอสุก ตักขึ้นพักไว้\\n3. ตอกไข่ใส่ลงในกระทะ ยีให้พอสุก\\n4. ใส่ข้าวกล้อง เห็ดหอม และแครอทลงไปผัดคลุกเคล้าให้เข้ากัน\\n5. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยป่น ผัดต่อจนเข้ากันดี\\n6. ใส่แซลมอนที่พักไว้กลับลงไปผัดให้เข้ากันอีกครั้ง\\n7. ตักใส่จาน โรยหน้าด้วยต้นหอมซอย พร้อมเสิร์ฟครับ\",\"desc\":\"เมนูเช้าที่อุดมไปด้วยโปรตีนจากแซลมอนและไข่ พร้อมคาร์โบไฮเดรตเชิงซ้อนจากข้าวกล้อง ช่วยให้คุณKhaอิ่มนานและได้รับพลังงานที่สม่ำเสมอ เห็ดหอมและแครอทเพิ่มใยอาหารและวิตามิน การใช้ซีอิ๊วลดโซเดียมช่วยควบคุมความดันได้อย่างดีเยี่ยมครับ\"},{\"name\":\"แกงเขียวหวานไก่\",\"calories\":810,\"ingredients\":\"- สะโพกไก่ไม่มีหนังหั่นชิ้นพอดีคำ 150 กรัม\\n- กะทิธัญพืช หรือ กะทิไขมันต่ำ 150 มิลลิลิตร\\n- พริกแกงเขียวหวาน 1.5 ช้อนโต๊ะ (เลือกแบบลดโซเดียม)\\n- มะเขือเปราะหั่น 100 กรัม\\n- มะเขือพวง 50 กรัม\\n- ใบโหระพา 1\\/2 ถ้วย\\n- พริกชี้ฟ้าหั่นแฉลบ 1 เม็ด\\n- น้ำมันรำข้าว 1 ช้อนโต๊ะ\\n- น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\\n- หญ้าหวาน (แทนน้ำตาล) เล็กน้อย (ถ้าต้องการเพิ่มรสหวาน)\\n- ข้าวกล้องหุงสุก 200 กรัม (สำหรับทานคู่)\",\"instructions\":\"1. ตั้งกระทะ ใส่น้ำมันรำข้าวเล็กน้อย ผัดพริกแกงเขียวหวานจนหอม\\n2. ใส่สะโพกไก่ลงไปผัดจนพอสุก\\n3. เติมกะทิธัญพืช\\/ไขมันต่ำลงไป เคี่ยวจนไก่สุกและน้ำแกงเดือด\\n4. ใส่มะเขือเปราะและมะเขือพวง เคี่ยวต่อจนมะเขือสุกนิ่ม\\n5. ปรุงรสด้วยน้ำปลาลดโซเดียม และหญ้าหวาน (หากใช้) ชิมรสตามชอบ\\n6. ใส่พริกชี้ฟ้าและใบโหระพา คนให้เข้ากัน ปิดไฟ\\n7. ตักเสิร์ฟพร้อมข้าวกล้องหุงสุกครับ\",\"desc\":\"แกงเขียวหวานไก่เป็นเมนูที่ให้พลังงานสูง เหมาะสำหรับการเพิ่มน้ำหนักของคุณKhaครับ การใช้สะโพกไก่ไม่มีหนังช่วยเพิ่มโปรตีนและไขมันดี การเลือกกะทิไขมันต่ำ\\/กะทิธัญพืช พริกแกงลดโซเดียม และการไม่เติมน้ำตาลจะช่วยควบคุมระดับน้ำตาลในเลือดและความดันโลหิตได้เป็นอย่างดีครับ\"},{\"name\":\"แซลมอนย่างซีอิ๊วลดโซเดียมกับผักรวม\",\"calories\":780,\"ingredients\":\"- เนื้อปลาแซลมอน 200 กรัม\\n- ซีอิ๊วลดโซเดียม 2 ช้อนโต๊ะ\\n- น้ำมันงา 1 ช้อนชา\\n- พริกไทยป่นเล็กน้อย\\n- แครอทหั่นแท่ง 50 กรัม\\n- บรอกโคลี 100 กรัม\\n- น้ำมันมะกอกสำหรับย่าง\\/ผัด 1 ช้อนโต๊ะ\\n- ข้าวกล้องหุงสุก 200 กรัม (สำหรับทานคู่)\",\"instructions\":\"1. หมักเนื้อปลาแซลมอนด้วยซีอิ๊วลดโซเดียม น้ำมันงา และพริกไทยป่น พักทิ้งไว้ประมาณ 15-20 นาที\\n2. ตั้งกระทะหรือเตาสำหรับย่างทาน้ำมันมะกอกเล็กน้อย พอร้อนนำปลาแซลมอนลงย่างจนสุกตามชอบ โดยย่างด้านหนังก่อน\\n3. ลวกแครอทและบรอกโคลีในน้ำเดือด หรือผัดกับน้ำมันมะกอกเล็กน้อยจนสุกกรอบ\\n4. จัดปลาแซลมอนย่างใส่จาน เสิร์ฟพร้อมผักรวมลวกหรือผัด และข้าวกล้องหุงสุกครับ\",\"desc\":\"เมนูนี้ดีต่อสุขภาพหัวใจของคุณKhaอย่างมาก ด้วยกรดไขมันโอเมก้า 3 จากแซลมอน และใยอาหารสูงจากแครอทและบรอกโคลี การใช้ซีอิ๊วลดโซเดียมจะช่วยควบคุมโซเดียมได้ดีครับ เป็นอีกมื้อที่ให้โปรตีนและพลังงานสูง เหมาะกับการเพิ่มน้ำหนักอย่างมีคุณภาพ\"},{\"name\":\"ขนมปังโฮลวีทหน้าไข่คนเห็ดหอมแครอท\",\"calories\":420,\"ingredients\":\"- ขนมปังโฮลวีท 2 แผ่น\\n- ไข่ไก่ 2 ฟอง\\n- นมสดไขมันต่ำ 2 ช้อนโต๊ะ\\n- เห็ดหอมแห้งแช่น้ำหั่นเต๋าเล็ก 20 กรัม\\n- แครอทหั่นเต๋าเล็ก 20 กรัม\\n- หอมใหญ่สับละเอียด 1 ช้อนโต๊ะ\\n- น้ำมันรำข้าว 1 ช้อนชา\\n- พริกไทยดำป่นเล็กน้อย\\n- เกลือลดโซเดียมเล็กน้อย\",\"instructions\":\"1. ตอกไข่ใส่ชาม ตีผสมกับนมสดไขมันต่ำและพริกไทยดำป่น พักไว้\\n2. ตั้งกระทะทาน้ำมันรำข้าวเล็กน้อย ใส่หอมใหญ่ เห็ดหอม และแครอทลงไปผัดจนนิ่มและมีกลิ่นหอม\\n3. เทไข่ที่ตีไว้ลงในกระทะ คนเบาๆ ให้ไข่สุกเป็นไข่คน ปรุงรสด้วยเกลือลดโซเดียมเล็กน้อย\\n4. นำขนมปังโฮลวีทไปปิ้งจนเหลืองกรอบ\\n5. ตักไข่คนเห็ดหอมแครอทวางบนขนมปังโฮลวีทปิ้ง พร้อมเสิร์ฟเป็นมื้อว่างแสนอร่อยครับ\",\"desc\":\"เป็นมื้อว่างที่อุดมด้วยโปรตีนจากไข่ และคาร์โบไฮเดรตเชิงซ้อนจากขนมปังโฮลวีท ซึ่งช่วยให้คุณKhaได้รับพลังงานต่อเนื่องไปถึงมื้อถัดไปครับ เห็ดหอมและแครอทยังช่วยเพิ่มใยอาหารและสารอาหารที่จำเป็น เป็นการเพิ่มน้ำหนักที่ใส่ใจสุขภาพและคุมระดับน้ำตาลได้ดีเยี่ยมครับ\"}]', '2026-03-09 14:38:19'),
(146, 9, 'user', 'ขอเมนูคลีนๆหน่อยได้ไหม', '2026-03-09 15:55:08'),
(147, 9, 'ai', 'ครับคุณKha! ในฐานะเชฟและนักโภชนาการ ผมยินดีอย่างยิ่งที่จะรังสรรค์เมนูคลีนๆ ที่ดีต่อสุขภาพและอร่อยถูกใจคุณKha นะครับ สำหรับเป้าหมายลดน้ำหนักมาตรฐานและการดูแลโรคเบาหวานและความดันสูงนั้น สำคัญที่เราต้องเน้นอาหารที่ครบถ้วน ลดโซเดียม ลดน้ำตาล และมีใยอาหารสูงครับ\n\nผมได้คัดสรรและปรับปรุงเมนูมาให้คุณKha เป็นพิเศษ โดยคำนึงถึงความหลากหลายและไม่ซ้ำกับเมนูที่คุณKhaเพิ่งทานไปแน่นอนครับ ทุกเมนูเน้นวัตถุดิบสดใหม่ ปรุงด้วยวิธีที่ดีต่อสุขภาพ และปลอดภัย 100% สำหรับภาวะสุขภาพของคุณKha ครับ\n\nหวังว่าคุณKhaจะมีความสุขกับการทานอาหารเหล่านี้ และเห็นผลลัพธ์ที่ดีตามที่ตั้งใจไว้นะครับ!|||MENUS|||[{\"name\":\"ไข่ตุ๋นทรงเครื่อง\",\"calories\":280,\"ingredients\":\"- ไข่ไก่ 2 ฟอง\\n- อกไก่สับละเอียด 50 กรัม\\n- เห็ดหอมสดหั่นเต๋า 30 กรัม\\n- แครอทหั่นเต๋า 20 กรัม\\n- ต้นหอมซอย 1 ช้อนโต๊ะ\\n- น้ำซุปไก่ไขมันต่ำ 1\\/2 ถ้วย (ประมาณ 120 ml)\\n- ซีอิ๊วขาวลดโซเดียม 1\\/2 ช้อนชา\\n- พริกไทยเล็กน้อย\",\"instructions\":\"1. ตอกไข่ใส่ชาม ตีเบาๆ ให้เข้ากัน\\n2. เติมน้ำซุป ซีอิ๊วขาวลดโซเดียม และพริกไทย คนให้เข้ากัน\\n3. ใส่อกไก่สับ เห็ดหอม และแครอทลงไป คนผสม\\n4. กรองส่วนผสมไข่ผ่านกระชอนตาถี่ เพื่อให้เนื้อเนียนขึ้น\\n5. เทใส่ภาชนะที่ทนความร้อน\\n6. นำไปนึ่งในน้ำเดือดปานกลาง ประมาณ 15-20 นาที หรือจนไข่สุก\\n7. โรยต้นหอมซอยก่อนเสิร์ฟ\",\"desc\":\"เมนูมื้อเช้าโปรตีนสูง ไขมันต่ำ อุดมไปด้วยใยอาหารจากผัก และดีต่อการควบคุมระดับน้ำตาลในเลือด เหมาะสำหรับคุณKha ที่ต้องการควบคุมเบาหวานและความดันครับ\"},{\"name\":\"แกงส้มชะอมกุ้ง\",\"calories\":520,\"ingredients\":\"- กุ้งสดปอกเปลือก 100 กรัม\\n- ไข่เจียวชะอมหั่นชิ้นพอดีคำ 100 กรัม (เจียวด้วยน้ำมันรำข้าวเล็กน้อย)\\n- เนื้อปลาต้มสุก 50 กรัม (สำหรับทำน้ำแกงส้ม)\\n- น้ำพริกแกงส้ม 2 ช้อนโต๊ะ (เลือกแบบลดโซเดียม)\\n- น้ำปลาลดโซเดียม 1-2 ช้อนโต๊ะ\\n- น้ำมะขามเปียก 3 ช้อนโต๊ะ\\n- น้ำตาลปี๊บ 1 ช้อนชา (หรือหญ้าหวาน\\/อิริทริทอลแทน)\\n- น้ำเปล่า\\/น้ำซุป 2-3 ถ้วย\\n- ผักรวมตามชอบ (เช่น หัวไชเท้า, ถั่วฝักยาว, กะหล่ำปลี) 150 กรัม\\n- ข้าวกล้อง 1 ถ้วย\",\"instructions\":\"1. โขลกเนื้อปลาต้มสุกกับน้ำพริกแกงส้มให้เข้ากัน (หรือใช้เครื่องปั่น)\\n2. ต้มน้ำซุปให้เดือด ใส่ส่วนผสมน้ำพริกที่โขลกไว้ลงไป คนให้ละลาย\\n3. ปรุงรสด้วยน้ำปลาลดโซเดียม น้ำมะขามเปียก และน้ำตาลปี๊บ (หรือสารให้ความหวานแทน) ชิมรสให้ออกเปรี้ยว เค็ม หวานเล็กน้อย\\n4. ใส่ผักที่สุกยากลงไปก่อน พอผักเริ่มนิ่ม ใส่ผักที่สุกง่ายตาม\\n5. เมื่อผักสุก ใส่กุ้งสดลงไป รอจนกุ้งสุก (อย่าต้มนานเกินไป)\\n6. ใส่ไข่เจียวชะอมลงไปเป็นลำดับสุดท้าย ตักเสิร์ฟพร้อมข้าวกล้อง\",\"desc\":\"เมนูรสจัดจ้านที่อุดมไปด้วยโปรตีนจากกุ้งและไข่ชะอม มีใยอาหารสูงจากผักนานาชนิด และไขมันต่ำ การเลือกใช้น้ำปลาลดโซเดียมและลดน้ำตาลจะช่วยควบคุมโรคเบาหวานและความดันโลหิตสูงได้ดีครับ\"},{\"name\":\"แกงจืดเต้าหู้หมูสับ\",\"calories\":400,\"ingredients\":\"- เต้าหู้ไข่\\/เต้าหู้อ่อน 1 หลอด\\/ก้อน\\n- หมูสับติดมันน้อย 80 กรัม\\n- วุ้นเส้นแช่น้ำ 30 กรัม\\n- ผักกาดขาว 100 กรัม\\n- แครอทหั่นแว่น 30 กรัม\\n- เห็ดหอมสด\\/แห้งแช่น้ำ 30 กรัม\\n- น้ำซุปไก่ไขมันต่ำ 2 ถ้วย\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนโต๊ะ\\n- พริกไทยป่นเล็กน้อย\\n- ผักชีสำหรับโรยหน้า\\n- ข้าวกล้อง 1 ถ้วย\",\"instructions\":\"1. ต้มน้ำซุปให้เดือด ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทย\\n2. ปั้นหมูสับเป็นก้อนพอดีคำ ใส่ลงในน้ำซุป เมื่อหมูสุกจะลอยขึ้น\\n3. ใส่แครอทและเห็ดหอมลงไปก่อน รอให้เริ่มนิ่ม\\n4. ใส่ผักกาดขาวและวุ้นเส้น เมื่อผักสุกและวุ้นเส้นนิ่ม\\n5. ใส่เต้าหู้ไข่\\/เต้าหู้อ่อนที่หั่นแล้วลงไป เบาๆ เพื่อไม่ให้เละ\\n6. รอให้น้ำซุปเดือดอีกครั้ง ตักใส่ชาม โรยผักชี\\n7. เสิร์ฟพร้อมข้าวกล้อง\",\"desc\":\"เมนูมื้อเย็นเบาๆ ที่ย่อยง่าย อุดมด้วยโปรตีนจากเต้าหู้และหมูสับ มีใยอาหารจากผัก และโซเดียมต่ำ เหมาะสำหรับคุณKha เพื่อรักษาระดับน้ำตาลและความดันโลหิตให้คงที่ครับ\"},{\"name\":\"ผลไม้รวมหั่นเต๋า\",\"calories\":120,\"ingredients\":\"- ฝรั่งหั่นเต๋า 80 กรัม\\n- แอปเปิ้ลหั่นเต๋า 80 กรัม\\n- แก้วมังกรหั่นเต๋า 80 กรัม\",\"instructions\":\"1. ล้างผลไม้ให้สะอาด\\n2. ปอกเปลือกและหั่นเป็นชิ้นพอดีคำ\\n3. จัดใส่จานหรือกล่องแช่เย็นพร้อมรับประทาน\",\"desc\":\"มื้อว่างที่สดชื่น มีวิตามินและใยอาหารสูง ช่วยให้อิ่มนานขึ้นโดยไม่เพิ่มน้ำตาลในเลือดมากเกินไป ควรเลือกผลไม้ที่มีรสไม่หวานจัด เพื่อสุขภาพที่ดีของคุณKha ครับ\"}]', '2026-03-09 15:55:41'),
(148, 9, 'user', 'หิวข้าวอะแก', '2026-03-12 01:47:44'),
(149, 9, 'ai', 'สวัสดีครับคุณKha! ได้เลยครับ เห็นคุณKhaกำลังหิว เชฟคนนี้พร้อมเสิร์ฟเมนูอร่อยๆ และดีต่อสุขภาพให้คุณKhaถึงที่เลยครับ!\n\nสำหรับวันนี้ ผมได้จัดเมนูอาหารไทย 4 มื้อ ที่คิดมาอย่างพิถีพิถันเป็นพิเศษเพื่อคุณKhaเลยนะครับ โดยคำนึงถึงเป้าหมายการรักษาน้ำหนัก และที่สำคัญคือปลอดภัย 100% สำหรับผู้ป่วยเบาหวานและความดันสูง ที่สำคัญคือเมนูเหล่านี้ไม่ซ้ำกับที่เพิ่งทานไปแน่นอนครับ\n\nผมได้เน้นวัตถุดิบที่สดใหม่ ลดน้ำตาลและโซเดียม รวมถึงเลือกใช้โปรตีนไม่ติดมัน และใยอาหารสูง เพื่อช่วยควบคุมระดับน้ำตาลและความดันของคุณKha ให้มีสุขภาพที่ดีอย่างยั่งยืนครับ|||MENUS|||[{\"name\":\"ข้าวต้มปลาอินทรี\",\"calories\":480,\"ingredients\":\"- ข้าวกล้องหุงสุก 1.5 ทัพพี (ประมาณ 150 กรัม)\\n- เนื้อปลาอินทรีสด (ไม่ติดหนัง) 100 กรัม\\n- ขิงซอย 1 ช้อนโต๊ะ\\n- ขึ้นฉ่ายหั่นท่อน 1 ต้น\\n- เห็ดหอมสดหั่น 2 ดอก\\n- น้ำซุปกระดูกปลาหรือกระดูกไก่ (ไม่ปรุงรส) 2 ถ้วย\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนชา\\n- พริกไทยป่นเล็กน้อย\",\"instructions\":\"1. ล้างเนื้อปลาอินทรีให้สะอาด ซับให้แห้ง หั่นเป็นชิ้นพอดีคำ\\n2. ตั้งน้ำซุปให้เดือด ใส่ข้าวกล้องหุงสุกลงไป เคี่ยวด้วยไฟอ่อนประมาณ 5-7 นาที\\n3. ใส่เห็ดหอมและขิงซอยลงไป พอข้าวเริ่มนิ่มและข้นเล็กน้อย\\n4. ใส่เนื้อปลาอินทรีลงไป ลวกให้สุกพอดี ไม่ต้องคนแรง เพื่อไม่ให้ปลาเละ\\n5. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยป่นเล็กน้อย ชิมรสตามชอบ (เน้นจืด)\\n6. ตักใส่ชาม โรยด้วยขึ้นฉ่าย เสิร์ฟร้อนๆ\",\"desc\":\"เมนูยามเช้าที่ย่อยง่าย ให้โปรตีนสูงจากปลาอินทรีซึ่งมีไขมันดี และมีขิงช่วยขับลม ลดน้ำตาลและโซเดียมต่ำ เหมาะสำหรับผู้ป่วยเบาหวานและความดันสูงครับ\"},{\"name\":\"ผัดกะเพราไก่สับอกราดข้าวกล้อง\",\"calories\":680,\"ingredients\":\"- อกไก่สับ 150 กรัม\\n- ข้าวกล้องหุงสุก 2 ทัพพี (ประมาณ 200 กรัม)\\n- ใบกะเพรา 1\\/2 ถ้วย\\n- พริกขี้หนูแดงซอย 2-3 เม็ด (ปรับตามชอบ)\\n- กระเทียมสับ 1 ช้อนโต๊ะ\\n- ถั่วฝักยาวหั่น 1\\/4 ถ้วย\\n- แครอทหั่นเต๋า 1\\/4 ถ้วย\\n- น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนชา\\n- น้ำมันหอยลดโซเดียม 1 ช้อนชา\\n- น้ำมันรำข้าว 1 ช้อนชา\\n- ไข่ดาวน้ำ\\/ไข่ต้ม 1 ฟอง\",\"instructions\":\"1. ตั้งกระทะ ใส่น้ำมันรำข้าวเล็กน้อย พอร้อน ใส่กระเทียมและพริกขี้หนูลงไปผัดให้หอม\\n2. ใส่อกไก่สับลงไป ผัดจนไก่เริ่มสุก\\n3. ใส่ถั่วฝักยาวและแครอทลงไป ผัดให้ผักพอสุก\\n4. ปรุงรสด้วยน้ำปลาลดโซเดียม ซีอิ๊วขาวลดโซเดียม และน้ำมันหอยลดโซเดียม เติมน้ำเปล่าเล็กน้อยเพื่อไม่ให้แห้งเกินไป\\n5. ใส่ใบกะเพราลงไป ผัดอย่างรวดเร็วจนใบกะเพราสลด ปิดไฟ\\n6. ตักราดบนข้าวกล้อง เสิร์ฟพร้อมไข่ดาวน้ำหรือไข่ต้ม (เพื่อลดไขมัน)\",\"desc\":\"เมนูโปรดของใครหลายๆ คน ปรับให้เฮลท์ตี้ขึ้นด้วยอกไก่ไม่ติดมัน ลดโซเดียม และเพิ่มผักใบเขียว พร้อมข้าวกล้องช่วยควบคุมระดับน้ำตาลได้ดี เหมาะสำหรับคุณKhaครับ\"},{\"name\":\"เต้าฮวยฟรุตสลัด (ไม่ใส่น้ำเชื่อม)\",\"calories\":250,\"ingredients\":\"- เต้าฮวยนมสด (ทำเองหรือเลือกแบบหวานน้อย) 1 ถ้วย\\n- ผลไม้รวมหั่นเต๋า 1\\/2 ถ้วย (เช่น สับปะรด ฝรั่ง แก้วมังกร แอปเปิ้ล)\\n- นมสดพร่องมันเนย หรือน้ำเต้าหู้ไม่ใส่น้ำตาล 1\\/4 ถ้วย\",\"instructions\":\"1. หั่นเต้าฮวยเป็นชิ้นพอดีคำ ใส่ลงในถ้วย\\n2. จัดเรียงผลไม้รวมหั่นเต๋าลงไปบนเต้าฮวย\\n3. ราดด้วยนมสดพร่องมันเนย หรือน้ำเต้าหู้ไม่ใส่น้ำตาลเล็กน้อย\\n4. แช่เย็นก่อนเสิร์ฟเพื่อความสดชื่น\",\"desc\":\"ของว่างเย็นๆ ชื่นใจ ให้โปรตีนจากเต้าฮวย วิตามินและใยอาหารจากผลไม้ โดยไม่ใส่น้ำเชื่อม จึงดีต่อผู้ป่วยเบาหวานและช่วยคุมน้ำหนักได้ดีครับ\"},{\"name\":\"กุ้งอบวุ้นเส้น\",\"calories\":600,\"ingredients\":\"- กุ้งขาวสด 150 กรัม (ประมาณ 6-8 ตัว)\\n- วุ้นเส้นแห้ง 50 กรัม\\n- ข้าวกล้องหุงสุก 1 ทัพพี (ประมาณ 100 กรัม)\\n- เห็ดหอมแห้งแช่น้ำให้นิ่ม 3 ดอก (หั่นชิ้น)\\n- ขิงแก่ซอย 2 ช้อนโต๊ะ\\n- รากผักชีทุบ 2 ราก\\n- พริกไทยเม็ดบุบพอแตก 1 ช้อนชา\\n- ซีอิ๊วขาวลดโซเดียม 2 ช้อนโต๊ะ\\n- น้ำมันหอยลดโซเดียม 1 ช้อนโต๊ะ\\n- น้ำมันงา 1 ช้อนชา\\n- ผักขึ้นฉ่ายหั่นท่อน สำหรับโรยหน้า\\n- น้ำเปล่าเล็กน้อย\",\"instructions\":\"1. แช่วุ้นเส้นในน้ำให้นิ่มแล้วสะเด็ดน้ำ พักไว้\\n2. นำกุ้งมาผ่าหลัง ดึงเส้นดำออก พักไว้\\n3. ผสมซีอิ๊วขาวลดโซเดียม, น้ำมันหอยลดโซเดียม, น้ำมันงา และพริกไทยเม็ดบุบเข้าด้วยกัน\\n4. วางรากผักชีทุบและขิงซอยครึ่งหนึ่งลงก้นหม้อหรือกระทะ ใส่เห็ดหอม\\n5. วางวุ้นเส้นที่แช่แล้วลงไป ราดด้วยน้ำซอสที่ผสมไว้ เคล้าให้เข้ากัน\\n6. วางกุ้งสดลงบนวุ้นเส้น โรยขิงที่เหลือ\\n7. เติมน้ำเปล่าเล็กน้อย ปิดฝา อบหรือตั้งไฟอ่อนๆ ประมาณ 10-15 นาที หรือจนกุ้งสุกและวุ้นเส้นดูดน้ำซอสเข้าที่\\n8. ตักใส่จาน โรยด้วยขึ้นฉ่าย เสิร์ฟพร้อมข้าวกล้อง\",\"desc\":\"เมนูยอดนิยมที่อุดมด้วยโปรตีนจากกุ้งและวุ้นเส้นที่ให้พลังงานกำลังดี โดยเน้นการลดโซเดียมและไขมัน และเพิ่มขิงเพื่อสุขภาพที่ดีของคุณKhaครับ\"}]', '2026-03-12 01:48:14'),
(150, 8, 'user', 'เมนูไก่วันนี้', '2026-03-16 15:24:39'),
(151, 8, 'ai', 'ครับคุณsql! ในฐานะเชฟและนักโภชนาการ ผมได้คัดสรรเมนูไก่แสนอร่อยและมีประโยชน์มาให้คุณsql ครบทั้ง 4 มื้อเลยครับ สำหรับเป้าหมายรักษาน้ำหนักให้คงที่ของคุณsql เมนูเหล่านี้เน้นโปรตีนดี มีหลากหลายรสชาติ และแน่นอนว่าปลอดภัย 100% เพราะคุณsql ไม่มีโรคประจำตัวหรืออาหารที่แพ้ครับ ลองดูเมนูที่ผมจัดให้วันนี้ได้เลย!|||MENUS|||[{\"name\":\"ข้าวต้มไก่\",\"calories\":350,\"ingredients\":\"- ข้าวสวยหุงสุก 1 ถ้วย\\n- อกไก่หั่นชิ้น 100 กรัม\\n- น้ำซุปไก่ 3 ถ้วย\\n- ขิงซอย 1 ช้อนโต๊ะ\\n- ขึ้นฉ่ายหั่น 1 ช้อนโต๊ะ\\n- กระเทียมเจียว 1 ช้อนชา\\n- พริกไทยป่น เล็กน้อย\\n- ซีอิ๊วขาว 1 ช้อนชา\",\"instructions\":\"1. ต้มน้ำซุปไก่ให้เดือด ใส่ข้าวสวยลงไป คนเบาๆ\\n2. พอข้าวเริ่มเดือดและนุ่ม ใส่อกไก่หั่นชิ้นลงไป ลวกจนไก่สุก\\n3. ปรุงรสด้วยซีอิ๊วขาวและพริกไทยป่น\\n4. ตักใส่ชาม โรยหน้าด้วยขิงซอย ขึ้นฉ่าย และกระเทียมเจียว\\n5. เสิร์ฟร้อนๆ\",\"desc\":\"เมนูย่อยง่าย เหมาะกับการเริ่มต้นวันใหม่ของคุณsql ครับ ให้พลังงานกำลังดีและโปรตีนจากไก่จะช่วยให้อิ่มสบายท้องไปจนถึงมื้อกลางวันครับ\"},{\"name\":\"ข้าวมันไก่\",\"calories\":580,\"ingredients\":\"- ข้าวมัน 1 จาน (ประมาณ 200 กรัม)\\n- เนื้อไก่ต้มหั่นชิ้น 120 กรัม\\n- น้ำจิ้มข้าวมันไก่ (เต้าเจี้ยว, ขิง, พริก, กระเทียม) 2 ช้อนโต๊ะ\\n- น้ำซุปไก่ 1 ถ้วย\\n- แตงกวาหั่น 3-4 ชิ้น\\n- ผักชี สำหรับโรยหน้า\",\"instructions\":\"1. จัดข้าวมันใส่จาน วางเนื้อไก่ต้มหั่นชิ้นลงบนข้าว\\n2. เสิร์ฟพร้อมน้ำจิ้มข้าวมันไก่ น้ำซุป และแตงกวา\\n3. โรยหน้าด้วยผักชีเล็กน้อยก่อนเสิร์ฟ\",\"desc\":\"ข้าวมันไก่เป็นเมนูยอดนิยมที่ให้พลังงานดีเยี่ยมสำหรับมื้อกลางวันของคุณsql ครับ มีทั้งคาร์โบไฮเดรตและโปรตีนครบถ้วน อิ่มอร่อยได้ไม่น่าเบื่อเลยครับ\"},{\"name\":\"แกงเขียวหวานไก่\",\"calories\":680,\"ingredients\":\"- เนื้ออกไก่หั่นชิ้น 150 กรัม\\n- กะทิ 250 มล.\\n- พริกแกงเขียวหวาน 2 ช้อนโต๊ะ\\n- มะเขือเปราะ 50 กรัม\\n- มะเขือพวง 20 กรัม\\n- ใบโหระพา 1\\/4 ถ้วย\\n- พริกชี้ฟ้าหั่นแฉลบ 1 เม็ด\\n- น้ำปลา 1 ช้อนโต๊ะ\\n- น้ำตาลปี๊บ 1 ช้อนชา\\n- ใบมะกรูด 2 ใบ\\n- ข้าวสวย 1 ถ้วย (180 กรัม)\",\"instructions\":\"1. ผัดพริกแกงเขียวหวานกับหัวกะทิเล็กน้อยจนมีกลิ่นหอม\\n2. ใส่เนื้อไก่ลงไปผัดจนสุก\\n3. เติมกะทิที่เหลือลงไป คนให้เข้ากัน ตั้งไฟให้เดือด\\n4. ใส่มะเขือเปราะ มะเขือพวง และใบมะกรูด ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ\\n5. เคี่ยวจนมะเขือสุก\\n6. ใส่พริกชี้ฟ้าและใบโหระพา คนให้เข้ากัน ปิดไฟ\\n7. ตักแกงเขียวหวานไก่ราดข้าวสวยร้อนๆ\",\"desc\":\"แกงเขียวหวานไก่เป็นเมนูไทยคลาสสิกที่อุดมไปด้วยสมุนไพรและรสชาติจัดจ้านครับคุณsql เหมาะสำหรับมื้อเย็นที่ต้องการความอร่อยและได้พลังงานกำลังดี ทานคู่กับข้าวสวยร้อนๆ อร่อยลงตัวครับ\"},{\"name\":\"อกไก่ย่างสมุนไพร\",\"calories\":280,\"ingredients\":\"- อกไก่ 1 ชิ้น (ประมาณ 150-180 กรัม)\\n- รากผักชีโขลกละเอียด 1 ช้อนชา\\n- กระเทียมโขลกละเอียด 1 ช้อนชา\\n- พริกไทยป่น 1\\/2 ช้อนชา\\n- ซีอิ๊วขาวลดโซเดียม 1 ช้อนโต๊ะ\\n- น้ำมันหอยลดโซเดียม 1 ช้อนโต๊ะ\\n- น้ำจิ้มแจ่ว หรือน้ำจิ้มซีฟู้ดรสไม่จัดมาก (ถ้ามี) 1-2 ช้อนโต๊ะ\",\"instructions\":\"1. ล้างอกไก่ให้สะอาด บั้งเล็กน้อยเพื่อให้เครื่องปรุงซึมเข้าเนื้อ\\n2. ผสมรากผักชี กระเทียม พริกไทย ซีอิ๊วขาว และน้ำมันหอยเข้าด้วยกัน\\n3. นำอกไก่ลงไปหมักกับเครื่องปรุง ทิ้งไว้ในตู้เย็นอย่างน้อย 30 นาที หรือ 1 ชั่วโมง\\n4. นำอกไก่ไปย่างบนกระทะเทฟลอน หรือเตาอบ จนสุกเหลืองทั้งสองด้าน\\n5. หั่นเป็นชิ้นพอดีคำ จัดใส่จาน เสิร์ฟพร้อมน้ำจิ้มแจ่ว (ถ้าต้องการ)\",\"desc\":\"เมนูอกไก่ย่างสมุนไพรเป็นมื้อว่างที่เหมาะสำหรับคุณsql มากๆ ครับ ให้โปรตีนสูง ไขมันต่ำ ช่วยให้อิ่มนานและควบคุมน้ำหนักได้ดีเยี่ยมเลยครับ หากไม่ทานน้ำจิ้มแคลอรี่ก็จะลดลงไปอีกครับ\"}]', '2026-03-16 15:25:02'),
(152, 9, 'user', 'เมนูสุขภาพที่ฉันกินได้', '2026-03-19 04:07:54'),
