INSERT INTO `news` (`id`, `title`, `content`, `image_url`, `created_at`) VALUES
(41, 'บุกจับโกดังอาหารสัตว์เถื่อน ประมวลภาพกันชัด ๆ ยี่ห้อไหนไม่ควรซื้อ เพื่อสุขภาพน้อง - kapook.com', 'สรุปข่าวคือมีการบุกทลายโกดังอาหารสัตว์เถื่อนที่ไม่ได้มาตรฐาน ซึ่งอาจส่งผลเสียต่อสุขภาพของสัตว์เลี้ยง ผู้บริโภคจึงควรระมัดระวังในการเลือกซื้ออาหารโดยตรวจสอบแหล่งที่มาและมาตรฐานความปลอดภัยให้ดีก่อนนำไปให้สัตว์เลี้ยงกิน\n\nเมนูอาหารสุขภาพแนะนำคือ ข้าวต้มไก่ใส่ฟักทองสำหรับสัตว์เลี้ยง เริ่มจากนำอกไก่ไปต้มให้สุกแล้วฉีกเป็นชิ้นเล็กๆ จากนั้นนำฟักทองหั่นเต๋าไปต้มในน้ำซุปไก่จนนิ่ม แล้วนำมาคลุกเคล้ากับข้าวสวยหุงสุกและอกไก่ เมนูนี้เน้นวัตถุดิบจากธรรมชาติ ปราศจากสารกันเสียและสารปรุงแต่งที่เป็นอันตราย ช่วยให้มั่นใจได้ว่าสัตว์เลี้ยงได้รับสารอาหารที่ปลอดภัยและมีประโยชน์ต่อร่างกายแน่นอน', 'https://loremflickr.com/800/500/healthy,food?lock=745399', '2026-03-19 00:00:05'),
(42, 'บุกจับโกดังอาหารสัตว์เถื่อน ประมวลภาพกันชัด ๆ ยี่ห้อไหนไม่ควรซื้อ เพื่อสุขภาพน้อง - kapook.com', 'สรุปข่าว เจ้าหน้าที่เข้าบุกจับโกดังอาหารสัตว์เถื่อนที่ไม่ได้มาตรฐาน ซึ่งอาจส่งผลเสียต่อสุขภาพของสัตว์เลี้ยงโดยตรง เพื่อความปลอดภัยควรตรวจสอบแหล่งที่มาและหลีกเลี่ยงยี่ห้อที่ไม่มีมาตรฐานรับรอง\n\nเมนูแนะนำเพื่อสุขภาพสัตว์เลี้ยง คือ อกไก่ต้มฟักทอง โดยนำอกไก่ไปต้มให้สุกแล้วฉีกเป็นชิ้นเล็กๆ ผสมกับฟักทองนึ่งที่บดละเอียด เมนูนี้ให้โปรตีนสูงและวิตามินจากฟักทอง ช่วยเรื่องระบบขับถ่ายและเป็นอาหารที่ปลอดภัยเพราะทำเองได้ง่ายไม่ต้องกังวลเรื่องสารปนเปื้อนจากอาหารสำเร็จรูปที่ไม่ได้มาตรฐาน', 'https://loremflickr.com/800/500/healthy,food?lock=662535', '2026-03-20 00:00:03'),
(43, 'บุกจับโกดังอาหารสัตว์เถื่อน ประมวลภาพกันชัด ๆ ยี่ห้อไหนไม่ควรซื้อ เพื่อสุขภาพน้อง - kapook.com', 'สรุปข่าวจากกรณีเจ้าหน้าที่บุกทลายโกดังอาหารสัตว์เถื่อนที่ไม่ได้มาตรฐานนั้น เตือนให้ผู้เลี้ยงควรตรวจสอบแหล่งที่มาและคุณภาพของอาหารสัตว์อย่างละเอียดก่อนซื้อ เพราะสินค้าปลอมแปลงหรือไม่ได้มาตรฐานอาจมีสารปนเปื้อนหรือคุณค่าทางโภชนาการไม่เพียงพอ ซึ่งส่งผลเสียโดยตรงต่อสุขภาพและอายุขัยของสัตว์เลี้ยงในระยะยาว\n\nเมนูแนะนำสำหรับสัตว์เลี้ยงเพื่อความปลอดภัยคือ อกไก่ต้มฟักทองบด\n\nวิธีทำคือ นำอกไก่ลอกหนังต้มจนสุกแล้วฉีกเป็นเส้นเล็กๆ จากนั้นนำฟักทองไปนึ่งจนนิ่มแล้วบดให้ละเอียด นำทั้งสองอย่างมาคลุกเคล้าให้เข้ากัน เมนูนี้ให้โปรตีนคุณภาพดีจากอกไก่และใยอาหารรวมถึงวิตามินเอจากฟักทองซึ่งช่วยระบบขับถ่ายและบำรุงสายตา โดยไม่มีสารปรุงแต่งหรือสารกันบูดเหมือนอาหารสัตว์แปรรูปทั่วไป ทำให้มั่นใจได้ว่าสัตว์เลี้ยงจะได้รับสารอาหารที่ปลอดภัยและดีต่อสุขภาพอย่างแท้จริง', 'https://loremflickr.com/800/500/healthy,food?lock=428191', '2026-03-21 00:00:05'),
(44, 'NOLA ส่งโปรดักส์ใหม่ ‘โนล่า มานูก้า ฮันนี่ (MGO400+)’ เครื่องดื่มเพื่อสุขภาพ ลุยตลาดซุปเปอร์ฟู้ดส์..เทรนด์อาหารมาแรงแห่งปี - Marketeer Online', 'สรุปข่าว NOLA เปิดตัวเครื่องดื่มสุขภาพใหม่ โนล่า มานูก้า ฮันนี่ ที่ใช้ความเข้มข้นระดับ MGO400 เพื่อเจาะกลุ่มผู้บริโภคที่ใส่ใจสุขภาพและตอบรับเทรนด์ซุปเปอร์ฟู้ดส์ที่กำลังเติบโตอย่างต่อเนื่องในปัจจุบัน\n\nเมนูแนะนำ กรีกโยเกิร์ตหน้าผลไม้สดและน้ำผึ้งมานูก้า\n\nวิธีทำ\nตักกรีกโยเกิร์ตรสธรรมชาติใส่ถ้วย โรยหน้าด้วยเบอร์รี่สด เช่น สตรอว์เบอร์รีหรือบลูเบอร์รี เพิ่มถั่วอัลมอนด์อบเพื่อสัมผัสกรุบกรอบ จากนั้นราดด้วยน้ำผึ้งมานูก้าเพียงหนึ่งช้อนชาเพื่อเพิ่มความหวานธรรมชาติและคุณประโยชน์จากสารต้านอนุมูลอิสระ เมนูนี้ให้โปรตีนสูงและสารอาหารครบถ้วนเหมาะสำหรับเป็นมื้อเช้าหรือของว่างเพื่อสุขภาพครับ', 'https://loremflickr.com/800/500/healthy,food?lock=561889', '2026-03-22 00:00:04'),
(45, 'บุกจับโกดังอาหารสัตว์เถื่อน ประมวลภาพกันชัด ๆ ยี่ห้อไหนไม่ควรซื้อ เพื่อสุขภาพน้อง - kapook.com', 'สรุปข่าว\nเจ้าหน้าที่เข้าทลายแหล่งผลิตและจัดเก็บอาหารสัตว์ที่ไม่ได้มาตรฐานและผิดกฎหมาย เพื่อป้องกันไม่ให้ผลิตภัณฑ์เหล่านี้เข้าสู่ตลาดและเป็นอันตรายต่อสุขภาพของสัตว์เลี้ยง ผู้บริโภคควรตรวจสอบแหล่งที่มาของอาหารสัตว์อย่างละเอียดก่อนเลือกซื้อทุกครั้ง\n\nเมนูแนะนำเพื่อสุขภาพสัตว์เลี้ยง\nเมนู ไก่ต้มผักรวมมิตรสำหรับสัตว์เลี้ยง\n\nวิธีทำ\nเตรียมอกไก่ลอกหนังและมันออก นำไปต้มจนสุกแล้วฉีกเป็นชิ้นเล็กๆ จากนั้นนำแครอทและฟักทองหั่นเต๋าไปนึ่งจนนิ่ม นำส่วนผสมทั้งหมดมาคลุกเคล้ารวมกัน เมนูนี้ให้โปรตีนคุณภาพดีและวิตามินจากผักโดยไม่มีสารปรุงแต่งหรือสารกันเสียที่เป็นอันตรายต่อสัตว์เลี้ยง ซึ่งเป็นทางเลือกที่ปลอดภัยกว่าการเสี่ยงใช้อาหารสำเร็จรูปที่ไม่ได้มาตรฐานครับ', 'https://loremflickr.com/800/500/healthy,food?lock=492346', '2026-03-23 00:00:04'),
(46, 'ชุมชนโคโดเปิดตัวเทศกาลกีฬาเพื่อสุขภาพประจำปี 2026 - Vietnam.vn', 'สรุปข่าว ชุมชนโคโดจัดเทศกาลกีฬาเพื่อสุขภาพประจำปี 2026 เพื่อส่งเสริมให้คนในชุมชนหันมาออกกำลังกายและใส่ใจสุขภาพมากขึ้น โดยเน้นการสร้างวิถีชีวิตที่แข็งแรงและยั่งยืน\n\nเมนูสุขภาพแนะนำ สลัดอกไก่ม้วนผักรวม สำหรับเมนูนี้เหมาะมากสำหรับผู้ที่รักการออกกำลังกายเพราะให้โปรตีนสูงจากอกไก่ที่ช่วยซ่อมแซมกล้ามเนื้อ และได้รับวิตามินจากผักหลากหลายชนิด เช่น แครอท แตงกวา และผักสลัด ซึ่งมีกากใยสูงช่วยในเรื่องระบบขับถ่ายและการเผาผลาญ พลังงานไม่สูงจนเกินไป เหมาะสำหรับรับประทานหลังจากการออกกำลังกายในเทศกาลกีฬาเพื่อฟื้นฟูร่างกายได้เป็นอย่างดี', 'https://loremflickr.com/800/500/healthy,food?lock=615926', '2026-03-24 00:00:07'),
(47, 'Betagro Ventures เปิดตัว ‘blüüm’ แบรนด์อาหารเสริมวิตามินน้องใหม่ ชูนวัตกรรมโภชนาการ - ประชาชาติธุรกิจ', 'สรุปข่าว Betagro Ventures เปิดตัวแบรนด์อาหารเสริมวิตามินน้องใหม่ภายใต้ชื่อ blüüm โดยเน้นการใช้นวัตกรรมทางโภชนาการที่ทันสมัยเพื่อตอบโจทย์สุขภาพของผู้บริโภคยุคใหม่ที่ต้องการการดูแลตัวเองอย่างเฉพาะเจาะจง\n\nเมนูอาหารสุขภาพที่แนะนำ สลัดอกไก่นุ่มคีนัวอโวคาโด\n\nวัตถุดิบและวิธีทำ\nใช้เนื้ออกไก่ต้มสุกหั่นชิ้นพอดีคำ คลุกเคล้ากับคีนัวหุงสุก ผักสลัดสดตามชอบ อโวคาโดหั่นเต๋า และถั่วแระญี่ปุ่น ราดด้วยน้ำสลัดน้ำมันมะกอกผสมน้ำมะนาวและเกลือเล็กน้อย เมนูนี้ให้โปรตีนคุณภาพสูงจากอกไก่ ไขมันดีจากอโวคาโด และไฟเบอร์จากคีนัวและผัก ซึ่งสอดคล้องกับแนวคิดการดูแลสุขภาพด้วยโภชนาการที่สมดุลและมีประโยชน์ต่อร่างกายตามวิถีใหม่ของการดูแลตัวเอง', 'https://loremflickr.com/800/500/healthy,food?lock=789110', '2026-03-25 00:01:59');
INSERT INTO `recipes` (`id`, `title`, `description`, `ingredients`, `instructions`, `servings`, `image`, `created_by`, `created_at`, `calories`, `view_count`) VALUES
(1, 'ผัดกะเพราหมูสับ', 'เมนูยอดฮิต รสจัดจ้าน หอมกลิ่นใบกะเพรา ทำง่ายและรวดเร็ว', NULL, '1. โขลกพริกกับกระเทียมให้พอหยาบ \r\n2. ตั้งกระทะใส่น้ำมัน นำพริกกระเทียมลงผัดจนหอม \r\n3. ใส่หมูสับลงไปผัดจนสุก \r\n4. ปรุงรสด้วยซอสหอยนางรม น้ำปลา ซีอิ๊วดำ และน้ำตาล ผัดให้เข้ากัน \r\n5. ปิดไฟ ใส่ใบกะเพราแล้วผัดเร็วๆ ให้ใบกะเพราสลด ตักเสิร์ฟ', 1, '1772986947_c07747088f182ba6cfabe8be6724229e.png.avif', NULL, '2026-03-08 14:35:01', 580, 2),
(2, 'ต้มยำกุ้งน้ำข้น', 'ซุปต้มยำรสชาติเข้มข้น เปรี้ยวเผ็ดกำลังดี หอมเครื่องต้มยำ', NULL, '1. ต้มน้ำซุปให้เดือด ใส่ข่า ตะไคร้ ใบมะกรูดที่ฉีกไว้ \r\n2. ใส่เห็ดฟางต้มจนสุก \r\n3. ใส่กุ้งสด พอกุ้งเริ่มเปลี่ยนสีให้ใส่น้ำพริกเผาและนมข้นจืด \r\n4. ปิดไฟ ปรุงรสด้วยน้ำปลา น้ำมะนาว และพริกบุบ \r\n5. โรยผักชี พร้อมเสิร์ฟ', 2, '1772991032_hq720.jpg', NULL, '2026-03-08 14:35:01', 320, 2),
(3, 'แกงเขียวหวานไก่', 'แกงกะทิสีเขียวสวย หอมพริกแกง รสชาติหวานมัน', NULL, '1. ตั้งกะทิ 1 ถ้วยในกระทะให้แตกมัน \r\n2. ใส่พริกแกงเขียวหวานลงผัดให้หอม \r\n3. ใส่เนื้อไก่ลงไปผัดจนสุก \r\n4. เติมกะทิที่เหลือ ต้มจนเดือด \r\n5. ใส่มะเขือเปราะและมะเขือพวง ต้มจนสุก \r\n6. ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ \r\n7. ใส่พริกชี้ฟ้าและใบโหระพา ปิดไฟ ตักเสิร์ฟ', 2, '1772991721_9f824e56-6919-46c9-910b-d962b508260e.jpg', NULL, '2026-03-08 14:35:01', 400, 7),
(4, 'ผัดไทยกุ้งสด', 'ผัดไทยกุ้งสดเป็นเมนูจานเดียวที่ครบครัน มีทั้งคาร์โบไฮเดรต โปรตีนจากกุ้งและไข่ และใยอาหารจากถั่วงอก คุณวิกรมจะได้รับสารอาหารที่จำเป็นอย่างสมดุลและอร่อยถูกใจแน่นอนครับ', NULL, '1. ตั้งกระทะใส่น้ำมัน ผัดเต้าหู้ ไชโป๊ว และกุ้งแห้งให้หอม \r\n2. ใส่กุ้งสดลงไปผัดพอสุก ตอกไข่ใส่ลงไปยีให้แตก \r\n3. ใส่เส้นจันท์และน้ำซอสมะขาม ผัดจนเส้นนิ่ม \r\n4. ใส่ถั่วงอกและใบกุยช่าย ผัดให้เข้ากัน \r\n5. ตักใส่จาน โรยถั่วลิสงคั่ว', 1, '1773065803_ผัดไทยกุ้งสด.jpg', NULL, '2026-03-08 14:35:01', 550, 4),
(5, 'ต้มข่าไก่', 'ต้มข่าไก่กะทิสด หอมละมุนกลิ่นข่าและสมุนไพร เนื้อไก่นุ่ม เห็ดฟางชิ้นโต รสชาติเปรี้ยว เค็ม หวาน กลมกล่อมซดคล่องคอ', NULL, '1. ต้มกะทิด้วยไฟอ่อน ใส่ข่า ตะไคร้ ใบมะกรูด \r\n2. พอเดือดใส่เนื้อไก่ลงไปต้มจนสุก \r\n3. ใส่เห็ดนางฟ้า รอจนเดือดอีกครั้ง \r\n4. ปิดไฟ ปรุงรสด้วยน้ำปลา น้ำมะนาว และพริกขี้หนู \r\n5. โรยหน้าด้วยผักชี พร้อมเสิร์ฟ', 2, '1773066156_ต้มข่าไก่.jpg', NULL, '2026-03-08 14:35:01', 380, 1),
(6, 'ส้มตำไทย', 'ส้มตำไทยรสจัดจ้าน เส้นมะละกอกรอบ คลุกเคล้ากุ้งแห้ง ถั่วลิสงคั่ว และมะเขือเทศ ปรุงรสเปรี้ยว หวาน เค็ม เผ็ดลงตัว', NULL, '1. โขลกกระเทียมและพริกขี้หนูพอหยาบ \r\n2. ใส่ถั่วฝักยาวลงไปตำเบาๆ \r\n3. ปรุงรสด้วยน้ำตาลปี๊บ น้ำปลา และน้ำมะนาว คนให้เข้ากัน \r\n4. ใส่มะเขือเทศ กุ้งแห้ง และถั่วลิสง \r\n5. ใส่มะละกอสับลงไป คลุกเคล้าให้เข้ากัน ตักเสิร์ฟ', 1, '1773066400_ส้มตำไทย.jpg', NULL, '2026-03-08 14:35:01', 120, 2),
(7, 'ยำวุ้นเส้นหมูสับ', 'ยำวุ้นเส้นเหนียวนุ่ม คลุกเคล้าหมูสับรวนสุก หอมแดง มะเขือเทศ และขึ้นฉ่าย ปรุงรสน้ำยำเปรี้ยวเผ็ดจัดจ้าน แซ่บถึงใจ', NULL, '1. ลวกวุ้นเส้นและรวนหมูสับให้สุก พักไว้ \r\n2. ผสมพริก น้ำปลา น้ำมะนาว และน้ำตาล คนให้เข้ากันเป็นน้ำยำ \r\n3. นำวุ้นเส้น หมูสับ หอมใหญ่ และมะเขือเทศ ใส่ชามผสม \r\n4. ราดน้ำยำลงไป คลุกเคล้าให้เข้ากัน โรยขึ้นฉ่าย พร้อมเสิร์ฟ', 1, '1773071435_ยำวุ้นเส้นหมูสับ.jpg', NULL, '2026-03-08 14:35:01', 250, 5),
(8, 'ไก่ผัดเม็ดมะม่วงหิมพานต์', 'ไก่ทอดชิ้นโตผัดคลุกเคล้าซอสน้ำพริกเผารสกลมกล่อม หอมมันด้วยเม็ดมะม่วงหิมพานต์คั่ว กรุบกรอบเข้ากันอย่างลงตัว', NULL, '1. คลุกไก่กับแป้งทอดกรอบบางๆ แล้วนำไปทอดจนเหลืองกรอบ พักไว้ \r\n2. ตั้งกระทะใส่น้ำมันนิดหน่อย ผัดหอมใหญ่จนใส \r\n3. ใส่น้ำพริกเผา ซอสหอยนางรม ซีอิ๊วขาว และน้ำตาล ผัดให้เข้ากัน \r\n4. ใส่ไก่ทอด เม็ดมะม่วง ต้นหอม และพริกแห้ง ผัดให้เข้ากัน ตักเสิร์ฟ', 2, '1773071075_ไก่ผัดเม็ดมะม่วงหิมพานต์.jpg', NULL, '2026-03-08 14:35:01', 450, 2),
(9, 'ข้าวผัดหมู', 'ข้าวผัดหมูทรงเครื่อง ข้าวผัดเม็ดร่วนหอมกลิ่นคั่วกระทะ คลุกเคล้าไข่ไก่และเนื้อหมูนุ่ม รสชาติกลมกล่อม', NULL, '1. ตั้งกระทะผัดกระเทียมให้หอม ใส่หมูลงผัดจนสุก \r\n2. ตอกไข่ลงไป ยีให้แตกและสุก \r\n3. ใส่ข้าวสวย หอมใหญ่ มะเขือเทศ \r\n4. ปรุงรสด้วยซีอิ๊วขาว น้ำมันหอย และน้ำตาล ผัดด้วยไฟแรงให้เข้ากัน \r\n5. โรยต้นหอม ผัดอีกรอบแล้วตักเสิร์ฟ', 1, '1773070713_ข้าวผัดหมู.jpg', NULL, '2026-03-08 14:35:01', 520, 3),
(10, 'หมูทอดกระเทียมพริกไทย', 'หมูชิ้นหมักกระเทียมพริกไทย ทอดจนสุกนุ่มฉ่ำ หอมกลิ่นกระเทียมเจียวกรอบ รสชาติเค็มหวานกลมกล่อม', NULL, '1. โขลกรากผักชี กระเทียม และพริกไทยให้ละเอียด \r\n2. นำไปหมักกับเนื้อหมู ซอสหอยนางรม ซีอิ๊วขาว และน้ำตาล ทิ้งไว้ 15 นาที \r\n3. ตั้งกระทะใส่น้ำมัน นำกระเทียมสับลงเจียวให้เหลืองกรอบ ตักขึ้น \r\n4. นำหมูลงทอดในน้ำมันเดิมจนสุก \r\n5. ตักใส่จาน โรยกระเทียมเจียว', 1, '1773070314_หมูทอดกระเทียมพริกไทย.jpg', NULL, '2026-03-08 14:35:01', 450, 2),
(11, 'แกงส้มชะอมกุ้ง', 'เป็นแกงไทยรสจัดจ้านที่ผสมผสานความหอมนัวของไข่ทอดชะอมเข้ากับความเปรี้ยวอมหวานของน้ำแกงส้มและกุ้งสดครับ', NULL, '1. ตีไข่ผสมชะอม นำไปทอดจนสุก หั่นเป็นชิ้นพอดีคำ \r\n2. ต้มน้ำให้เดือด ละลายพริกแกงส้มลงไป \r\n3. ปรุงรสด้วยน้ำมะขามเปียก น้ำปลา และน้ำตาลปี๊บ ชิมรสตามชอบ \r\n4. ใส่กุ้งสดลงไป พอเดือดกุ้งสุก ให้ใส่ชะอมทอดลงไป ปิดไฟ', 2, '1773066824_แกงส้มชะอมกุ้ง.jpg', NULL, '2026-03-08 14:35:01', 280, 3),
(12, 'มัสมั่นไก่', 'ส่วนผสม: เนื้อสะโพกไก่ 300 กรัม, พริกแกงมัสมั่น 3 ช้อนโต๊ะ, กะทิ 2 ถ้วย, มันฝรั่งหั่นเต๋าใหญ่ 1 หัว, หอมใหญ่หั่น 1/2 หัว, ถั่วลิสงคั่ว 2 ช้อนโต๊ะ, น้ำมะขามเปียก 2 ช้อนโต๊ะ, น้ำปลา 2 ช้อนโต๊ะ, น้ำตาลปี๊บ 2 ช้อนโต๊ะ', NULL, '1. เคี่ยวกะทิครึ่งหนึ่งในกระทะให้แตกมัน ใส่พริกแกงมัสมั่นลงผัดให้หอม \r\n2. ใส่เนื้อไก่ลงผัดให้ตึง \r\n3. เติมกะทิที่เหลือ มันฝรั่ง หอมใหญ่ และถั่วลิสง เคี่ยวไฟอ่อน 20 นาที \r\n4. ปรุงรสด้วยน้ำมะขามเปียก น้ำปลา น้ำตาลปี๊บ \r\n5. เคี่ยวต่อจนมันฝรั่งนิ่มและน้ำแกงข้น', 2, '1773066536_มัสมั่นไก่2.jpg', NULL, '2026-03-08 14:35:01', 550, 2),
(13, 'ลาบหมู', 'ลาบหมูสับร่วน คลุกเคล้าเครื่องลาบ ข้าวคั่ว พริกป่น หอมแดง รสชาติแซ่บจัดจ้าน หอมกลิ่นมะนาวแท้และใบสะระแหน่', NULL, '1. รวนหมูสับในหม้อพร้อมน้ำเปล่าเล็กน้อยจนหมูสุก \r\n2. ยกลงจากเตา ใส่ตับต้ม ข้าวคั่ว และพริกป่น \r\n3. ปรุงรสด้วยน้ำปลาและน้ำมะนาว คลุกเคล้าให้เข้ากัน \r\n4. ใส่หอมแดง ต้นหอม ผักชีฝรั่ง และใบสะระแหน่ คลุกเบาๆ ตักเสิร์ฟ', 1, '1773064759_ลาบหมู.jpg', NULL, '2026-03-08 14:35:01', 220, 13),
(14, 'แกงจืดเต้าหู้หมูสับ', 'แกงจืดน้ำซุปใส หอมหวานกระดูกหมูและผักกาดขาว เสิร์ฟพร้อมหมูสับก้อนปรุงรส เต้าหู้ไข่นุ่มละมุน และโรยกระเทียมเจียวหอมกรุ่น', NULL, '1. หมักหมูสับกับซีอิ๊วขาวและรากผักชีกระเทียมพริกไทยเล็กน้อย \r\n2. ต้มน้ำซุปให้เดือด ใส่หมูสับปั้นเป็นก้อน \r\n3. หมูสุกให้ใส่ผักกาดขาวลงไปต้มจนนิ่ม \r\n4. ปรุงรสด้วยซีอิ๊วขาว ใส่เต้าหู้ไข่ \r\n5. ปิดไฟ โรยด้วยต้นหอมผักชีและพริกไทยป่น', 1, '1773064432_แกงจืดเต้าหู้หมูสับ.jpg', NULL, '2026-03-08 14:35:01', 150, 3),
(15, 'พะแนงหมู', 'พะแนงหมูเนื้อนุ่ม เคี่ยวในน้ำพริกแกงและกะทิเข้มข้น หอมกลิ่นถั่วลิสงคั่วและใบมะกรูดซอย รสชาติหวานนำ หอมมันกลมกล่อม', NULL, '1. เคี่ยวกะทิส่วนหัวให้แตกมัน ใส่พริกแกงลงผัดจนหอม \r\n2. ใส่เนื้อหมูลงไปผัดจนสุก 3. เติมหางกะทิที่เหลือ เคี่ยวไฟอ่อนจนน้ำข้น \r\n4. ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ \r\n5. ใส่ใบมะกรูดซอยและพริกชี้ฟ้า ปิดไฟ ตักเสิร์ฟ', 2, '1773064173_พะแนงหมู.jpg', NULL, '2026-03-08 14:35:01', 450, 0),
(16, 'ข้าวมันไก่', 'ข้าวมันหอมกรุ่นหุงด้วยน้ำซุปไก่ เสิร์ฟพร้อมเนื้อไก่ต้มชิ้นโตเนื้อนุ่มฉ่ำ ทานคู่กับน้ำจิ้มเต้าเจี้ยวขิงรสเด็ดและน้ำซุปซดคล่องคอ', NULL, '1. เจียวมันไก่ในกระทะจนได้น้ำมัน ใส่กระเทียมและขิงลงเจียวให้หอม \r\n2. นำข้าวสารลงผัดพอเข้ากัน \r\n3. ตักข้าวใส่หม้อหุงข้าว เติมน้ำซุปไก่ หุงจนสุก \r\n4. ผสมส่วนผสมน้ำจิ้มเข้าด้วยกัน \r\n5. หั่นไก่ต้มวางบนข้าวมัน เสิร์ฟพร้อมแตงกวาและน้ำจิ้ม', 2, '1773063621_ข้าวมันไก่.jpg', NULL, '2026-03-08 14:35:01', 600, 8),
(17, 'ข้าวขาหมู', 'ข้าวขาหมูเนื้อหนังฉ่ำๆ ตุ๋นจนเปื่อยละลายในปาก! ราดน้ำพะโล้หอมเครื่องเทศลงบนข้าวสวยร้อนๆ กินคู่กับไข่ต้มและพริกน้ำส้มแซ่บๆ อร่อยนัวจนต้องเบิ้ลข้าว!', NULL, '1. ทอดขาหมูพอหนังตึง พักไว้ \r\n2. ผัดกระเทียม รากผักชี พริกไทย โป๊ยกั๊ก อบเชย ผงพะโล้ให้หอม \r\n3. ใส่น้ำและขาหมูลงหม้อ ปรุงรสด้วยซีอิ๊วดำ ซีอิ๊วขาว น้ำตาลปี๊บ \r\n4. ตุ๋นไฟอ่อน 2-3 ชั่วโมงจนเปื่อย \r\n5. ใส่ไข่ต้ม ตุ๋นต่ออีก 30 นาที เสิร์ฟกับข้าวสวย', 4, '1773063243_ข้าวขาหมู.jpg', NULL, '2026-03-08 14:35:01', 650, 1),
(18, 'ราดหน้าเส้นใหญ่หมู', 'ราดหน้าเส้นใหญ่หมูนุ่มเด้ง! เส้นคั่วกระทะมาหอมๆ ราดด้วยน้ำราดหน้าเหนียวข้นกำลังดี รสชาติกลมกล่อม ซดร้อนๆ คล่องคอ เติมพริกน้ำส้มอีกนิด อร่อยซู้ดเส้นเพลินจนหมดจาน!', NULL, '1. ผัดเส้นใหญ่กับซีอิ๊วดำเล็กน้อยให้หอมกลิ่นกระทะ พักไว้ \r\n2. ตั้งกระทะเจียวกระเทียมและเต้าเจี้ยวให้หอม ใส่หมูลงผัด \r\n3. ใส่น้ำซุป พอเดือดใส่คะน้า \r\n4. ปรุงรสด้วยน้ำมันหอย ซีอิ๊วขาว น้ำตาล \r\n5. ค่อยๆ เทแป้งมันละลายน้ำลงไป คนจนน้ำซุปเหนียวข้น ราดลงบนเส้น', 1, '1773062781_ราดหน้าเส้นใหญ่หมู.jpg', NULL, '2026-03-08 14:35:01', 450, 1),
(19, 'ผัดซีอิ๊วเส้นใหญ่หมู', 'ผัดซีอิ๊วเส้นใหญ่หมูนุ่มๆ มาแล้ว! เส้นผัดมาหอมกลิ่นกระทะแบบสุดๆ คลุกเคล้าซีอิ๊วหวานกำลังดี กินคู่กับยอดคะน้ากรอบๆ เหยาะพริกน้ำส้มตัดเลี่ยนอีกนิด อร่อยฟินจนเกลี้ยงจาน!', NULL, '1. ตั้งกระทะเจียวกระเทียมให้หอม ใส่หมูลงผัดพอสุก \r\n2. ตอกไข่ลงไป ยีให้สุก 3. ใส่เส้นใหญ่และคะน้า \r\n4. ปรุงรสด้วยซีอิ๊วขาว ซีอิ๊วดำ น้ำมันหอย และน้ำตาล \r\n5. ผัดด้วยไฟแรงให้เส้นมีกลิ่นหอมกระทะเข้ากันดี ตักเสิร์ฟ', 1, '1773062519_ผัดซีอิ๊วเส้นใหญ่หมู.jpg', NULL, '2026-03-08 14:35:01', 500, 0),
(20, 'หอยทอด', 'หอยทอดกระทะร้อน แป้งกรอบสนั่น หอยสดหวานฉ่ำเต็มคำ! ราดน้ำจิ้มซอสพริกชุ่มๆ กินคู่กับถั่วงอกกรอบๆ อร่อยเพลินจนหยุดไม่อยู่ สายสตรีทฟู้ดต้องโดน!', NULL, '1. ผสมแป้งทั้งสองชนิดกับน้ำเย็นและซีอิ๊วขาว คนให้เข้ากัน ใส่หอยและต้นหอม \r\n2. ตั้งกระทะแบนใส่น้ำมัน รอให้ร้อนจัด เทแป้งลงไปทอดให้แผ่กระจาย \r\n3. ตอกไข่ใส่ลงไปเกลี่ยให้ทั่ว ทอดจนกรอบ \r\n4. กลับด้านให้กรอบทั้งสองฝั่ง \r\n5. ผัดถั่วงอกพอสลดรองจาน โปะหอยทอดด้านบน', 1, '1773062078_หอยทอด.jpg', NULL, '2026-03-08 14:35:01', 550, 3),
(21, 'ไข่เจียวหมูสับ', 'ข่เจียวฟูกรอบ ราดข้าวร้อนๆ! เมนูคลาสสิกที่กินกี่ครั้งก็ไม่เบื่อ ขอบกรอบๆ เนื้อไข่นุ่มละมุน หอมฟุ้งไปทั้งครัว เหยาะพริกน้ำปลาแซ่บๆ เข้าไปหน่อย อร่อยฟินจนต้องขอข้าวเพิ่ม!', NULL, '1. ตอกไข่ใส่ชาม ตีให้ฟูเข้ากัน 2. ใส่หมูสับ ต้นหอม และซีอิ๊วขาว คนให้เข้ากัน 3. ตั้งกระทะใส่น้ำมัน ใช้ไฟกลางค่อนข้างแรง รอจนน้ำมันร้อนจัด 4. เทไข่ลงไปทอดให้ฟูเหลืองกรอบทั้งสองด้าน 5. ตักขึ้นพักให้สะเด็ดน้ำมัน เสิร์ฟคู่ซอสพริก', 1, '1773061876_ไข่เจียว.jpg', NULL, '2026-03-08 14:35:01', 350, 0),
(22, 'น้ำตกหมู', 'น้ำตกหมูแซ่บซี้ด! หมูย่างฉ่ำๆ คลุกเครื่องปรุงรสเด็ด ข้าวคั่วหอมๆ พริกป่นเผ็ดโดนใจ กินแกล้มผักสดกับข้าวเหนียวร้อนๆ แซ่บหลายเด้อ!', NULL, '1. นำคอหมูย่างหั่นชิ้นใส่ลงในชามผสม \r\n2. ปรุงรสด้วยน้ำปลา น้ำมะนาว และพริกป่น คลุกเคล้าให้เข้ากัน \r\n3. ใส่ข้าวคั่ว หอมแดง ต้นหอม และผักชีฝรั่ง \r\n4. คลุกเคล้าให้ส่วนผสมเข้ากันดี \r\n5. ตักใส่จาน โรยด้วยใบสะระแหน่ เสิร์ฟพร้อมข้าวเหนียว', 1, '1773061524_น้ำตกหมู.jpg', NULL, '2026-03-08 14:35:01', 250, 1),
(23, 'คอหมูย่าง', 'คอหมูย่างฉ่ำๆ มันแทรกละมุนลิ้น! ย่างไฟหอมกรุ่น กัดคำไหนก็นุ่มละลายในปาก จิ้มกับแจ่วแซ่บๆ ข้าวเหนียวร้อนๆ ฟินสุดใจ!', NULL, '1. นำสันคอหมูมาจิ้มด้วยส้อมให้ทั่วเพื่อให้เครื่องปรุงซึมเข้าเนื้อ \r\n2. หมักหมูกับซอสหอยนางรม ซีอิ๊วขาว น้ำตาล และสามเกลอที่โขลกไว้ หมักทิ้งไว้ 30 นาที \r\n3. นำหมูไปย่างบนเตาถ่านหรือเตาอบด้วยไฟปานกลางจนสุกเหลือง \r\n4. หั่นเป็นชิ้นบางๆ เสิร์ฟพร้อมน้ำจิ้มแจ่ว', 2, '1773061038_คอหมูย่าง.jpg', NULL, '2026-03-08 14:35:01', 400, 0),
(24, 'ปลากะพงทอดน้ำปลา', 'ปลากะพงทอดน้ำปลา กรอบฟินสะท้านทรวง! เนื้อปลาสดหวาน ทอดมาร้อนๆ ราดน้ำปลาเคี่ยวกลิ่นหอมเตะจมูก กินคู่กับยำมะม่วงเปรี้ยวแซ่บ อร่อยเด็ดจนต้องแย่งกันคีบ!', NULL, '1. ล้างปลา ผ่าครึ่ง แบะออกและซับให้แห้ง \r\n2. ตั้งกระทะน้ำมันท่วม ไฟกลางค่อนแรง ทอดปลาจนเหลืองกรอบ ตักพักไว้ \r\n3. เคี่ยวน้ำปลากับน้ำตาลปี๊บจนหอม ราดลงบนตัวปลา \r\n4. ผสมส่วนผสมน้ำยำ เสิร์ฟคู่กับปลาทอด', 2, '1773059534_ปลากะพงทอดน้ำปลา2.jpg', NULL, '2026-03-08 14:35:01', 650, 2),
(25, 'ปูผัดผงกะหรี่', 'ปูผัดผงกะหรี่เยิ้มๆ! เนื้อปูแน่นหวานฉ่ำ คลุกเคล้าซอสผงกะหรี่เนื้อเนียนละมุน หอมกลิ่นเครื่องเทศเตะจมูก ตักราดข้าวสวยร้อนๆ อร่อยจนหยุดไม่ได้!', NULL, '1. สับปูเป็นชิ้น นำไปลวกพอสุก พักไว้ 2. ผสมไข่ นมข้นจืด ผงกะหรี่ น้ำพริกเผา ซอสหอยนางรม และซีอิ๊วขาว คนให้เข้ากัน 3. ตั้งกระทะผัดหอมใหญ่ให้หอม ใส่ปูลงไป 4. เทส่วนผสมไข่ที่เตรียมไว้ลงไป ผัดด้วยไฟอ่อนจนข้นเยิ้ม 5. ใส่ต้นหอม ขึ้นฉ่าย พริกชี้ฟ้า ตักเสิร์ฟ', 2, '1773059037_ปูผัดผงกระหรี่.png', NULL, '2026-03-08 14:35:01', 550, 9),
(26, 'กุ้งอบวุ้นเส้น', 'งอบวุ้นเส้นร้อนๆ ในหม้อดิน! วุ้นเส้นเหนียวนุ่มดูดซับน้ำซอสรสเด็ดแบบเข้มข้น หอมเครื่องเทศเตะจมูก กุ้งเนื้อเด้งหวานฉ่ำ ราดน้ำจิ้มซีฟู้ดแซ่บๆ เข้าไปอีกนิด ฟินอย่าบอกใคร!', NULL, '1. ผสมซอสหอยนางรม ซีอิ๊วขาว ซีอิ๊วดำ และน้ำซุปเข้าด้วยกัน นำวุ้นเส้นลงไปคลุก \r\n2. เรียงหมูสามชั้น ขิง รากผักชี กระเทียม พริกไทย ลงก้นหม้ออบ \r\n3. ใส่วุ้นเส้นที่คลุกไว้ และวางกุ้งด้านบน \r\n4. ปิดฝาอบไฟกลาง 10 นาที \r\n5. โรยขึ้นฉ่าย อบต่อ 1 นาที พร้อมเสิร์ฟ', 1, '1773058652_กุ้งอบวุ้นเส้น.jpg', NULL, '2026-03-08 14:35:01', 300, 2),
(27, 'ยำรวมมิตรทะเล', 'ยกมาทั้งทะเล! ยำรวมมิตรทะเลเครื่องล้นๆ กุ้งเด้งๆ หมึกกรอบๆ ราดด้วยน้ำยำสุดแซ่บจี๊ดจ๊าดถึงใจ สายยำห้ามพลาด จานนี้อร่อยเด็ดจนต้องซี้ดปาก!', NULL, '1. ผสมพริกขี้หนู น้ำมะนาว น้ำปลา และน้ำตาลทราย คนให้เข้ากันจนน้ำตาลละลาย \r\n2. นำอาหารทะเลและวุ้นเส้นที่ลวกไว้ ใส่ชามผสม \r\n3. ใส่หอมใหญ่ มะเขือเทศ และขึ้นฉ่าย \r\n4. ราดน้ำยำลงไป คลุกเคล้าทุกอย่างให้เข้ากัน ตักใส่จาน', 2, '1773058227_ยำรวมมิตรทะเล.jpg', NULL, '2026-03-08 14:35:01', 180, 2),
(28, 'แกงป่าหมู', 'ส่วนผสม: เนื้อหมูหั่นชิ้น 200 กรัม, พริกแกงป่า 2 ช้อนโต๊ะ, กระชายซอย 1/4 ถ้วย, พริกไทยอ่อน 2 ช่อ, มะเขือเปราะ 1/2 ถ้วย, ถั่วฝักยาว 1/2 ถ้วย, ใบกะเพรา, น้ำปลา 2 ช้อนโต๊ะ, น้ำซุป 2 ถ้วย', NULL, '1. ตั้งกระทะผัดพริกแกงป่ากับน้ำมันเล็กน้อยให้หอม \r\n2. ใส่หมูลงไปผัดจนสุก \r\n3. เติมน้ำซุป รอจนเดือด ใส่มะเขือเปราะและถั่วฝักยาว \r\n4. ปรุงรสด้วยน้ำปลา \r\n5. ใส่กระชาย พริกไทยอ่อน และใบกะเพรา รอเดือดอีกครั้ง ปิดไฟ ตักเสิร์ฟ', 2, '1773057390_แกงป่าหมู.jpg', NULL, '2026-03-08 14:35:01', 200, 3),
(29, 'หมูกรอบผัดพริกเกลือ', 'หมูกรอบผัดพริกเกลือ คั่วกระเทียมพริกสดหอมๆ หมูกรอบกัดดังกร๊วบ! รสชาติเค็มๆ เผ็ดๆ นัวสุดใจ กินเป็นกับแกล้มก็เด็ด กินกับข้าวสวยร้อนๆ ก็ฟิน!', NULL, '1. ตั้งกระทะเจียวกระเทียมและพริกขี้หนูให้หอมและเริ่มเหลืองกรอบ \r\n2. ใส่หมูกรอบลงไปคั่วในกระทะ \r\n3. ปรุงรสด้วยเกลือและน้ำตาล คั่วด้วยไฟแรงให้เข้ากัน \r\n4. ปิดไฟ โรยด้วยต้นหอมซอย คลุกเคล้าให้ทั่ว ตักใส่จาน', 1, '1773056600_ad88e8de-bd8e-4e61-9d92-4b349a0d506b.jpg', NULL, '2026-03-08 14:35:01', 600, 2),
(30, 'ฉู่ฉี่ปลาทู', 'เมนูปลาทูที่นำไปราดด้วยน้ำแกงขลุกขลิก ทำจากพริกแกงแดงเคี่ยวกับกะทิ รสชาติกลมกล่อม โดดเด่นด้วยกลิ่นหอมของสมุนไพรและใบมะกรูด', NULL, '1. นำปลาทูไปทอดในน้ำมันให้ผิวตึงและเหลืองสวย ตักพักไว้ \r\n2. เคี่ยวกะทิครึ่งหนึ่งให้แตกมัน ใส่พริกแกงลงผัดจนหอม \r\n3. ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ เติมกะทิที่เหลือ เคี่ยวจนข้น \r\n4. นำปลาทูลงไปคลุกเคล้ากับน้ำแกง \r\n5. โรยใบมะกรูดซอยและพริกชี้ฟ้า ตักเสิร์ฟ', 2, '1773055810_c562fabec86941a6bff3085686e8bc08.jpg', NULL, '2026-03-08 14:35:01', 350, 3),
(34, 'ข้าวต้มปลาอินทรี', 'เมนูยามเช้าที่ย่อยง่าย ให้โปรตีนสูงจากปลาอินทรีซึ่งมีไขมันดี และมีขิงช่วยขับลม ลดน้ำตาลและโซเดียมต่ำ เหมาะสำหรับผู้ป่วยเบาหวานและความดันสูงครับ', NULL, 'ลวกปลา (เคล็ดลับสำคัญ): ตั้งน้ำให้เดือดจัด ใส่ข่าแก่ลงไปเล็กน้อย นำเนื้อปลาลงไปลวกให้สุกพอประมาณ ห้ามคนจนกว่าปลาจะสุกเพื่อไม่ให้คาว จากนั้นตักขึ้นพักไว้ (การลวกแยกจะทำให้น้ำซุปใส ไม่ขุ่น และไม่มีกลิ่นคาวปลาครับ)\r\nต้มน้ำซุป: ตั้งหม้อน้ำซุป ใส่ข่าแว่นลงไปต้มจนหอม ปรุงรสด้วยซีอิ๊วขาวหรือเกลือนิดหน่อยพอให้รสชาติกลมกล่อม\r\nใส่ข้าว: ใส่ข้าวสวยลงไปในน้ำซุป ต้มต่อสักพักให้เม็ดข้าวบานออกเล็กน้อยตามความชอบ\r\nจัดเสิร์ฟ: ตักข้าวและน้ำซุปใส่ชาม วางเนื้อปลาที่ลวกไว้ลงไปด้านบน\r\nเติมเครื่อง: โรยหน้าด้วยตั้งฉ่าย ขิงซอย ขึ้นฉ่าย ต้นหอม และกระเทียมเจียว ปิดท้ายด้วยพริกไทยป่นเยอะๆ', 1, '1773941634_ข้าวต้มปลาอินทรี.jpg', NULL, '2026-03-12 03:16:14', 480, 4),
(35, 'ผัดกะเพราไก่สับอกราดข้าวกล้อง', 'เมนูโปรดของใครหลายๆ คน ปรับให้เฮลท์ตี้ขึ้นด้วยอกไก่ไม่ติดมัน ลดโซเดียม และเพิ่มผักใบเขียว พร้อมข้าวกล้องช่วยควบคุมระดับน้ำตาลได้ดี เหมาะสำหรับคุณKhaครับ', NULL, 'ผัดเครื่อง: ตั้งกระทะใส่น้ำมันเล็กน้อย (หรือน้ำเปล่าถ้าอยาก Clean สุดๆ) ใส่พริกกระเทียมลงไปผัดจนกลิ่นเริ่มเตะจมูก (ระวังจามนะครับ!)\r\nรวนไก่: ใส่อกไก่สับลงไป ผัดและยีให้กระจายตัว ไม่จับเป็นก้อน ผัดจนไก่เริ่มสุกเป็นสีขาว\r\nปรุงรส: ใส่เครื่องปรุงทั้งหมดลงไป ผัดให้เข้าเนื้อ ถ้าแห้งไปเติมน้ำเปล่าได้นิดหน่อยครับ แต่กะเพราอกไก่แนะนำแบบ \"ผัดแห้ง\" จะเข้ากับข้าวกล้องมาก\r\nใส่ใบกะเพรา: เร่งไฟแรง ใส่ใบกะเพราลงไป ผัดเร็วๆ 3-4 ทีพอให้ใบสลดแล้วปิดไฟทันที (เพื่อให้กลิ่นหอมยังอยู่และใบไม่ดำ)\r\nจัดจาน: ตักราดบนข้าวกล้องร้อนๆ พร้อมเสิร์ฟ', 1, '1773941960_ผัดกะเพราไก่สับอกราดข้าวกล้อง.png', NULL, '2026-03-12 03:16:48', 680, 32),
(36, 'ข้าวต้มเห็ดหอมไก่สับ', 'เมนูย่อยง่าย อุดมด้วยโปรตีนคุณภาพจากอกไก่และใยอาหารจากข้าวกล้องและเห็ดหอม ช่วยควบคุมระดับน้ำตาลในเลือดและดีต่อระบบหัวใจและหลอดเลือด เหมาะสำหรับมื้อเช้าที่ต้องการพลังงานและดูแลสุขภาพอย่างรอบด้าน', NULL, '1. ต้มน้ำซุปให้เดือด ใส่ข้าวกล้องหุงสุกและแครอทลงไป เคี่ยวจนข้าวนิ่ม\r\n2. ใส่อกไก่สับและเห็ดหอมลงไป คนเบาๆ ให้เนื้อไก่กระจายตัว ไม่จับเป็นก้อน\r\n3. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียม คนให้เข้ากัน ชิมรสตามชอบ\r\n4. ใส่ขิงซอยลงไป คนให้เข้ากันอีกครั้ง ปิดไฟ\r\n5. ตักใส่ชาม โรยหน้าด้วยต้นหอมซอย ผักชี และพริกไทยป่น เสิร์ฟขณะร้อน', 1, '1773939615_ข้าวต้มเห็ดหอมไก่สับ.jpg', NULL, '2026-03-19 04:24:38', 480, 4),
(37, 'ลาบหมูข้าวกล้อง', 'เมนูโปรตีนสูง ไขมันต่ำ เต็มไปด้วยสมุนไพรสดและเครื่องเทศ ที่ช่วยเสริมสร้างภูมิคุ้มกันและลดความดันโลหิต การใช้ข้าวคั่วจากข้าวเหนียวแท้และน้ำปลาลดโซเดียมทำให้เมนูนี้ปราศจากกลูเตนและโซเดียมต่ำ เหมาะกับคุณKha มากๆ เลยครับ', NULL, '1. รวนหมูสับในกระทะโดยไม่ต้องใช้น้ำมัน จนหมูสุกและมีน้ำออกมาเล็กน้อย พักให้เย็น\r\n2. ในชามผสม ใส่หมูรวน พริกป่น ข้าวคั่ว หอมแดงซอย ต้นหอมซอย และผักชีฝรั่งซอย\r\n3. ปรุงรสด้วยน้ำปลาลดโซเดียมและน้ำมะนาว คนให้เข้ากัน ชิมรสตามชอบ (ไม่เติมน้ำตาล)\r\n4. ใส่ใบสะระแหน่ลงไป คลุกเคล้าเบาๆ ให้เข้ากัน\r\n5. ตักลาบหมูใส่จาน เสิร์ฟพร้อมข้าวกล้องหุงสุกและผักสดหลากหลายชนิด', 1, '1773939038_699e2449fa0c4af1bf1678bc2489f99a.jpg', NULL, '2026-03-19 04:24:38', 620, 6),
(38, 'ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่', 'เมนูนี้อุดมด้วยโปรตีนจากเนื้อปลา ไขมันต่ำ และได้ประโยชน์จากสมุนไพรนานาชนิด ช่วยกระตุ้นการเผาผลาญและบำรุงหัวใจ ปรุงรสแบบจัดจ้านแต่ลดโซเดียมและปราศจากกลูเตน ทำให้ดีต่อเบาหวานและความดัน', NULL, '1. เตรียมหม้อนึ่งให้ร้อน วางชิ้นปลาลงในจานทนความร้อน ใส่ตะไคร้ ใบมะกรูด และข่าเล็กน้อยลงบนปลา\r\n2. นึ่งปลาประมาณ 10-15 นาที หรือจนปลาสุก (ความสุกขึ้นอยู่กับความหนาของชิ้นปลา)\r\n3. ระหว่างรอปลาสุก ผสมน้ำซุป น้ำปลาลดโซเดียม น้ำมะนาว พริกขี้หนู และกระเทียมในชาม คนให้เข้ากัน ชิมรสตามชอบ (ไม่เติมน้ำตาล)\r\n4. เมื่อปลาสุก ตักน้ำที่ออกมาจากตัวปลาในจานนึ่งทิ้งไป\r\n5. ราดน้ำยำที่เตรียมไว้ลงบนปลาที่นึ่งแล้ว โรยหน้าด้วยผักชี คื่นช่าย และมะนาวหั่นแว่น\r\n6. เสิร์ฟพร้อมข้าวไรซ์เบอร์รี่หุงสุกร้อนๆ', 1, '1773940381_ปลานึ่งมะนาวข้าวไรซ์เบอร์รี่.jpg', NULL, '2026-03-19 04:24:38', 600, 6),
(39, 'เมี่ยงปลาทู', 'เมี่ยงปลาทูเป็นเมนูของว่างที่ครบเครื่องเรื่องสุขภาพ ได้โปรตีนดีๆ จากปลาทูและโอเมก้า 3 ที่ช่วยบำรุงสมองและหัวใจ พร้อมใยอาหารจากผักสดนานาชนิด ช่วยควบคุมระดับน้ำตาลในเลือด ลดความดันโลหิต และปราศจากกลูเตน เหมาะกับการเป็นมื้อว่างที่อร่อยและดีต่อสุขภาพ', NULL, '1. แกะเนื้อปลาทูนึ่งออกจากก้าง พักไว้\r\n2. เตรียมผักสดและเครื่องเคียงต่างๆ จัดเรียงใส่จาน\r\n3. ทำน้ำจิ้มเมี่ยง โดยผสมน้ำปลาลดโซเดียม น้ำมะนาว น้ำเปล่า หญ้าหวาน พริกและกระเทียมที่ตำไว้เข้าด้วยกัน ชิมรสให้เปรี้ยว เค็ม เผ็ด ตามชอบ\r\n4. เวลาทาน ให้วางผักกาดแก้ว (หรือใบชะพลู) บนฝ่ามือ วางเส้นหมี่ข้าวกล้อง (ถ้าใส่) เนื้อปลาทู ขิงซอย หอมแดงซอย พริกซอย และโรยถั่วลิสงเล็กน้อย\r\n5. ราดน้ำจิ้มเมี่ยงที่เตรียมไว้ แล้วห่อให้พอดีคำ รับประทานได้เลยครับ', 1, '1773940787_เมี่ยงปลาทู.jpg', NULL, '2026-03-19 04:24:38', 400, 7),
(40, 'ข้าวต้มอกไก่ใส่เห็ดและขิง', 'เมนูยามเช้าที่ย่อยง่าย ให้พลังงานดีเยี่ยม โปรตีนสูงจากอกไก่ ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี เหมาะสำหรับผู้ป่วยเบาหวานและความดันสูง และปราศจากกลูเตน', '- ข้าวกล้องหุงสุก 1 ถ้วย\n- อกไก่หั่นชิ้น/สับ 100 กรัม\n- เห็ดหอมสด หรือเห็ดฟาง 50 กรัม\n- ขิงซอย 2 ช้อนโต๊ะ\n- ขึ้นฉ่ายหั่น 1 ช้อนโต๊ะ\n- น้ำซุปกระดูกไก่แบบไขมันต่ำ (ไม่ใส่ผงชูรส) 3 ถ้วย\n- ซีอิ๊วขาวลดโซเดียม สูตรปราศจากกลูเตน 1 ช้อนชา\n- พริกไทยป่น เล็กน้อย', '1. ต้มน้ำซุปให้เดือด ใส่ข้าวกล้องหุงสุกและเห็ดลงไป เคี่ยวจนข้าวนิ่ม\r\n2. ใส่อกไก่หั่นชิ้นหรือสับลงไป คนเบาๆ จนไก่สุก\r\n3. ปรุงรสด้วยซีอิ๊วขาวลดโซเดียม (ปราศจากกลูเตน) และพริกไทยเล็กน้อย ชิมรสตามชอบ\r\n4. ใส่ขิงซอยลงไป คนให้เข้ากัน\r\n5. ตักใส่ชาม โรยหน้าด้วยขึ้นฉ่ายหั่น เสิร์ฟขณะร้อน', 1, '1773941018_ข้าวต้มอกไก่ใส่เห็ดและขิง.jpg', NULL, '2026-03-19 04:53:28', 380, 6),
(41, 'แกงเขียวหวานอกไก่', 'เมนูโปรดของคุณKha หลายคน โดยเราปรับให้ดีต่อสุขภาพมากขึ้น ลดปริมาณกะทิและน้ำตาล แต่ยังคงความหอมอร่อยและได้โปรตีนจากอกไก่เต็มๆ ครับ ปราศจากกลูเตนและควบคุมความเค็มเพื่อสุขภาพหัวใจที่ดี', '- อกไก่หั่นชิ้นพอดีคำ 150 กรัม\n- พริกแกงเขียวหวาน (เลือกชนิดปราศจากกลูเตนและผงชูรส) 2 ช้อนโต๊ะ\n- หัวกะทิ (ใช้แบบไขมันต่ำ หรือลดปริมาณ) 1/2 ถ้วย\n- หางกะทิ หรือนมสดพร่องมันเนย 1 ถ้วย\n- มะเขือเปราะหั่น 3 ลูก\n- มะเขือพวง 1/4 ถ้วย\n- ใบโหระพา 1/2 ถ้วย\n- พริกชี้ฟ้าแดงหั่นแฉลบ 1 เม็ด\n- น้ำปลาลดโซเดียม สูตรปราศจากกลูเตน 1-2 ช้อนโต๊ะ\n- น้ำตาลหญ้าหวาน หรือน้ำตาลมะพร้าวปริมาณน้อยมาก 1 ช้อนชา\n- ข้าวไรซ์เบอร์รี่ หรือข้าวกล้อง 1 ถ้วย (สำหรับรับประทานคู่กัน)', '1. ผัดพริกแกงเขียวหวานกับหัวกะทิเล็กน้อยจนหอม และกะทิแตกมัน\r\n2. ใส่อกไก่ลงไปผัดจนไก่เริ่มสุก\r\n3. เติมหางกะทิหรือนมสดพร่องมันเนยลงไป เคี่ยวจนไก่นุ่ม\r\n4. ใส่มะเขือเปราะและมะเขือพวงลงไป เคี่ยวจนมะเขือสุก\r\n5. ปรุงรสด้วยน้ำปลาลดโซเดียม (ปราศจากกลูเตน) และน้ำตาลหญ้าหวาน ชิมรสตามชอบ\r\n6. ใส่หัวกะทิที่เหลือ ใบโหระพา และพริกชี้ฟ้าแดง คนให้เข้ากัน ปิดไฟ\r\n7. ตักราดบนข้าวไรซ์เบอร์รี่หรือข้าวกล้อง เสิร์ฟร้อนๆ', 1, '1773939713_แกงเขียวหวานอกไก่.jpg', NULL, '2026-03-19 04:53:28', 620, 7),
(42, 'ต้มข่าไก่ใส่มะพร้าวอ่อน', 'เมนูหอมกลิ่นสมุนไพรไทย ช่วยให้เจริญอาหารได้ดีค เราใช้เนื้ออกไก่เพื่อโปรตีนคุณภาพดี และลดปริมาณกะทิเพื่อควบคุมไขมัน ให้รสชาติกลมกล่อมและปราศจากกลูเตน', '- อกไก่หั่นชิ้นพอดีคำ 120 กรัม\n- หัวกะทิ (ใช้แบบไขมันต่ำ หรือลดปริมาณ) 1/2 ถ้วย\n- หางกะทิ หรือน้ำเปล่า 1.5 ถ้วย\n- ข่าหั่นแว่น 5 แว่น\n- ตะไคร้หั่นท่อนบุบ 2 ต้น\n- ใบมะกรูดฉีก 3 ใบ\n- เห็ดฟาง หรือเห็ดนางฟ้า 100 กรัม\n- เนื้อมะพร้าวอ่อนหั่นชิ้น 1/4 ถ้วย\n- น้ำปลาลดโซเดียม สูตรปราศจากกลูเตน 1-2 ช้อนโต๊ะ\n- น้ำมะนาว 2-3 ช้อนโต๊ะ\n- พริกขี้หนูบุบ (ตามชอบ) 1-2 เม็ด\n- ผักชีสำหรับโรยหน้า\n- ข้าวไรซ์เบอร์รี่ หรือข้าวกล้อง 1/2 ถ้วย (สำหรับรับประทานคู่กัน)', '1. ต้มหางกะทิ หรือน้ำเปล่ากับข่า ตะไคร้ และใบมะกรูดจนเดือดและหอม\r\n2. ใส่อกไก่ลงไปต้มจนสุก\r\n3. ใส่เห็ดและเนื้อมะพร้าวอ่อนลงไป ต้มพอสุก\r\n4. ปรุงรสด้วยน้ำปลาลดโซเดียม (ปราศจากกลูเตน) และน้ำมะนาว ชิมรสตามชอบ\r\n5. ใส่หัวกะทิที่เหลือลงไป คนให้เข้ากัน พอเดือดเล็กน้อย ปิดไฟ\r\n6. ใส่พริกขี้หนูบุบ (ถ้าชอบเผ็ด) โรยหน้าด้วยผักชี\r\n7. ตักเสิร์ฟพร้อมข้าวไรซ์เบอร์รี่หรือข้าวกล้อง', 1, '1774105822_987884af14514988b4b6445bb8e47fc9.jpg', NULL, '2026-03-19 04:53:28', 500, 7),
(43, 'อกไก่ย่างสมุนไพรกับผักลวก', 'เป็นมื้อว่างโปรตีนสูงที่ช่วยให้อิ่มท้องได้นาน ดีต่อการควบคุมน้ำหนัก และรักษาสมดุลของระดับน้ำตาลในเลือดครับคุณKha เมนูนี้ไขมันต่ำ ปราศจากกลูเตน และได้คุณประโยชน์จากสมุนไพรและผักครบถ้วน', '- อกไก่ไร้หนัง 150 กรัม\n- ตะไคร้ซอย 1 ช้อนโต๊ะ\n- กระเทียมสับ 1 ช้อนชา\n- พริกไทยดำป่น 1/2 ช้อนชา\n- น้ำปลาลดโซเดียม สูตรปราศจากกลูเตน 1 ช้อนโต๊ะ\n- น้ำมันหอยเจ (ปราศจากกลูเตน) หรือซีอิ๊วขาวลดโซเดียม (ปราศจากกลูเตน) 1 ช้อนโต๊ะ\n- น้ำตาลหญ้าหวาน หรือสารให้ความหวานแทนน้ำตาล 1/2 ช้อนชา\n- ผักลวกตามชอบ เช่น บรอกโคลี แครอท ถั่วลันเตา 1 ถ้วย', '1. ล้างอกไก่ให้สะอาด ซับให้แห้ง บั้งเล็กน้อยเพื่อให้เครื่องปรุงซึมเข้าเนื้อ\r\n2. ผสมตะไคร้ซอย กระเทียมสับ พริกไทยดำ น้ำปลาลดโซเดียม น้ำมันหอยเจ/ซีอิ๊วขาว และน้ำตาลหญ้าหวานเข้าด้วยกัน\r\n3. นำอกไก่ลงไปหมักกับเครื่องปรุง ทิ้งไว้ในตู้เย็นอย่างน้อย 30 นาที หรือนานกว่านั้นเพื่อรสชาติที่เข้มข้น\r\n4. นำอกไก่ไปย่างบนกระทะเทฟลอน หรือเตาอบ ด้วยไฟปานกลางจนสุกทั้งสองด้าน และเนื้ออกไก่นุ่ม\r\n5. หั่นอกไก่เป็นชิ้นพอดีคำ จัดใส่จานคู่กับผักลวกที่เตรียมไว้\r\n6. อาจเสิร์ฟพร้อมน้ำจิ้มแจ่วสูตรลดโซเดียมและน้ำตาล (ปราศจากกลูเตน) เพิ่มเติมได้ครับ', 1, '1773942113_อกไก่ย่างสมุนไพรกับผักลวก.jpg', NULL, '2026-03-19 04:53:28', 250, 5),
(44, 'ฟักทองนึ่ง', 'ฟักทองนึ่งเป็นของว่างที่ยอดเยี่ยมสำหรับคุณวิกรมครับ ให้ใยอาหารสูง ช่วยให้อิ่มนาน มีวิตามินและแร่ธาตุที่จำเป็น และมีรสหวานตามธรรมชาติ ไม่ต้องเติมน้ำตาลเพิ่ม เหมาะสำหรับผู้ป่วยเบาหวานและผู้ที่ต้องการควบคุมน้ำหนัก ไม่มีส่วนผสมของสารก่อภูมิแพ้ใดๆ เลยครับ', '- ฟักทองหั่นชิ้นพอดีคำ 250 กรัม', '1. ล้างฟักทองให้สะอาด หั่นเป็นชิ้นพอดีคำ โดยไม่ต้องปอกเปลือก (เปลือกมีประโยชน์)\r\n2. นำฟักทองจัดเรียงในลังถึง\r\n3. นึ่งในน้ำเดือดประมาณ 10-15 นาที หรือจนฟักทองนิ่มและสุกทั่ว\r\n4. ตักใส่จาน เสิร์ฟขณะอุ่นๆ เป็นของว่างเพื่อสุขภาพ', 1, '1774277856_pumpkin.jpg', NULL, '2026-03-20 12:58:27', 150, 3),
(45, 'อกไก่ย่างสมุนไพรกับผักลวกและข้าวกล้อง', 'เมนูนี้เน้นโปรตีนคุณภาพดีจากอกไก่ ที่ผ่านการหมักด้วยสมุนไพรหอมๆ และใช้วิธีการย่างแทนการทอด ทำให้ได้เมนูที่ไขมันต่ำมาก เป็นมิตรต่อหัวใจและไขมันในเลือดสูงครับ ทานคู่กับผักลวกหลากหลายชนิดและข้าวกล้อง จะช่วยให้คุณวิกรมได้รับสารอาหารครบถ้วน อิ่มอร่อย และดีต่อสุขภาพในทุกๆ ด้านครับ', '- อกไก่ไม่ติดหนัง 180 กรัม\n- ข้าวกล้องหุงสุก 180 กรัม\n- ตะไคร้ซอย 1 ช้อนโต๊ะ\n- ข่าซอย 1 ช้อนชา\n- ใบมะกรูดซอย 1 ช้อนชา\n- กระเทียมสับ 1 ช้อนชา\n- น้ำมันมะกอก 1.5 ช้อนชา\n- น้ำปลาลดโซเดียม 1.5 ช้อนโต๊ะ\n- ผักลวกตามชอบ (เช่น บรอกโคลี, แครอท, ถั่วฝักยาว) 200 กรัม', '1. นำอกไก่มาบั้งเล็กน้อยเพื่อให้เครื่องปรุงซึมเข้าเนื้อ\n2. ผสมตะไคร้, ข่า, ใบมะกรูด, กระเทียม, น้ำมันมะกอก และน้ำปลาลดโซเดียมเข้าด้วยกัน\n3. นำส่วนผสมสมุนไพรมาหมักอกไก่ ทิ้งไว้ในตู้เย็นอย่างน้อย 30 นาที\n4. นำอกไก่ที่หมักแล้วไปย่างบนกระทะเทฟลอน หรือเตาถ่านจนสุกเหลืองทั้งสองด้าน (ถ้าใช้กระทะ ให้ใช้ไฟกลางค่อนข้างอ่อนเพื่อไม่ให้ไหม้และสุกถึงด้านใน)\n5. ลวกผักต่างๆ ที่เตรียมไว้จนสุก\n6. จัดอกไก่ย่าง ผักลวก และข้าวกล้องหุงสุกใส่จาน เสิร์ฟ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=907830', NULL, '2026-03-20 12:58:27', 600, 3),
(46, 'มันเทศนึ่ง', 'เมนูของว่างเพื่อสุขภาพที่ให้คาร์โบไฮเดรตเชิงซ้อน วิตามิน และใยอาหารสูง ทำให้อิ่มอยู่ท้องได้นานโดยไม่ต้องกังวลเรื่องน้ำหนักตัว เป็นตัวเลือกที่ดีสำหรับคุณวิกรมที่ต้องการรักษาสุขภาพครับ', '- มันเทศสีส้ม (ขนาดกลาง) 1 หัว (ประมาณ 150 กรัม)', '1. ล้างมันเทศให้สะอาด ปอกเปลือกหรือไม่ปอกก็ได้ (ถ้าไม่ปอกให้ขัดผิวให้สะอาด)\n2. นำมันเทศวางในลังถึงสำหรับนึ่ง\n3. ตั้งหม้อน้ำให้เดือด นำลังถึงวางซ้อน นึ่งมันเทศประมาณ 15-20 นาที หรือจนกว่าจะสุกนิ่ม (ใช้ส้อมจิ้มดู)\n4. ตักเสิร์ฟอุ่นๆ หรือพักให้เย็นก็ได้', 1, 'https://loremflickr.com/800/500/healthy,food?lock=731568', NULL, '2026-03-20 13:00:10', 180, 2),
(47, 'โยเกิร์ตธรรมชาติกับกีวี่และธัญพืช', 'เมนูของว่างนี้เหมาะมากสำหรับคุณวิกรมที่ต้องการรักษาน้ำหนักครับ กีวี่ให้วิตามินซีและใยอาหาร โยเกิร์ตช่วยเรื่องระบบขับถ่าย และธัญพืชให้พลังงานที่ดี เป็นของว่างที่สดชื่นและมีประโยชน์มากๆ เลยครับ', '- โยเกิร์ตธรรมชาติ (ไม่ใส่น้ำตาล) 1 ถ้วยเล็ก (100-120 กรัม)\n- กีวี่ (ปอกเปลือก หั่นเต๋า) 1 ผลกลาง\n- กราโนล่า หรือธัญพืชรวม (ไม่ใส่น้ำตาลเยอะ) 2 ช้อนโต๊ะ\n- น้ำผึ้ง (ถ้าต้องการเพิ่มความหวานเล็กน้อย) 1 ช้อนชา', '1. ตักโยเกิร์ตธรรมชาติใส่ถ้วย\r\n2. วางกีวี่หั่นเต๋าลงบนโยเกิร์ต\r\n3. โรยด้วยกราโนล่าหรือธัญพืชรวม\r\n4. ถ้าชอบหวาน คุณวิกรมสามารถราดน้ำผึ้งเล็กน้อยได้\r\n5. เสิร์ฟเป็นของว่างเพื่อสุขภาพที่สดชื่นครับ', 1, '1774194097_yo.jpg', NULL, '2026-03-20 13:07:01', 210, 6),
(53, 'ไข่เจียวหมูสับกับผักลวก', 'เมนูมื้อเช้าที่อุดมไปด้วยโปรตีนจากไข่และหมูสับ ปรุงรสอ่อน ลดโซเดียม และใช้น้ำมันน้อย ช่วยควบคุมระดับน้ำตาลและความดันได้ดีครับคุณKha', '- ไข่ไก่ 2 ฟอง\n- หมูสับไม่ติดมัน 50 กรัม\n- ซีอิ๊วขาวลดโซเดียม (หรือน้ำปลาลดโซเดียม) 1 ช้อนชา\n- พริกไทยป่น เล็กน้อย\n- ผักลวกตามชอบ (เช่น บรอกโคลี แครอท) 1 ถ้วย\n- น้ำมันมะกอกสำหรับทอด 1 ช้อนชา', '1. ตอกไข่ใส่ชาม ตีให้เข้ากัน ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยป่น\n2. ใส่หมูสับลงไป คนให้เข้ากัน\n3. ตั้งกระทะ ใส่น้ำมันมะกอกเล็กน้อยพอร้อน เทไข่ลงทอดให้สุกเหลืองทั้งสองด้าน\n4. ตักใส่จาน เสิร์ฟพร้อมผักลวกที่เตรียมไว้', 1, 'https://loremflickr.com/800/500/healthy,food?lock=445765', NULL, '2026-03-22 08:34:48', 350, 1),
(54, 'แกงป่าไก่', 'แกงป่าเป็นเมนูที่ให้รสชาติจัดจ้าน หอมสมุนไพร ไม่ใส่กะทิทำให้ไขมันต่ำ โปรตีนสูงจากไก่ และมีใยอาหารจากผักหลากหลายชนิด เหมาะสำหรับคุณKhaที่ต้องการควบคุมเบาหวานและความดันครับ', '- อกไก่หั่นชิ้น 120 กรัม\n- พริกแกงป่า 1.5 ช้อนโต๊ะ (เลือกแบบไม่ใส่ผงชูรสและน้ำตาล)\n- ผักต่างๆ เช่น มะเขือเปราะ ถั่วฝักยาว ข้าวโพดอ่อน หน่อไม้ ใบกะเพรา พริกชี้ฟ้า หั่นเตรียมไว้รวม 1.5 ถ้วย\n- น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\n- น้ำเปล่าหรือน้ำสต็อกไก่ 1.5 ถ้วย\n- ข้าวกล้องหุงสุก 100 กรัม', '1. ตั้งหม้อ ใส่น้ำเล็กน้อยพอร้อน ใส่พริกแกงป่าลงไปผัดให้หอม\r\n2. ใส่อกไก่ลงไปผัดจนไก่เริ่มสุก\r\n3. เติมน้ำเปล่าหรือน้ำสต็อกไก่ลงไป ต้มให้เดือด\r\n4. ใส่มะเขือเปราะ หน่อไม้ และถั่วฝักยาวลงไป ต้มจนผักเริ่มนิ่ม\r\n5. ปรุงรสด้วยน้ำปลาลดโซเดียม\r\n6. ใส่ข้าวโพดอ่อน พริกชี้ฟ้า และใบกะเพราลงไป คนให้เข้ากัน ปิดไฟ\r\n7. ตักแกงป่าไก่เสิร์ฟพร้อมข้าวกล้อง', 1, '1774277506_maxresdefault.jpg', NULL, '2026-03-22 08:34:48', 410, 2),
(55, 'แกงส้มกุ้งชะอมไข่', 'เมนูมื้อเย็นรสกลมกล่อม เปรี้ยว เผ็ด หวานน้อย เน้นโปรตีนจากกุ้งและไข่ชะอม มีใยอาหารสูงจากผักนานาชนิด ช่วยให้คุณKhaอิ่มสบายท้อง และยังดีต่อการควบคุมน้ำตาลและความดันโลหิตอีกด้วยครับ', '- กุ้งสดปอกเปลือกผ่าหลัง 80 กรัม\n- พริกแกงส้ม 1 ช้อนโต๊ะ (เลือกแบบไม่ใส่ผงชูรสและน้ำตาล)\n- ชะอม 1 กำมือ\n- ไข่ไก่ 1 ฟอง\n- ผักรวมสำหรับแกงส้ม (เช่น หัวไชเท้า ถั่วฝักยาว มะละกอดิบ) หั่นชิ้นพอดีคำ 1 ถ้วย\n- น้ำปลาลดโซเดียม 1 ช้อนโต๊ะ\n- น้ำเปล่า 2 ถ้วย\n- น้ำมะขามเปียก 2-3 ช้อนโต๊ะ (ปรับตามชอบ)\n- น้ำมันมะกอก 1/2 ช้อนชา (สำหรับทอดชะอมไข่)\n- ข้าวกล้องหุงสุก 100 กรัม', '1. ทำชะอมไข่: ตอกไข่ใส่ชาม ตีให้เข้ากันกับชะอม ปรุงรสเล็กน้อย ตั้งกระทะใส่น้ำมันมะกอกเล็กน้อยพอร้อน เทไข่ลงทอดให้สุก ตักขึ้น หั่นเป็นชิ้นพอดีคำ พักไว้\n2. ตั้งหม้อ ใส่น้ำเปล่าพอเดือด ใส่พริกแกงส้มลงไปละลาย คนให้เข้ากัน\n3. ใส่ผักรวมสำหรับแกงส้มลงไป ต้มจนผักเริ่มสุก\n4. ปรุงรสด้วยน้ำปลาลดโซเดียมและน้ำมะขามเปียก ชิมรสตามชอบ (เปรี้ยว เค็ม เผ็ด)\n5. ใส่กุ้งสดลงไป ต้มจนกุ้งสุก\n6. ใส่ชะอมไข่ที่เตรียมไว้ลงไป ปิดไฟ\n7. ตักแกงส้มกุ้งชะอมไข่เสิร์ฟพร้อมข้าวกล้อง', 1, 'https://loremflickr.com/800/500/healthy,food?lock=45959', NULL, '2026-03-22 08:34:48', 450, 2),
(56, 'โจ๊กไก่ใส่ไข่ขาวและเห็ดหอม', 'เมนูมื้อเช้าที่ย่อยง่าย ให้โปรตีนสูงจากอกไก่และไข่ขาว มีใยอาหารจากข้าวกล้องและเห็ดหอม ช่วยควบคุมระดับน้ำตาลในเลือดของคุณroot เหมาะสำหรับผู้ป่วยเบาหวานและความดันสูง โดยปรุงรสแบบลดโซเดียมและปราศจากกลูเตนครับ', '- ข้าวกล้องหุงสุกบด 100 กรัม\n- อกไก่สับ 80 กรัม\n- เห็ดหอมสดหั่น 50 กรัม\n- ขิงซอย 1 ช้อนโต๊ะ\n- ต้นหอมซอย 1 ช้อนโต๊ะ\n- ไข่ขาว 1 ฟอง\n- ซีอิ๊วขาวแบบปราศจากกลูเตน (หรือเกลือเล็กน้อย) 1 ช้อนชา\n- น้ำซุปไก่ไขมันต่ำ 2 ถ้วยตวง', '1. ตั้งน้ำซุปไก่ให้เดือด ใส่ข้าวกล้องหุงสุกบดลงไป คนให้เข้ากัน\n2. ใส่อกไก่สับและเห็ดหอมลงไป เคี่ยวด้วยไฟอ่อนจนไก่สุกและโจ๊กข้นขึ้น\n3. ค่อยๆ เทไข่ขาวลงไปเป็นสาย พร้อมใช้ตะเกียบคนเบาๆ ให้ไข่ขาวจับตัวเป็นเส้น\n4. ปรุงรสด้วยซีอิ๊วขาวแบบปราศจากกลูเตน (หรือเกลือเล็กน้อย) ชิมรสตามชอบ แต่เน้นปรุงรสอ่อนๆ\n5. ตักใส่ชาม โรยหน้าด้วยขิงซอยและต้นหอมซอย พร้อมเสิร์ฟร้อนๆ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=845030', NULL, '2026-03-22 08:40:45', 380, 3),
(57, 'ไก่ผัดขิงกับเห็ดและข้าวกล้อง', 'เมนูย่อยง่าย รสชาติกลมกล่อมจากขิงช่วยกระตุ้นการไหลเวียนเลือด และดีต่อระบบย่อยอาหาร อุดมด้วยโปรตีนและใยอาหารจากอกไก่ เห็ด และข้าวกล้อง ปรุงรสแบบปราศจากกลูเตนและลดโซเดียม เป็นมื้อเย็นที่เบาสบายและเหมาะสมกับคุณrootมากๆ ครับ', '- อกไก่หั่นชิ้นพอดีคำ 120 กรัม\n- ขิงซอย 3 ช้อนโต๊ะ\n- เห็ดต่างๆ (เช่น เห็ดหอมสด, เห็ดออรินจิ) 80 กรัม\n- แครอทหั่นแว่นบาง 30 กรัม\n- พริกชี้ฟ้าแดงหั่นแฉลบ 1 เม็ด\n- ต้นหอมหั่นท่อน 2 ช้อนโต๊ะ\n- ข้าวกล้องหุงสุก 150 กรัม\n- ซีอิ๊วขาวปราศจากกลูเตน 1 ช้อนโต๊ะ\n- น้ำมันรำข้าว/น้ำมันมะกอก 1 ช้อนชา\n- น้ำซุปไก่ไขมันต่ำ 3 ช้อนโต๊ะ', '1. ตั้งกระทะ ใส่น้ำมันเล็กน้อย พอร้อนใส่ขิงซอยลงไปผัดจนหอม\n2. ใส่อกไก่ลงไปผัดให้พอสุก\n3. ใส่เห็ดและแครอทลงไปผัดจนผักเริ่มสุก\n4. ปรุงรสด้วยซีอิ๊วขาวปราศจากกลูเตน เติมน้ำซุปเล็กน้อย ผัดให้เข้ากัน ชิมรสโดยเน้นรสชาติอ่อนๆ\n5. ใส่พริกชี้ฟ้าและต้นหอมลงไป ผัดอีกเล็กน้อย ปิดไฟ\n6. ตักราดบนข้าวกล้องหุงสุก พร้อมเสิร์ฟเป็นมื้อเย็นแสนอร่อยและดีต่อสุขภาพของคุณrootครับ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=241435', NULL, '2026-03-22 08:40:45', 500, 2),
(58, 'แกงจืดเต้าหู้หมูสับ (กับข้าวกล้อง)', 'เมนูยามเช้าที่ย่อยง่าย ให้โปรตีนดีจากหมูสับและเต้าหู้ไข่ ผักหลากหลายชนิดให้ใยอาหาร ช่วยควบคุมระดับน้ำตาลในเลือดและดูแลความดันโลหิตได้ดี เพราะปรุงรสอ่อนและปราศจากกลูเตนครับ', '- หมูสับติดมันน้อย 80 กรัม\n- เต้าหู้ไข่ 1 หลอด\n- ผักกาดขาว 50 กรัม\n- แครอทหั่นแว่น 30 กรัม\n- เห็ดหอมสด 30 กรัม\n- น้ำซุปกระดูกหมู/ไก่ (ไม่ใส่ผงชูรส) 2 ถ้วย\n- ซีอิ๊วขาว (ชนิดปราศจากกลูเตน) 1 ช้อนชา\n- เกลือชมพูเล็กน้อย (สำหรับหมูหมัก)\n- พริกไทยป่นเล็กน้อย\n- ต้นหอมและผักชีซอย สำหรับโรยหน้า\n- ข้าวกล้องหุงสุก 100 กรัม (ประมาณ 1 ทัพพี)', '1. หมักหมูสับกับซีอิ๊วขาวปราศจากกลูเตนและพริกไทยป่นเล็กน้อย พักไว้ 10 นาที\n2. ต้มน้ำซุปให้เดือด ปั้นหมูสับเป็นก้อนพอดีคำ ใส่ลงในน้ำซุป รอจนหมูสุก\n3. ใส่ผักกาดขาว แครอท และเห็ดหอมลงไป ต้มจนผักเริ่มนิ่ม\n4. หั่นเต้าหู้ไข่เป็นชิ้นพอดีคำ ใส่ลงไปในหม้อ\n5. ปรุงรสด้วยซีอิ๊วขาวชนิดปราศจากกลูเตน (ชิมรสก่อน หากจำเป็นให้เติมเกลือชมพูเล็กน้อย)\n6. ตักใส่ชาม โรยด้วยต้นหอมและผักชีซอย เสิร์ฟพร้อมข้าวกล้องหุงสุก', 1, 'https://loremflickr.com/800/500/healthy,food?lock=187063', NULL, '2026-03-22 08:43:41', 380, 0),
(59, 'แกงส้มกุ้งชะอมไข่ กับข้าวกล้อง', 'แกงส้มเป็นเมนูที่ดีเยี่ยมสำหรับคุณadminครับ ให้โปรตีนสูงจากกุ้งและไข่ มีใยอาหารและวิตามินมากมายจากผัก ปรุงรสโดยเน้นความเปรี้ยวจากมะขามเปียก ลดปริมาณโซเดียมและน้ำตาล จึงเหมาะสำหรับผู้ป่วยเบาหวานและความดันสูง และปราศจากกลูเตนแน่นอนครับ', '- กุ้งสดปอกเปลือก 100 กรัม\n- ชะอม 1 ถ้วย\n- ไข่ไก่ 1 ฟอง\n- น้ำมะขามเปียก 3 ช้อนโต๊ะ\n- น้ำปลาลดโซเดียม (ปราศจากกลูเตน) 2 ช้อนโต๊ะ\n- พริกแกงส้ม 2 ช้อนโต๊ะ (เลือกแบบโฮมเมดหรืออ่านฉลากให้แน่ใจว่าไม่มีกลูเตน/ผงชูรส)\n- น้ำเปล่า 3 ถ้วย\n- ผักรวมสำหรับแกงส้ม (เช่น ถั่วฝักยาว, มะละกอดิบหั่น) 1 ถ้วย\n- สารให้ความหวานแทนน้ำตาล (ถ้าจำเป็น) เล็กน้อย\n- ข้าวกล้องหุงสุก 1.5 ถ้วย (ประมาณ 200 กรัม)', '1. นำไข่ไก่มาตีผสมกับชะอมเล็กน้อย ทอดในกระทะเทฟลอนเป็นแผ่นบางๆ แล้วหั่นเป็นชิ้นพอดีคำ พักไว้\n2. ต้มน้ำให้เดือด ใส่พริกแกงส้มลงไปละลาย คนให้เข้ากัน\n3. ปรุงรสด้วยน้ำปลาลดโซเดียมและน้ำมะขามเปียก ชิมรสให้ออกเปรี้ยว เค็ม เผ็ด (ถ้าต้องการหวานเล็กน้อย ให้ใช้สารให้ความหวานแทนน้ำตาล)\n4. ใส่ผักรวมที่เตรียมไว้ลงไป ต้มจนผักเริ่มสุก\n5. ใส่กุ้งสดลงไป ต้มจนกุ้งสุก (อย่าต้มนานเกินไปกุ้งจะแข็ง)\n6. ใส่ชะอมไข่ทอดที่หั่นไว้ลงไป ปิดไฟ\n7. ตักแกงส้มใส่ชาม รับประทานคู่กับข้าวกล้องหุงสุกครับ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=137549', NULL, '2026-03-22 08:46:07', 650, 4),
(60, 'แกงเลียงกุ้งสด กับข้าวไรซ์เบอร์รี่', 'แกงเลียงเป็นเมนูอาหารไทยโบราณที่อุดมไปด้วยสมุนไพรและผักหลากหลายชนิดครับคุณadmin ให้ใยอาหารสูง วิตามินและแร่ธาตุครบถ้วน ปราศจากไขมันจากกะทิ และเมื่อปรุงรสด้วยน้ำปลาลดโซเดียม จะช่วยควบคุมความดันโลหิตและระดับน้ำตาลได้ดีเยี่ยมครับ เมนูนี้ยังปราศจากกลูเตนอีกด้วยครับ', '- กุ้งสดปอกเปลือก 100 กรัม\n- ฟักทองหั่นชิ้น 1/2 ถ้วย\n- บวบหั่นชิ้น 1/2 ถ้วย\n- เห็ดฟางผ่าครึ่ง 1/2 ถ้วย\n- ใบแมงลัก 1/2 ถ้วย\n- ข้าวโพดอ่อนหั่น 1/2 ถ้วย\n- ตำลึง 1/2 ถ้วย (หรือผักอื่นๆ ตามชอบ)\n- หอมแดง 3 หัว\n- พริกไทยเม็ด 1 ช้อนชา\n- กะปิ 1 ช้อนชา (เลือกแบบไม่มีผงชูรส/กลูเตน)\n- น้ำปลาลดโซเดียม (ปราศจากกลูเตน) 1-2 ช้อนโต๊ะ\n- น้ำเปล่า/น้ำซุปไก่ 3-4 ถ้วย\n- ข้าวไรซ์เบอร์รี่หุงสุก 1.5 ถ้วย (ประมาณ 200 กรัม)', '1. โขลกหอมแดง พริกไทยเม็ด และกะปิให้ละเอียดเข้ากัน พักไว้ (สำคัญคือต้องตรวจสอบกะปิว่าปราศจากกลูเตนและผงชูรสครับ)\n2. ต้มน้ำซุปหรือน้ำเปล่าให้เดือด ใส่เครื่องแกงที่โขลกไว้ลงไปละลาย คนให้เข้ากัน\n3. ใส่ผักที่สุกยากก่อน เช่น ฟักทอง ข้าวโพดอ่อน ต้มจนเกือบสุก\n4. ใส่ผักที่สุกง่าย เช่น บวบ เห็ดฟาง ตำลึง ลงไป\n5. เมื่อผักทั้งหมดสุกดีแล้ว ใส่กุ้งสดลงไป ต้มจนกุ้งสุก\n6. ปรุงรสด้วยน้ำปลาลดโซเดียม ชิมรสให้กลมกล่อม (เน้นรสธรรมชาติจากผักและกุ้ง)\n7. ใส่ใบแมงลักลงไป คนเบาๆ ปิดไฟทันที\n8. ตักแกงเลียงใส่ชาม รับประทานคู่กับข้าวไรซ์เบอร์รี่หุงสุกครับ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=228526', NULL, '2026-03-22 08:46:07', 630, 1),
(61, 'ไข่เจียวอกไก่สับกับผักลวก', 'สำหรับมื้อเช้าของคุณadmin เมนูนี้เป็นโปรตีนสูง เหมาะสำหรับมื้อเช้าที่ต้องการพลังงานและอิ่มนาน ช่วยควบคุมระดับน้ำตาลในเลือดได้ดี และปลอดภัยสำหรับผู้แพ้กลูเตนครับ', '- ไข่ไก่ 2 ฟอง\n- อกไก่สับ 80 กรัม\n- แครอทหั่นเต๋าเล็ก 30 กรัม\n- ถั่วลันเตา 30 กรัม\n- ซีอิ๊วขาวลดโซเดียม (ปราศจากกลูเตน) 1 ช้อนชา\n- น้ำมันรำข้าว/น้ำมันมะกอก 1 ช้อนชา\n- เกลือเล็กน้อย, พริกไทยป่น\n- บรอกโคลีลวก 100 กรัม (สำหรับผักลวก)\n- น้ำจิ้มแจ่ว (ปรุงเอง: น้ำปลาลดโซเดียม, มะนาว, หอมแดง, พริกป่น, ข้าวคั่ว (ตรวจสอบว่าปราศจากกลูเตน))', '1. ตีไข่ไก่ให้เข้ากัน ปรุงรสด้วยซีอิ๊วขาวลดโซเดียมและพริกไทยเล็กน้อย\r\n2. ตั้งกระทะ ใส่น้ำมันเล็กน้อย พอร้อน ใส่อกไก่สับลงไปผัดจนสุก\r\n3. ใส่แครอทและถั่วลันเตาลงไปผัดพอสุก ตักขึ้นพักไว้\r\n4. เทไข่ที่ตีไว้ลงในกระทะที่เหลือ ใส่อกไก่ผัดและผักที่พักไว้ลงบนไข่\r\n5. พับไข่เป็นรูปครึ่งวงกลมหรือสี่เหลี่ยม เจียวจนสุกเหลืองทั้งสองด้าน\r\n6. จัดเสิร์ฟคู่กับบรอกโคลีลวก และน้ำจิ้มแจ่วที่ปรุงเองแบบปราศจากกลูเตนและลดโซเดียม', 1, '1774278084_ffd345de0c014bc6854e7fc26f5e9613.jpg', NULL, '2026-03-22 08:53:19', 380, 1),
(62, 'มะละกอสุก', 'มะละกอสุกเป็นผลไม้ที่มีใยอาหารสูง วิตามินซีและสารต้านอนุมูลอิสระมากมาย ซึ่งมีส่วนช่วยบำรุงผิวพรรณและระบบภูมิคุ้มกัน เป็นของว่างที่สดชื่นและดีต่อสุขภาพของคุณBANCHA ทั้งเรื่องการลดน้ำหนักและช่วยเสริมวิตามินสำหรับผู้มีสะเก็ดเงินครับ', '- มะละกอสุกหั่นชิ้นพอดีคำ 150 กรัม', '1. ปอกเปลือกมะละกอสุก คว้านเมล็ดออก\r\n2. หั่นเป็นชิ้นพอดีคำ จัดใส่จาน\r\n3. เสิร์ฟเป็นของว่าง', 1, '1774277281_6278ca88f72400710777a4a7c1d1efbb.jpg', NULL, '2026-03-22 09:56:51', 120, 1),
(64, 'แกงเลียงกุ้งสด', 'เมนูนี้ดีต่อสุขภาพมากๆ เลยครับคุณคนสวยดูดีเด้งดึ๋ง เป็นซุปผักรวมรสจัดจ้านที่ให้ใยอาหารสูงมาก วิตามินและแร่ธาตุครบครัน แถมแคลอรี่ต่ำ ทำให้อิ่มท้องโดยไม่รู้สึกผิด เป็นทางเลือกที่ดีเยี่ยมแทนซุปมะเขือครับ', '- กุ้งสดปอกเปลือกผ่าหลัง 100 กรัม\n- ฟักทองหั่นชิ้น 80 กรัม\n- บวบหั่นชิ้น 80 กรัม\n- เห็ดฟาง 50 กรัม\n- ใบแมงลัก 1 กำมือ\n- ใบตำลึง 1 กำมือ\n- พริกแกงเลียง (กะปิ 1 ช้อนชา, หอมแดง 2 หัว, พริกไทยเม็ด 1 ช้อนชา, กุ้งแห้งป่น 1 ช้อนโต๊ะ) โขลกละเอียด\n- น้ำเปล่า หรือน้ำซุปผัก 3 ถ้วย\n- น้ำปลาลดโซเดียมสำหรับปรุงรสเล็กน้อย', '1. ต้มน้ำเปล่าหรือน้ำซุปผักให้เดือด ใส่น้ำพริกแกงเลียงที่โขลกไว้ลงไป คนให้ละลาย\n2. เมื่อน้ำแกงเดือดอีกครั้ง ใส่ฟักทองและบวบลงไป ต้มจนผักเริ่มสุกนิ่ม\n3. ใส่กุ้งสดและเห็ดฟางลงไป ต้มจนกุ้งสุก\n4. ปรุงรสด้วยน้ำปลาลดโซเดียมเล็กน้อย ชิมรสตามชอบ\n5. สุดท้ายใส่ใบตำลึงและใบแมงลักลงไป คนเล็กน้อย ปิดไฟทันทีเพื่อไม่ให้ผักช้ำ\n6. ตักใส่ชาม เสิร์ฟร้อนๆ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=295244', NULL, '2026-03-22 10:10:41', 280, 1),
(65, 'แจ่วปลาทู กับมะเขือเปราะลวก', 'เมนู \'แจ่วปลาทู กับมะเขือเปราะลวก\' นี้เป็นเมนูที่แคลอรี่ต่ำมากครับคุณคนสวยดูดีเด้งดึ๋ง อุดมไปด้วยโปรตีนคุณภาพดีจากปลาทู และใยอาหารสูงจากมะเขือเปราะและต้นหอม ซึ่งจะช่วยให้อิ่มนาน ดีต่อระบบขับถ่าย และเหมาะอย่างยิ่งสำหรับการลดน้ำหนักเร่งด่วนตามเป้าหมายของคุณคนสวยดูดีเด้งดึ๋งครับ รับรองว่าทั้งอร่อยและมีประโยชน์ครบถ้วนแน่นอน!', '- ปลาทูนึ่ง 1 ตัว (ขนาดกลาง)\n- มะเขือเปราะ 3-4 ลูก\n- ต้นหอม 2 ต้น\n- พริกจินดาแดง 5-7 เม็ด (ปรับตามชอบ)\n- กระเทียมไทย 3-4 กลีบ\n- น้ำปลาร้าต้มสุก 2 ช้อนโต๊ะ\n- น้ำปลา 1 ช้อนชา\n- น้ำมะนาว 1 ช้อนโต๊ะ\n- ผักชี (สำหรับโรยหน้า)', '1. ล้างมะเขือเปราะให้สะอาด หั่นครึ่ง หรือตามชอบ แล้วนำไปลวกหรือนึ่งจนสุกนิ่ม พักไว้\n2. ล้างปลาทูนึ่ง แกะเนื้อปลาออกจากก้างและหนัง พักไว้\n3. นำพริกจินดาแดงและกระเทียมไปคั่วหรืออบจนสุกหอม จากนั้นโขลกรวมกันให้ละเอียด\n4. ใส่เนื้อปลาทูที่แกะไว้ลงไปในครก โขลกพอเข้ากัน ไม่ต้องละเอียดมากนัก\n5. ปรุงรสด้วยน้ำปลาร้าต้มสุก น้ำปลา และน้ำมะนาว คนให้เข้ากัน ชิมรสตามชอบ\n6. ซอยต้นหอมและผักชีเล็กน้อย ใส่ลงไปในน้ำพริก คนให้เข้ากันอีกครั้ง\n7. จัดเสิร์ฟแจ่วปลาทูคู่กับมะเขือเปราะลวก และต้นหอมสดที่เหลือ (ถ้ามีผักสดอื่นๆ เช่น ถั่วฝักยาว แตงกวา หรือผักกาดขาวลวก สามารถจัดเพิ่มเพื่อเพิ่มใยอาหารได้ครับ)', 1, 'https://loremflickr.com/800/500/healthy,food?lock=770250', NULL, '2026-03-22 10:14:14', 180, 0),
(75, 'อกไก่นึ่งสมุนไพร', 'เมนูว่างโปรตีนสูง ไขมันต่ำ ปรุงน้อย และไม่ใส่กลูเตนครับ การนึ่งช่วยรักษาสารอาหารและลดการใช้น้ำมัน สมุนไพรต่างๆ ยังช่วยเพิ่มกลิ่นหอมและมีประโยชน์ต่อสุขภาพ เหมาะสำหรับคุณadmin ที่ต้องการควบคุมระดับน้ำตาลและความดัน และรักษาน้ำหนักครับ', '- อกไก่ (ไม่ติดหนัง) 150 กรัม\n- ตะไคร้ซอย 1 ช้อนโต๊ะ\n- ใบมะกรูดฉีก 2 ใบ\n- ข่าหั่นแว่น 5-6 แว่น\n- น้ำปลา (เลือกแบบโซเดียมต่ำ) 1 ช้อนชา\n- พริกไทยดำป่น ¼ ช้อนชา\n- ผักสดหรือผักลวก (เช่น ถั่วฝักยาว, กะหล่ำปลี) สำหรับทานคู่', '1. ล้างทำความสะอาดอกไก่ ซับให้แห้ง\n2. หมักอกไก่ด้วยน้ำปลาและพริกไทยดำเล็กน้อย\n3. โรยตะไคร้ ใบมะกรูด และข่าลงบนอกไก่\n4. นำไปนึ่งในซึ้งที่น้ำเดือดจัด ประมาณ 15-20 นาที หรือจนอกไก่สุกทั่ว\n5. หั่นเป็นชิ้นพอดีคำ จัดเสิร์ฟคู่กับผักสดหรือผักลวก เป็นมื้อว่างเบาๆ ครับ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=798847', NULL, '2026-03-22 15:46:18', 180, 1),
(76, 'ไข่ตุ๋นกุ้งสับ', 'เมนูมื้อเช้าที่ย่อยง่าย อุดมไปด้วยโปรตีนจากไข่และกุ้ง ช่วยให้อิ่มนานและควบคุมระดับน้ำตาลได้ดี ปลอดภัยสำหรับคุณadminเพราะปราศจากกลูเตนและมีโซเดียมต่ำครับ', '- ไข่ไก่ 2 ฟอง\n- กุ้งสดสับ 80 กรัม\n- น้ำซุปผัก/ไก่ (ลดโซเดียม) 150 มล.\n- ซีอิ๊วขาวลดโซเดียม (ชนิดปราศจากกลูเตน) 1 ช้อนชา\n- แครอทหั่นเต๋าเล็ก 2 ช้อนโต๊ะ\n- ต้นหอมซอยสำหรับโรยหน้า 1 ช้อนโต๊ะ\n- พริกไทยขาวเล็กน้อย', '1. ตอกไข่ใส่ชาม ตีให้เข้ากันเบาๆ ไม่ให้เกิดฟองมาก\n2. เติมน้ำซุป ซีอิ๊วขาวลดโซเดียม และพริกไทย ตีให้เข้ากันอีกครั้ง\n3. กรองส่วนผสมไข่ผ่านกระชอนละเอียด เพื่อให้เนื้อเนียนและกำจัดฟองอากาศ\n4. ใส่กุ้งสับและแครอทหั่นเต๋าลงในชามทนความร้อน\n5. เทส่วนผสมไข่ที่กรองแล้วลงไป ปิดฝาหรือใช้ฟิล์มถนอมอาหารคลุม (เจาะรูเล็กน้อย)\n6. นำไปนึ่งในน้ำเดือดปานกลาง ประมาณ 15-20 นาที หรือจนไข่สุกและเซ็ตตัว\n7. โรยหน้าด้วยต้นหอมซอยก่อนเสิร์ฟ', 1, 'https://loremflickr.com/800/500/healthy,food?lock=50017', NULL, '2026-03-22 16:24:55', 250, 0);
